-- Poems batch 369
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('88290ab7-1d3a-4687-a680-b818688cb8da','過梅田追傷胡公立寄其姪仲平','汪藻','宋','宋诗','song-poetry','','[]','繫船還共竹林居，憶昨盃行手挽蔬。',64,'全唐诗/poet.song.83000.json','["繫船還共竹林居，憶昨盃行手挽蔬。", "滿眼誰同春夢事，經年不枉故人書。", "木奴封戶千頭橘，雪片傾箱二寸魚。", "信美湖湘異吾土，且尋烟艇意何如。"]'),
('7831a4c4-fdae-46c2-b593-be771f9cc8c9','致政王參政挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','直道行藏世所難，拂衣談笑便休官。',64,'全唐诗/poet.song.83000.json','["直道行藏世所難，拂衣談笑便休官。", "逢時合上麒麟閣，執法先峨獬豸冠。", "兩國旌旜交境外，三年帷幄侍朝端。", "龐眉未向清時老，萬事浮雲忽蓋棺。"]'),
('ca1269fd-85d3-4213-b0b5-86e4d2b44117','致政王參政挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','賜第崇寧一再春，建炎方識老成人。',64,'全唐诗/poet.song.83000.json','["賜第崇寧一再春，建炎方識老成人。", "早爲勇退山林士，晚作中興社稷臣。", "手把青箱傳後裔，日陪黄閣轉洪鈞。", "鄉關間闊雖千里，松檟相望亦海濱。"]'),
('65c3621b-8893-4bb5-9aa4-b05ef6cb4a3b','挽刑部王侍郎詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','詔蹕南來首賜環，清名誰不仰高山。',64,'全唐诗/poet.song.83000.json','["詔蹕南來首賜環，清名誰不仰高山。", "獨操廷尉平反柄，徐步文昌侍從班。", "曾子哀矜情得後，臯陶明允罪疑間。", "中朝正賴公持議，那得超然便不還。"]'),
('6befac04-f425-42ba-9de2-14d5d68e30b4','挽刑部王侍郎詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','滿朝忠恕更誰知，家有西京小杜書。',64,'全唐诗/poet.song.83000.json','["滿朝忠恕更誰知，家有西京小杜書。", "揚子清貧安甔石，于公陰德大門閭。", "雖嗟平進鶱騰晚，正值中興選擢初。", "遺直至今談未已，故知人不數曹蜍。"]'),
('b0d7518f-387b-429f-bc88-b0e542faffae','湖南安撫劉龍圖挽詞二首  其一','汪藻','宋','宋诗','song-poetry','','[]','胸次光風霽月明，論文衮衮九河傾。',64,'全唐诗/poet.song.83000.json','["胸次光風霽月明，論文衮衮九河傾。", "一辭天上金鑾直，再見湘南竹馬迎。", "梁相合圖烟閣上，鄭公忽去雪山輕。", "眼看過棹呱呱泣，誰謂衡州浪得名。"]'),
('d1292cff-93b3-48e2-b402-7b71863ac8e6','湖南安撫劉龍圖挽詞二首  其二','汪藻','宋','宋诗','song-poetry','','[]','前年旌節駐江湄，始向清揚識紫芝。',64,'全唐诗/poet.song.83000.json','["前年旌節駐江湄，始向清揚識紫芝。", "名繫南陬朱鳥影，官兼東觀白雲司。", "初驚楚俗招魂些，已見羊公墮淚碑。", "千古風流鍾嶺嶠，湘人應配曲江祠。"]'),
('95f66fdd-5bbb-4e67-b63b-1bc7832652ff','張徽猷挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','家有平津舊學傳，人材嘉祐至和前。',64,'全唐诗/poet.song.83000.json','["家有平津舊學傳，人材嘉祐至和前。", "運籌慣倚將軍樹，畫諾頻分刺史天。", "字得鍾王真楷法，心超粲可祖師禪。", "零陵宴寢公重到，父老追思靜治年。"]'),
('b2004dfa-ecf9-4283-99c2-2e65f3517745','張徽猷挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','天與精忠伯仲間，功成公獨拂衣閑。',64,'全唐诗/poet.song.83000.json','["天與精忠伯仲間，功成公獨拂衣閑。", "專城早應賢侯選，延閣榮聯近侍班。", "去國久違龍尾道，思鄉長夢鹿頭關。", "談經盡日摳衣處，學子相逢淚雨潸。"]'),
('f919aab5-d6d5-4e75-b380-68836c55b756','廣川夫人挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','壼範閨風照里閭，來嬪文伯薦牢蔬。',64,'全唐诗/poet.song.83000.json','["壼範閨風照里閭，來嬪文伯薦牢蔬。", "眼看再世登詞掖，身得三朝錫命書。", "忽報孟軻陳後鼎，漫勞潘岳賦閑居。", "遙知京兆新阡上，千兩爭看會葬車。"]'),
('7f7c1c1c-e555-402a-9ef7-88d8e6cb71fd','廣川夫人挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','秋風一夕霣庭萱，無復春歸壽母門。',64,'全唐诗/poet.song.83000.json','["秋風一夕霣庭萱，無復春歸壽母門。", "修墓已將徵在合，渡江猶喜伯仁存。", "早爲舉案齊眉婦，晚見扶牀坐膝孫。", "全福了無毫髪恨，始知陰德自平反。"]'),
('bcab6863-2507-41ab-a7a9-628d149d3acb','賈太夫人王氏挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','優恩不與外庭同，詔墨親頒出九重。',64,'全唐诗/poet.song.83000.json','["優恩不與外庭同，詔墨親頒出九重。", "鐘鼎承家能兩大，詩書教子得三從。", "葭莩密接椒房慶，脂澤頻增石窌封。", "千里歸來鳴鶴野，湘江正繞墓前松。"]'),
('d84b317e-4734-4bcc-8961-badd9c8efb65','賈太夫人王氏挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','憶昨容衣未祔姑，哀深反哺白頭烏。',64,'全唐诗/poet.song.83000.json','["憶昨容衣未祔姑，哀深反哺白頭烏。", "佳城欲見千年日，旅殯先求五父衢。", "汲汲素冠蒙霧雨，翩翩丹旐歷江湖。", "竟成窀穸干戈後，此事哀榮世所無。"]'),
('07bd86dd-2716-4471-a759-c422fe605902','挽靖安縣君','汪藻','宋','宋诗','song-poetry','','[]','五世傳家德有徽，更嬪蕭史慕靈妃。',64,'全唐诗/poet.song.83000.json','["五世傳家德有徽，更嬪蕭史慕靈妃。", "平生未足魚軒樂，故里空傷羽翣歸。", "雌劍忽先收夜氣，寸荄猶欲報春暉。", "自慚不就磨笄志，尚在徒能淚滿衣。"]'),
('51a5354a-1a7d-4d2a-b949-2c4ffabd4281','龜山上方','汪藻','宋','宋诗','song-poetry','','[]','度險逢幽處，憑誰寫壯懷。',168,'全唐诗/poet.song.83000.json','["度險逢幽處，憑誰寫壯懷。", "連甍棲絕壁，孤塔表長淮。", "地本吳楓接，山今禹績皆。", "潮聲遙入寺，竹影自翻階。", "木杪朱欄出，城坳雪浪埋。", "乾坤迷枉渚，霧雨泄陰崖。", "丹葉經寒在，蒼洲向晚佳。", "魚龍宵聼唄，猿鳥晝窺齋。", "月滿蠙珠實，霜清磬石諧。", "僧盂收柏子，樵徑埽松釵。", "左宦書無鴈，南烹菜有鮭。", "風烟欺短髮，雲水信殘骸。", "竟作何鄉老，虚慚素尚乖。", "江湖今在眼，歸合辦青鞋。"]'),
('4c10fbe4-73aa-440f-bfd2-451c82801271','壽建安郡王','汪藻','宋','宋诗','song-poetry','','[]','氣協高秋爽，祥開寶胄華。',120,'全唐诗/poet.song.83000.json','["氣協高秋爽，祥開寶胄華。", "從今丹府籍，爲瑞帝王家。", "桂滿前宵影，桃舒浩劫花。", "德參龍種後，班次雁行斜。", "早賜真王策，榮膺上將牙。", "兔園宏建敞，貂冕異恩加。", "仙掌高承露，天潢穩泛槎。", "漢邦傳異慶，周篚拜親嘉。", "永接宗枝秀，同符玉歷賒。", "喬松千載壽，他日看肩差。"]'),
('4959850d-383b-4d1c-b368-9193b10fca19','壽俞少宰','汪藻','宋','宋诗','song-poetry','','[]','閩海羣仙地，商秋少昊辰。',240,'全唐诗/poet.song.83000.json','["閩海羣仙地，商秋少昊辰。", "盡裒山嶽氣，來作廟堂身。", "秀拔千尋玉，羣開一角麐。", "早年提巨筆，平步歷通津。", "當宁欣前席，同時歎絕塵。", "鱣堂初簡拔，烏府即騰掀。", "旋綜天官要，還躋政路親。", "南臺沙磧合，兩省衮衣新。", "金鼎功名會，紗籠富貴人。", "房籌須杜決，蕭畫賴曹遵。", "畎畝家蒙福，圖書日效珍。", "百城收唾手，萬事斷垂紳。", "皎皎胸中鑑，融融筆底春。", "羣工推靖密，舉世服清真。", "直宿非箕斗，逢時實渭莘。", "帝嘉忠力久，朝羨寵光頻。", "申伯詩方續，桓榮賜已陳。", "露清龜食息，霜老鶴精神。", "永世承元首，中天轉大鈞。", "歲留稱壽斚，旬日看車輪。"]'),
('9d3775b3-b180-45c8-9eff-c5c4591ccf29','上蔡太師生辰二首  其一','汪藻','宋','宋诗','song-poetry','','[]','萬古儲英氣，生賢鎮廟祧。',288,'全唐诗/poet.song.83000.json','["萬古儲英氣，生賢鎮廟祧。", "方春回暖律，隨帝下神霄。", "早歲陪興運，清忠服邇僚。", "三篇俱命說，兩紀獨承堯。", "爲國隆堂陛，中天斡斗杓。", "光華歸使牒，寧謐載民謠。", "九牧金成鼎，三山石峙橋。", "元圭來舊錫，神寶獻新雕。", "堂起房心次，音諧角徵韶。", "車書人一統，符瑞歲千條。", "璧海材逾盛，沙場虜不驕。", "獻琛皆累譯，入彀有垂髫。", "郭解雙封國，班超五日朝。", "嘉謀從昔合，奕業更誰昭。", "眷禮羣臣異，恩光此日饒。", "授圖開地壯，傍闕築堤遙。", "供帳移金屋，歌鐘實綺寮。", "名園藏茂密，華閣聳岧嶢。", "詔蹕紆臨幸，宸毫紀宴招。", "弟兄聯衮繡，孫子列蟬貂。", "印琢金爲彩，魚懸玉在腰。", "中姻連築沁，外族綴塗椒。", "帝子傳杯勺，宫牆有鼓簫。", "果新無獨享，羮美或親調。"]'),
('a12ff3e9-04e0-4988-b019-15bfe7ccde52','上蔡太師生辰二首  其二','汪藻','宋','宋诗','song-poetry','','[]','宇宙將昭泰，風雲必會同。',288,'全唐诗/poet.song.83000.json','["宇宙將昭泰，風雲必會同。", "帝師黄閣老，人羨黑頭公。", "慶節同堯歷，新陽應嶰筩。", "儀韶來彩鳯，占夢得真熊。", "壽考天資魯，神靈嶽降嵩。", "曲儀尊赤舄，歌詠美彤弓。", "夷險無殊節，誠明信保躬。", "濟川先衆楫，遵渚集飛鴻。", "炳炳丹青筆，堂堂社稷忠。", "斗杓還列宿，廉陛倚層穹。", "文武俱爲憲，詩書孰比隆。", "規模三代遠，謀略萬夫雄。", "字畫諸王品，文章兩漢風。", "早登青瑣闥，頻入紫微宫。", "器敏無餘刃，才豪妙吐虹。", "聲光連日月，氣概俯華戎。", "天上經綸合，人間制作工。", "向來凝庶績，誰復簡清衷。", "絃誦三雍富，舟車四海通。", "地歸銅柱北，春滿玉關東。", "養士菁莪盛，論才駿馬空。", "聖時方密勿，賢業助昭融。", "螭紐乾符正，龍文帝鼐崇。", "伊湯咸有德，房杜不言功。"]'),
('97b5d10f-0930-4627-86fc-63a7ec2a0fd1','哭尚書龍學程公','汪藻','宋','宋诗','song-poetry','','[]','江左推人物，時清得俊髦。',264,'全唐诗/poet.song.83000.json','["江左推人物，時清得俊髦。", "肺肝傾耿介，頭角長英豪。", "鄉郡賓興最，賢關譽望高。", "萬夫爭射鵠，一舉獨連鼇。", "經術爭儒館，詞章重省曹。", "主憂俄旰食，邦禍始秋毫。", "彊寇來侵逼，敷天徧繹騷。", "奮身攄憤懣，銜命何腥臊。", "深入邊亭隧，堅持漢節毛。", "道途千里隔，忠義寸心牢。", "歸報龍顔喜，親聞鳯詔襃。", "功成侔李郭，政合付伊臯。", "超擢陞青瑣，謀謨拱赭袍。", "百官瞻矩矱，八座次甄陶。", "晚歲猶持槖，鄰州暫夢刀。", "台星方兩兩，逝水忽滔滔。", "上意長圖舊，朝廷未閔勞。", "謝安幾一起，秦失卻三號。", "伊昔身遐謫，公時首屢搔。", "交情如骨肉，仕路正風濤。", "里閈期重會，泉臺恨莫逃。", "終天吁永訣，雨淚滴香醪。"]'),
('7bacbe92-b15f-4c1b-b604-6d312cb04785','知非齋','汪藻','宋','宋诗','song-poetry','','[]','真是果安在，況今非故吾。',24,'全唐诗/poet.song.83000.json','["真是果安在，況今非故吾。", "箇中惟醉好，莫忘黄公壚。"]'),
('3a2c92e2-3855-499e-8ea4-b5d1c9c94697','愛閑齋','汪藻','宋','宋诗','song-poetry','','[]','竿木逢場處，何人肯自還。',24,'全唐诗/poet.song.83000.json','["竿木逢場處，何人肯自還。", "秖應韓吏部，能道不如閑。"]'),
('ba993c96-ea60-40f3-b23a-2f51f28a04e2','光風橋','汪藻','宋','宋诗','song-poetry','','[]','茂林修竹下，一水獨縈回。',24,'全唐诗/poet.song.83000.json','["茂林修竹下，一水獨縈回。", "時過赤欄去，風從蘋末來。"]'),
('304ad2e7-d8d1-4434-9260-32e46840e08b','飯牛庵','汪藻','宋','宋诗','song-poetry','','[]','相從龍具中，耕稼亦吾學。',24,'全唐诗/poet.song.83000.json','["相從龍具中，耕稼亦吾學。", "所求一飽同，安用瑩蹄角。"]'),
('1053c8a8-1f5f-4e16-a907-d28da29b7e99','臨賦閣','汪藻','宋','宋诗','song-poetry','','[]','與物相忘久，于何寄此情。',24,'全唐诗/poet.song.83000.json','["與物相忘久，于何寄此情。", "秖應逢勝會，不覺句還成。"]'),
('3c44b95d-bc98-4140-93ea-e8d1f4c22e00','次韻吳明叟集鶴林五首  其一','汪藻','宋','宋诗','song-poetry','','[]','平生夢往處，始到天南峰。',24,'全唐诗/poet.song.83000.json','["平生夢往處，始到天南峰。", "風來荷氣度，日轉松陰重。"]'),
('ffec797f-915b-412d-8429-c80fbd59025c','次韻吳明叟集鶴林五首  其二','汪藻','宋','宋诗','song-poetry','','[]','林間煮茗罷，谷口蒼烟漫。',24,'全唐诗/poet.song.83000.json','["林間煮茗罷，谷口蒼烟漫。", "行看草根露，已作珠璣團。"]'),
('167a0df0-d68f-49bb-935d-9074bebb591f','次韻吳明叟集鶴林五首  其三','汪藻','宋','宋诗','song-poetry','','[]','臨分更攜手，坐聽烟鐘聲。',24,'全唐诗/poet.song.83000.json','["臨分更攜手，坐聽烟鐘聲。", "斜陽有底急，不貸四窗明。"]'),
('10b9b42a-6d75-4ef9-9639-676fe5544f54','次韻吳明叟集鶴林五首  其四','汪藻','宋','宋诗','song-poetry','','[]','支頭澗底石，濯足松下泉。',24,'全唐诗/poet.song.83000.json','["支頭澗底石，濯足松下泉。", "吾生儻有此，無復東西緣。"]'),
('a55cd410-d6ce-4ed9-9513-4769debcce5c','次韻吳明叟集鶴林五首  其五','汪藻','宋','宋诗','song-poetry','','[]','冥冥近嶺翠，瀏瀏長廊風。',24,'全唐诗/poet.song.83000.json','["冥冥近嶺翠，瀏瀏長廊風。", "他年竹林社，記取山王同。"]'),
