('0b08825d-9cd1-47cf-925a-0abcd9d9e764','次韻蔡天任十首  其二','汪藻','宋','宋诗','song-poetry','','[]','幽人午枕夢清熟，書筆滿牀花自開。',32,'全唐诗/poet.song.83000.json','["幽人午枕夢清熟，書筆滿牀花自開。", "兒童誤起聽脩竹，舊雨故人今不來。"]'),
('22845642-e610-4f07-b01f-a715fce0b5ea','次韻蔡天任十首  其三','汪藻','宋','宋诗','song-poetry','','[]','我家君家一牛鳴，相見幾何今露螢。',32,'全唐诗/poet.song.83000.json','["我家君家一牛鳴，相見幾何今露螢。", "要須來往成白首，痛飲共讀離騷經。"]'),
('87036852-40ba-45aa-99f0-5a2ed559b7bd','次韻蔡天任十首  其四','汪藻','宋','宋诗','song-poetry','','[]','江南六月底風土，十日市無山鞠藭。',32,'全唐诗/poet.song.83000.json','["江南六月底風土，十日市無山鞠藭。", "不應梅子趁時節，自是國人愁寓公。"]'),
('30218f4c-6b8f-40cb-b99f-8470dfa6e567','次韻蔡天任十首  其五','汪藻','宋','宋诗','song-poetry','','[]','君家食指如堵牆，不著斗酒求西涼。',32,'全唐诗/poet.song.83000.json','["君家食指如堵牆，不著斗酒求西涼。", "門前䆉稏三百畝，勝我筆耕無寸秧。"]'),
('0fd6d883-7237-448f-b40d-d1aacf244a3e','次韻蔡天任十首  其六','汪藻','宋','宋诗','song-poetry','','[]','關西老將爭捐軀，帳下健兒思草枯。',32,'全唐诗/poet.song.83000.json','["關西老將爭捐軀，帳下健兒思草枯。", "誰能捐粟百萬斛，乞與繞樹南飛烏。"]'),
('6aa414b6-d1dd-4fb1-9f37-43d6ddc8b0ec','次韻蔡天任十首  其七','汪藻','宋','宋诗','song-poetry','','[]','山中種橘無千頭，一飽未卜爲君憂。',32,'全唐诗/poet.song.83000.json','["山中種橘無千頭，一飽未卜爲君憂。", "長年有飯即吾土，問米貴賤還東流。"]'),
('81d15479-3172-46b9-b249-51f5cee0d5c1','次韻蔡天任十首  其八','汪藻','宋','宋诗','song-poetry','','[]','脩廊過午夕陰合，蝴蝶滿庭春草長。',32,'全唐诗/poet.song.83000.json','["脩廊過午夕陰合，蝴蝶滿庭春草長。", "呼兒更卷簾數尺，要放晚晴升屋梁。"]'),
('6fffc8b0-a1ba-4261-aa41-b098f68303fb','次韻蔡天任十首  其九','汪藻','宋','宋诗','song-poetry','','[]','百年都盧能幾日，況迫晼晚行歸休。',32,'全唐诗/poet.song.83000.json','["百年都盧能幾日，況迫晼晚行歸休。", "高車列鼎豈非欲，安步晚食差無憂。"]'),
('e36417c5-dc7d-4233-9766-84679ee286cd','次韻蔡天任十首  其一○','汪藻','宋','宋诗','song-poetry','','[]','中郎故是渥洼種，不受世人金絡頭。',32,'全唐诗/poet.song.83000.json','["中郎故是渥洼種，不受世人金絡頭。", "十年一衲作僧過，卧看烟雨明沙鷗。"]'),
('5551c34c-e156-4de1-8d86-44e32a931b7c','萬上人將游三吳袖杼山居士贈言見過戲成兩絕送之  其一','汪藻','宋','宋诗','song-poetry','','[]','參得湯休五字禪，一缾一鉢去飄然。',32,'全唐诗/poet.song.83000.json','["參得湯休五字禪，一缾一鉢去飄然。", "定知游歷名山徧，吟入江湖萬頃天。"]'),
('902b811d-c591-40a8-83e2-3cf54ca3e6b4','萬上人將游三吳袖杼山居士贈言見過戲成兩絕送之  其二','汪藻','宋','宋诗','song-poetry','','[]','韓子由來未識真，欲還澄觀作詩人。',32,'全唐诗/poet.song.83000.json','["韓子由來未識真，欲還澄觀作詩人。", "若教早被儒冠誤，那得雲山自在身。"]'),
('b20bae9b-32aa-4e63-a4c6-66ea572f1d7f','還璉上人詩卷','汪藻','宋','宋诗','song-poetry','','[]','筆端遊戲詎須頻，短軸才開即可人。',32,'全唐诗/poet.song.83000.json','["筆端遊戲詎須頻，短軸才開即可人。", "月映澄江梅映雪，比君猶自未清新。"]'),
('0a4da088-51f7-4618-bd1a-3747e008b8bb','或傳有歸期陳時發餉靈壽杖求詩','汪藻','宋','宋诗','song-poetry','','[]','聖恩端許返柴荆，便合跏趺過此生。',32,'全唐诗/poet.song.83000.json','["聖恩端許返柴荆，便合跏趺過此生。", "九節煩君持送似，人間險處不重行。"]'),
('5a5f8a64-7665-4ef5-b4b0-d25f9c8c9a9b','銀毫','汪藻','宋','宋诗','song-poetry','','[]','玉爲蟾蜍冰作滴，烏絲欄開寶鴉墨。',32,'全唐诗/poet.song.83000.json','["玉爲蟾蜍冰作滴，烏絲欄開寶鴉墨。", "天孫夜拾瑤草歸，醉舞銀毫鬬春碧。"]'),
('f87eb4a8-196c-442f-8b7b-3c228bb56f53','即事二首  其一','汪藻','宋','宋诗','song-poetry','','[]','燕子將雛語夏深，綠槐庭院不多陰。',32,'全唐诗/poet.song.83000.json','["燕子將雛語夏深，綠槐庭院不多陰。", "西窗一雨無人見，展盡芭蕉數尺心。"]'),
('5ee5c53b-a517-4622-a294-a5664cb43bf9','即事二首  其二','汪藻','宋','宋诗','song-poetry','','[]','雙鷺能忙翻白雪，平疇許遠漲清波。',32,'全唐诗/poet.song.83000.json','["雙鷺能忙翻白雪，平疇許遠漲清波。", "鉤簾百頃風烟上，卧看青雲載雨過。"]'),
('7db68add-e1db-4edc-9524-334181e9d4e7','雜詩  其一','汪藻','宋','宋诗','song-poetry','','[]','古屋清寒雪未消，小窗晴日展芭蕉。',32,'全唐诗/poet.song.83000.json','["古屋清寒雪未消，小窗晴日展芭蕉。", "酸甘荔子清醇酒，更展青芽薦菊苗。"]'),
('ed3617c3-2ed0-4a17-ad1b-4e92d91ad240','雜詩  其二','汪藻','宋','宋诗','song-poetry','','[]','碧窗涼簟惟便睡，露井無塵蔭綠槐。',32,'全唐诗/poet.song.83000.json','["碧窗涼簟惟便睡，露井無塵蔭綠槐。", "夢入醉鄉猶病渇，轆轤聲到枕邊來。"]'),
('54a65f02-a48b-4ec0-9269-f268a98be064','枯禪','汪藻','宋','宋诗','song-poetry','','[]','我行昔到虎溪頭，俗氣浮光兩無盡。',32,'全唐诗/poet.song.83000.json','["我行昔到虎溪頭，俗氣浮光兩無盡。", "當時獨指烟樹杪，有士枯禪雪侵鬢。"]'),
('8253334a-7540-43da-ab45-6d2e3d381e34','浴孫日熊叔雅有詩次其韻二首  其一','汪藻','宋','宋诗','song-poetry','','[]','休論臭腐與神奇，康樂還生謝客兒。',32,'全唐诗/poet.song.83000.json','["休論臭腐與神奇，康樂還生謝客兒。", "我有浮溪農圃在，他年分付小樊遲。"]'),
('9a5cdf0b-8aed-4613-b812-473760e95a9f','浴孫日熊叔雅有詩次其韻二首  其二','汪藻','宋','宋诗','song-poetry','','[]','釋氏夢中親抱送，人言價重百車渠。',32,'全唐诗/poet.song.83000.json','["釋氏夢中親抱送，人言價重百車渠。", "阮家新婦得雄帖，還有數行中令書。"]'),
('557cc2ed-a350-4981-b20c-cca8a20706b0','夜雨遣興','汪藻','宋','宋诗','song-poetry','','[]','風雨鳴窗報客知，還孤月底探梅期。',32,'全唐诗/poet.song.83000.json','["風雨鳴窗報客知，還孤月底探梅期。", "泉聲猶自斷還續，遙想棲禽無定枝。"]'),
('484d18f5-218d-48a9-b8c1-e68b64774b3e','宿酇侯鎮二首  其一','汪藻','宋','宋诗','song-poetry','','[]','當時踏月此長亭，鬢似河堤柳色青。',32,'全唐诗/poet.song.83000.json','["當時踏月此長亭，鬢似河堤柳色青。", "今日重來堤樹老，一簪華髪載寒星。"]'),
('d34645fa-9706-4a58-a9ca-7e3e6be3c916','宿酇侯鎮二首  其二','汪藻','宋','宋诗','song-poetry','','[]','微涼初破候蟲秋，水露草螢光不流。',32,'全唐诗/poet.song.83000.json','["微涼初破候蟲秋，水露草螢光不流。", "搔首與誰論往事，星河無語下城頭。"]'),
('d9809f56-981c-4cac-999c-c591d476daa9','次韻何子應七月十八日書事二首  其一','汪藻','宋','宋诗','song-poetry','','[]','寄語江鷗莫浪猜，先生愛汝水瀠洄。',32,'全唐诗/poet.song.83000.json','["寄語江鷗莫浪猜，先生愛汝水瀠洄。", "自從楚國靈均後，幾箇騷人到此來。"]'),
('23f83d12-4670-46f9-91b1-bcd2e78a4122','次韻何子應七月十八日書事二首  其二','汪藻','宋','宋诗','song-poetry','','[]','卧看山色懶扶輿，擬櫂扁舟學釣魚。',32,'全唐诗/poet.song.83000.json','["卧看山色懶扶輿，擬櫂扁舟學釣魚。", "誰似湘流知我意，秋來三得道州書。"]'),
('0203207c-229c-447c-90c5-dcf657c4facd','呂丞相自天台寄示退老堂詩卷賦此二首  其一','汪藻','宋','宋诗','song-poetry','','[]','心如金石氣如虹，整頓乾坤指顧中。',64,'全唐诗/poet.song.83000.json','["心如金石氣如虹，整頓乾坤指顧中。", "挽去暫成調鼎事，歸來還作釣璜翁。", "東山勝踐今人見，西洛耆年幾客同。", "圮上一編渾未用，赤松那得便從公。"]'),
('61f0fbb7-3a7e-405d-8e76-08ffb3cafcdb','呂丞相自天台寄示退老堂詩卷賦此二首  其二','汪藻','宋','宋诗','song-poetry','','[]','我公英爽笑臞仙，來占東南古洞天。',64,'全唐诗/poet.song.83000.json','["我公英爽笑臞仙，來占東南古洞天。", "幾度傾身安社稷，一朝袖手向林泉。", "長勞海內簪纓望，小作山中杖屨緣。", "謾使吳兒生意氣，涼臺燠館記他年。"]'),
('2c43cc84-6709-4d49-b041-b8f629a35401','盡心堂爲張丞相題','汪藻','宋','宋诗','song-poetry','','[]','道林岳麓天下無，下有萬頃之重湖。',176,'全唐诗/poet.song.83000.json','["道林岳麓天下無，下有萬頃之重湖。", "羣山奇變水清瀉，紫氣合沓來中區。", "張公扶持宇宙了，天與此境爲公娛。", "煙雲沖融几席上，幻出百態供朝晡。", "那知公亦寓焉耳，胸中炯炯如冰壺。", "平生忠孝心鐵石，不磨要與茲山俱。", "向來卜築營草木，汲汲可笑平泉愚。", "何如坐以眼爲界，卷藏雲夢吞衡巫。", "主人歸來頭正黑，劍履未給黄門扶。", "我雖忘世世不爾，唾手行取東西都。", "誰云古今不相及，今見謝傅東山圖。"]'),
('81861835-6604-4535-81d4-d54723f61f38','宿招賢館','汪藻','宋','宋诗','song-poetry','','[]','兒時客衢州，嘗過招賢館。',120,'全唐诗/poet.song.83000.json','["兒時客衢州，嘗過招賢館。", "主人敬愛客，置驛極安便。", "堂前花作屏，堂後竹成援。", "人來銅步嶺，路異玉玉縣。", "回頭四十載，興廢眼中見。", "重尋舊館盟，井逕無復辨。", "沉吟茂林缺，悵望佳石轉。", "道逢里監門，難我曾識面。", "白頭相勞苦，語已涕雙泫。", "破屋爲少留，天寒雨如線。"]'),
('68a03a4a-50f9-4682-a169-d23c5d03b2d9','新安石硯','汪藻','宋','宋诗','song-poetry','','[]','冰蠶吐繭抽銀忽，仙女鳴機號月窟。',64,'全唐诗/poet.song.83000.json','["冰蠶吐繭抽銀忽，仙女鳴機號月窟。", "雲綃裂斷擲殘繻，淪入空山作尤物。", "中書君老不任事，蛛網陶泓空俗骨。", "故令玉質傲松腴，萬縷秋毫聊出沒。"]'),
('bfd8a400-5a3b-42be-99b8-7820379129d9','霜餘溪上絕句','汪藻','宋','宋诗','song-poetry','','[]','水似秋蛇巧作蟠，山如濃翠擁高鬟。',32,'全唐诗/poet.song.83000.json','["水似秋蛇巧作蟠，山如濃翠擁高鬟。", "清風明月元無主，乞我煙蘿茅數間。"]'),
('ff4140ef-12cb-4885-b609-cfeebfabca33','旅次','汪藻','宋','宋诗','song-poetry','','["\u5bd3\u4eba", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u82b1"]','一春略無十日晴，處處溪雲將雨行。',64,'全唐诗/poet.song.83000.json','["一春略無十日晴，處處溪雲將雨行。", "野田春水碧於鏡，人影渡傍鷗不驚。", "桃花嫣然出籬笑，似開未開最有情。", "茅茨煙暝客衣濕，破夢午雞啼一聲。"]'),
('6902146d-62fd-41fe-95a3-750fb2f3d6e3','題賀水部書畫五首  其一','汪藻','宋','宋诗','song-poetry','','[]','茹芝商嶺見時清，來望重瞳日月明。',32,'全唐诗/poet.song.83000.json','["茹芝商嶺見時清，來望重瞳日月明。", "徑去似知真主意，東游不爲羨門生。"]'),
('b04a0067-02b2-4292-b88f-32a0d6db4f0d','題賀水部書畫五首  其二','汪藻','宋','宋诗','song-poetry','','[]','枕中鴻寶謾紛如，尺素題詩已月餘。',32,'全唐诗/poet.song.83000.json','["枕中鴻寶謾紛如，尺素題詩已月餘。", "何物彌明兒女語，剛云不解世間書。"]'),
('0e2c907a-d048-4775-ae83-d587a3331947','題賀水部書畫五首  其三','汪藻','宋','宋诗','song-poetry','','[]','眼見嘉平忍更論，當時爵里至今存。',32,'全唐诗/poet.song.83000.json','["眼見嘉平忍更論，當時爵里至今存。", "子真何苦更名姓，白首區區守市門。"]'),
('e27c6aaf-9600-4e4b-9bdf-b904e9397c74','題賀水部書畫五首  其四','汪藻','宋','宋诗','song-poetry','','[]','紛紛兒輩自名家，妙道從來豈有他。',32,'全唐诗/poet.song.83000.json','["紛紛兒輩自名家，妙道從來豈有他。", "時以丹青寫佛事，不妨柱史入流沙。"]'),
('13fc8e9d-5966-4229-9abb-7747e331f66f','題賀水部書畫五首  其五','汪藻','宋','宋诗','song-poetry','','[]','風吹鳥跡落巖間，付與區中萬古傳。',32,'全唐诗/poet.song.83000.json','["風吹鳥跡落巖間，付與區中萬古傳。", "故遣詩人收拾得，要知身不是頑仙。"]'),
('55b959e2-b33a-4774-93c3-d1041f06c08b','題日暮倚修竹圖','汪藻','宋','宋诗','song-poetry','','[]','藁砧何在復凋年，興在孤鴻落照邊。',32,'全唐诗/poet.song.83000.json','["藁砧何在復凋年，興在孤鴻落照邊。", "遮莫春光無處著，只蔣修竹共嬋娟。"]'),
('d4af4404-3736-46fe-8519-cf22c9a2f8d5','題大年小景','汪藻','宋','宋诗','song-poetry','','[]','忽驚坐上江天渺，半幅鵝溪寫霜曉。',160,'全唐诗/poet.song.83000.json','["忽驚坐上江天渺，半幅鵝溪寫霜曉。", "風低黄蘆潮欲到，平沙無人喧宿鳥。", "而來著眼應萬里，開卷尺餘那盡了。", "須知王孫寄筆力，平日氣吞雲夢小。", "故將點綴調兒輩，不待淋漓翻墨沼。", "滕王蛺蝶往誰並，曹霸驊騮今已少。", "坐令好事費百金，窗几短屏橫軸繞。", "君家此本傳幾世，羈客見之先絕倒。", "江頭歷歷舊行處，好在漁磯落寒潦。", "浮家泛宅歸去來，還看飛鴻臥林杪。"]'),
('9ebe5aca-e8cb-4612-9e4e-8648812a28d0','贈人','汪藻','宋','宋诗','song-poetry','','[]','撥爐應對夜語久，雲灰消盡紅金斗。',48,'全唐诗/poet.song.83000.json','["撥爐應對夜語久，雲灰消盡紅金斗。", "君才合在殿閣間，簿書帷中不應有。", "且置玉堂風雨筆，來試牛刀霹靂手。"]'),
('2918e52e-2d71-4c40-98c5-9f527abc134e','徽宗皇帝靈駕發引挽詞四首  其一','汪藻','宋','宋诗','song-poetry','','[]','圖治八王上，增光六聖餘。',48,'全唐诗/poet.song.83000.json','["圖治八王上，增光六聖餘。", "仁恩漸動植，文物揜詩書。", "未及金縢啟，俄成玉帳虛。", "衣冠歸故國，神已在化胥。"]'),
('068d773d-3623-4356-9586-dfd63fee3c4c','徽宗皇帝靈駕發引挽詞四首  其二','汪藻','宋','宋诗','song-poetry','','[]','三雍無逸雋，四海屢豐年。',48,'全唐诗/poet.song.83000.json','["三雍無逸雋，四海屢豐年。", "嘉瑞標圖諜，休功被管絃。", "鼎成龍即去，書遠雁空傳。", "多少承平老，遙悲杞國天。"]'),
('d4ada17f-2ab9-4dcf-b4e4-44675433f2aa','徽宗皇帝靈駕發引挽詞四首  其三','汪藻','宋','宋诗','song-poetry','','[]','無心居大寶，有子傳鴻鈞。',48,'全唐诗/poet.song.83000.json','["無心居大寶，有子傳鴻鈞。", "萬里方終宴，千年忽上賓。", "地今縱禹葬，天不返虞巡。", "愴極皇情處，還觀吉仗陳。"]'),
('5f18708f-1cf4-4d40-9228-3f2cdb08db2c','徽宗皇帝靈駕發引挽詞四首  其四','汪藻','宋','宋诗','song-poetry','','[]','七聖迷途後，宮車遂不回。',48,'全唐诗/poet.song.83000.json','["七聖迷途後，宮車遂不回。", "乘雲知益遠，濡露但增哀。", "日卜天寧近，山依冰固開。", "千巖應更秀，從此是軒臺。"]'),
('0eaf3590-8912-4581-8ab3-917cc5a30e64','隆祐皇太后挽詞三首  其一','汪藻','宋','宋诗','song-poetry','','[]','四紀歸坤極，三朝賴母臨。',48,'全唐诗/poet.song.83000.json','["四紀歸坤極，三朝賴母臨。", "德齊先后懿，恩及聖君深。", "冊寶追崇祀，衰麻欲報心。", "哀榮千古事，誰復嗣徽音。"]'),
('4c08e51e-c9a3-4be0-8cdd-e0a536237c52','隆祐皇太后挽詞三首  其二','汪藻','宋','宋诗','song-poetry','','[]','化行江漢域，人喜翟車還。',48,'全唐诗/poet.song.83000.json','["化行江漢域，人喜翟車還。", "色養方無阻，神游遽莫扳。", "月沉長樂殿，雲繞慶都山。", "不奉旋京駕，千秋慘聖顔。"]'),
('dcba5486-daa6-42da-91f6-a10772f67842','隆祐皇太后挽詞三首  其三','汪藻','宋','宋诗','song-poetry','','[]','德盛周文母，儀尊嚳正妃。',48,'全唐诗/poet.song.83000.json','["德盛周文母，儀尊嚳正妃。", "山河隳地載，星宿掩軒暉。", "此日哀笳曲，他年大練衣。", "越岡寧久駐，會有灞陵歸。"]'),
('434a471a-63ca-43e7-aa4e-ed13be15512a','何郡王挽詞二首  其一','汪藻','宋','宋诗','song-poetry','','[]','兩紀中天侍冕旒，甘盤仍作濟川舟。',64,'全唐诗/poet.song.83000.json','["兩紀中天侍冕旒，甘盤仍作濟川舟。", "傳家經術終黄閣，袖手功名未白頭。", "身似留侯初出漢，葬如姬旦不忘周。", "千官祖奠城東陌，十里春風鼓吹憂。"]'),
('32bf612a-f815-40e3-a572-9e8461266ba5','何郡王挽詞二首  其二','汪藻','宋','宋诗','song-poetry','','[]','名標南國洞中天，胄出西京鼎足賢。',64,'全唐诗/poet.song.83000.json','["名標南國洞中天，胄出西京鼎足賢。", "早扈六蜚依日月，晚辭三事作神仙。", "馬蹄忽到縢公室，雞夢那逢謝傅年。", "一品真王對異姓，功臣今日數凌煙。"]'),
('ae0d3562-438e-46c5-8e3e-2197f4ddef85','學士蔣公母挽詞三首  其一','汪藻','宋','宋诗','song-poetry','','[]','舉酒頻華族，高堂有白頭。',48,'全唐诗/poet.song.83000.json','["舉酒頻華族，高堂有白頭。", "生兒勝武子，偕老得黔婁。", "未免平反笑，俄驚孺慕憂。", "他年如輟社，牛女有悲秋。"]'),
('40d46d7d-bbaf-4cb5-9e93-d32b72ca86b2','學士蔣公母挽詞三首  其二','汪藻','宋','宋诗','song-poetry','','[]','坐膝扶床處，人看七十稀。',29,'全唐诗/poet.song.83000.json','["坐膝扶床處，人看七十稀。", "孤雛方反哺，雙劍忽隨飛。", "脂澤新封。"]'),
('486d2e68-c8a1-47cd-8281-2b8e6bdcf53b','學士蔣公母挽詞三首  其三','汪藻','宋','宋诗','song-poetry','','[]','才大驚餘子，名高壓四夷。',48,'全唐诗/poet.song.83000.json','["才大驚餘子，名高壓四夷。", "雁書希世事，鵩賦暮年悲。", "習險從人在，杯圈舊事非。", "凄涼嘉樹側，無復板輿歸。"]'),
('918b3683-4aa1-4905-8c03-760048c7a924','詹令人挽詞二首  其一','汪藻','宋','宋诗','song-poetry','','[]','小隱嚴陵下，當年得孟光。',48,'全唐诗/poet.song.83000.json','["小隱嚴陵下，當年得孟光。", "里師爲婦順，子慶事親長。", "洲橘應還熟，庭萱遂不芳。", "他年冠蓋會，來看伏牛岡。"]'),
('a05de057-8b68-4da8-950a-dec2639ffc48','詹令人挽詞二首  其二','汪藻','宋','宋诗','song-poetry','','[]','有子皆通籍，迎扶出萬山。',48,'全唐诗/poet.song.83000.json','["有子皆通籍，迎扶出萬山。", "色難三釜外，眉壽百年間。", "帝渥書泥紫，兒嬉服綵班。", "空成潘岳賦，無復板輿還。"]'),
('40366ba7-e566-4236-b02a-d3223293d43e','天台道中','汪藻','宋','宋诗','song-poetry','','[]','渺渺孤程逐雁飛，茫茫平野見人稀。',64,'全唐诗/poet.song.83000.json','["渺渺孤程逐雁飛，茫茫平野見人稀。", "水紋縈石作蟲篆，麥隴掛山如衲衣。", "日月尚留滄海照，山川盍護翠華歸。", "春風自滿江南岸，不管人間萬事非。"]'),
('f7aec845-6a18-443b-9b2a-cf0158575270','歸州','汪藻','宋','宋诗','song-poetry','','[]','寫真不怨毛延壽，視死還同屈大夫。',32,'全唐诗/poet.song.83000.json','["寫真不怨毛延壽，視死還同屈大夫。", "異世同鄉俱薄命，空令千載起嗟吁。"]'),
('15d5296b-f82f-4898-80b5-2c42cdfaf14a','蠶婦行','汪藻','宋','宋诗','song-poetry','','[]','樹頭恰恰晴鳩喜，上巳人家掃蠶蟻。',128,'全唐诗/poet.song.83000.json','["樹頭恰恰晴鳩喜，上巳人家掃蠶蟻。", "紙窗茅屋春雨寒，買炭添爐中夜起。", "平明採葉晞露痕，隨刀翠縷如絲勻。", "三眠欲食春已老，旋炊新麥祀蠶神。", "咽明足緊解絲簇，猶向前溪問茅卜。", "東鄰西里想殷勤，借問今年幾分熟。", "繰車軋軋桑陰涼，主家人立鴻雁行。", "絲成不得半縷著，一生麻紵隨風霜。"]'),
('05067c1e-4a79-4766-9b93-a5c9fc191e3a','琴高魚','汪藻','宋','宋诗','song-poetry','','[]','百川萃南州，水族何磊砢。',180,'全唐诗/poet.song.83000.json','["百川萃南州，水族何磊砢。", "其間琴高魚，初未列楚些。", "豈堪陪薧鮮，裁用當殽果。", "土人私自珍，千里事封裹。", "遂令四方傳，噍嚼亦云頗。", "俗云琴高生，控鯉宛溪左。", "靈蹤散如煙，遺鬣尚餘顆。", "向來騎鯨人，逸駕嘗慕我。", "不應當時遊，反用此么麽。", "得非效齊諧，怪者記之過。", "彭越小如錢，蹤跡由漢禍。", "越書載王餘，變化更微瑣。", "因知天地間，人莫窮物夥。", "區區於其中，臆決蓋不可。", "僞真吾何知，且用慰頤朵。"]'),
('01e17c42-e24b-4c3f-99ce-9e631099b9a2','餘杭道中','汪藻','宋','宋诗','song-poetry','','[]','過境全疑道若窮，縈紆百轉曲回通。',64,'全唐诗/poet.song.83000.json','["過境全疑道若窮，縈紆百轉曲回通。", "人行山頂半天上，舟繞溪流亂石中。", "獄訟已無前世號，衣冠猶有古人風。", "纔歸又見爭相慶，共聽歌謠萬室同。"]'),
('52768c94-9c0c-48f2-89d4-dff7ae5fbe09','桃源行','汪藻','宋','宋诗','song-poetry','','[]','祖龍門外神傳璧，方士猶言仙可得。',128,'全唐诗/poet.song.83000.json','["祖龍門外神傳璧，方士猶言仙可得。", "東行欲與羨門親，咫尺蓬萊滄海隔。", "那知平地有青春，只屬尋常避世人。", "關中日月空萬古，花下山川長一身。", "中原別後無消息，聞說胡塵因感昔。", "誰教晉鼎判東西，卻愧秦城恨南北。", "人間萬事愈可憐，此地當時亦偶然。", "何事區區漢天子，種桃辛苦望長年。"]'),
('31248778-7c8b-4921-a80c-414abf06db17','謝端明遣騎送酒','汪藻','宋','宋诗','song-poetry','','[]','十樣華樽照蓽門，兒童歌舞徹比鄰。',64,'全唐诗/poet.song.83000.json','["十樣華樽照蓽門，兒童歌舞徹比鄰。", "他鄉忽作青州夢，新歲初嘗白墮春。", "敢謂五漿駭先饋，且欣一盞便醺人。", "扶衰卻老皆公惠，肯學劉伶祀鬼神。"]'),
('3a2612d0-2757-4ebd-b29f-a3df3989afa7','寄何山慧老','汪藻','宋','宋诗','song-poetry','','[]','一見蟬聯話不休，別來林壑又經秋。',64,'全唐诗/poet.song.83000.json','["一見蟬聯話不休，別來林壑又經秋。", "每思樹杪聞清磬，幾欲沙邊具小舟。", "未辦眼前茅一把，誰知身後橘千頭。", "遠公社裏栽蓮處，他日還能着我不。"]'),
('a48c2e07-afb4-42e0-80c1-cdda822aaa8d','題葆真閣','汪藻','宋','宋诗','song-poetry','','[]','溪山上下碧相尋，中有幽人妙陸沉。',64,'全唐诗/poet.song.83000.json','["溪山上下碧相尋，中有幽人妙陸沉。", "自古幾人能轉物，平生萬事要刳心。", "清風不動竹陰直，白日有餘春意深。", "世論未宜輕小隱，可能朝市勝山林。"]'),
('b12f5174-f0c4-4f6c-8f8c-24836c646e56','附舶船送荔子','汪藻','宋','宋诗','song-poetry','','[]','千里雲飄破浪開，使君知道荔枝來。',64,'全唐诗/poet.song.83000.json','["千里雲飄破浪開，使君知道荔枝來。", "未嘗玉井醍醐味，先看金盤火齊堆。", "肯作浪題霜後橘，聊同馳寄隴頭梅。", "到頭應遣纖纖手，笑擘輕紅噢酒盃。"]'),
('69ba4c26-de07-4030-910c-ce461b98ffef','相如','汪藻','宋','宋诗','song-poetry','','[]','詞氣縱橫亦壯夫，低回功業獨何如。',32,'全唐诗/poet.song.83000.json','["詞氣縱橫亦壯夫，低回功業獨何如。", "可憐封禪遺忠意，魂魄應須愧史魚。"]'),
('7a90853d-f0d3-40e0-aec7-ec76b043c715','過定香寺','汪藻','宋','宋诗','song-poetry','','[]','雨痕狼藉龍掛虛，風林岑蔚梟哺雛。',64,'全唐诗/poet.song.83000.json','["雨痕狼藉龍掛虛，風林岑蔚梟哺雛。", "一川窈窕水雲國，百家世世封樵漁。", "鐘來木杪知有寺，杖藜起踏蒼煙孤。", "溪山清明攙楚尾，臺殿傾圮存唐餘。"]'),
('155024f3-a3bb-4352-b272-3a81234394be','吳江','汪藻','宋','宋诗','song-poetry','','[]','好在松江水，丁年憶此過。',48,'全唐诗/poet.song.83000.json','["好在松江水，丁年憶此過。", "垂垂梅子雨，細細麯塵波。", "花老千頭橘，香聞數丈荷。", "百憂今已矣，搔首意如何。"]'),
('d00a486d-3624-4142-9535-f2c153e37b5b','題晉祠','汪藻','宋','宋诗','song-poetry','','[]','一脈泉隨天地老，悠然洗盡半生心。',64,'全唐诗/poet.song.83000.json','["一脈泉隨天地老，悠然洗盡半生心。", "欲令惠及生民遠，須道仁同此水深。", "聖母慈靈昭往古，高題崇號重來今。", "登祠拜罷秋無際，目極西成萬畝陰。"]'),
('913ab216-165b-47a5-8c34-3ccb45c54415','過靖安鎮','汪藻','宋','宋诗','song-poetry','','[]','檣竿歷歷表中流，瞑宿河堤古驛頭。',32,'全唐诗/poet.song.83000.json','["檣竿歷歷表中流，瞑宿河堤古驛頭。", "天遣山川渾着月，人將榆柳共驚秋。"]'),
('033dafa4-a90a-4751-aed0-5082115dde45','過五嶺','汪藻','宋','宋诗','song-poetry','','[]','蜀道如天世路稀，那知五嶺與雲齊。',64,'全唐诗/poet.song.83000.json','["蜀道如天世路稀，那知五嶺與雲齊。", "登臨直上凌霄去，仰視何妨穩步躋。", "仁傑思親聊稅駕，王尊念國欲鞭蹄。", "往還勿謂茲山險，更有無窮萬丈溪。"]'),
('2b973c72-b8ca-45ef-a018-f9dae28e05ba','宿焦山方丈','汪藻','宋','宋诗','song-poetry','','[]','明發理煙艇，歡言濟遙岑。',156,'全唐诗/poet.song.83000.json','["明發理煙艇，歡言濟遙岑。", "盤渦沸風雨，稍辨鐘磬音。", "行行並疏柳，迎客多幽禽。", "扶輿上犖確，始見江湖深。", "臺殿明海色，嵌空憶龍吟。", "修廊延客步，妙香慰人心。", "遐眺未云極，千巖忽秋陰。", "孤月欲生嶺，諸天悉浮金。", "茲遊倍奇絕，況接支道林。", "夜語不知旦，虛窗對橫參。", "人間驚毫末，物外雄窺臨。", "稽首悟真理，微生安所任。", "蒼崖有奇字，霜乾約重尋。"]'),
('ae3e3558-98d8-4616-bef0-cb791d7dd1da','宿上方院','汪藻','宋','宋诗','song-poetry','','[]','問津漁子浦，休駕法王城。',48,'全唐诗/poet.song.83000.json','["問津漁子浦，休駕法王城。", "一雨夜來過，數峰煙際明。", "藤蘿月不到，鐘磬寒愈清。", "信美欲歸去，村鵑如放聲。"]'),
('f3f1353a-80fb-44c9-968c-ee00882b9333','句  其一','汪藻','宋','宋诗','song-poetry','','[]','敵帳夢回驚日處，都城心切望雲時。',16,'全唐诗/poet.song.83000.json','["敵帳夢回驚日處，都城心切望雲時。"]'),
('8595c742-7658-496a-8d6f-dd9cafeb5d04','句  其二','汪藻','宋','宋诗','song-poetry','','[]','班立青雲腰佩玉，手持洪造印塗金。',16,'全唐诗/poet.song.83000.json','["班立青雲腰佩玉，手持洪造印塗金。"]'),
