('7a08337d-e7c5-48c2-9597-b909d45148cd','句  其二','林大聲','宋','宋诗','song-poetry','','[]','雙瀑掛天紳，七杉排斗樣。',12,'全唐诗/poet.song.83000.json','["雙瀑掛天紳，七杉排斗樣。"]'),
('f0b57e56-3a9d-4714-82be-4bba8d518460','偈三首  其一','釋道震','宋','宋诗','song-poetry','','[]','白雲深覆古寒巖，異草靈花彩鳳銜。',32,'全唐诗/poet.song.83000.json','["白雲深覆古寒巖，異草靈花彩鳳銜。", "夜半天明日當午，騎牛背面着靴衫。"]'),
('a92c802e-e250-407f-8977-b27995a5afce','偈三首  其二','釋道震','宋','宋诗','song-poetry','','[]','眼見色時耳便聾，耳聞聲處眼無功。',32,'全唐诗/poet.song.83000.json','["眼見色時耳便聾，耳聞聲處眼無功。", "朝來不耐靈禽報，樹上楊梅似火紅。"]'),
('8dca3289-3012-48af-83f9-8b73a54e3f1c','偈三首  其三','釋道震','宋','宋诗','song-poetry','','[]','石人問枯椿，何時汝發華。',60,'全唐诗/poet.song.83000.json','["石人問枯椿，何時汝發華。", "枯椿怒石人，何得口吧吧。", "石人呵呵笑，枯椿吐異葩。", "紅霞輝玉象，白玉碾金沙。", "借問通玄士，何人不到家。"]'),
('256d412b-9866-4382-afd9-35ab9fc01fe0','插鍬井頌','釋道震','宋','宋诗','song-poetry','','[]','盡道溈山父子和，插鍬猶自带干戈。',32,'全唐诗/poet.song.83000.json','["盡道溈山父子和，插鍬猶自带干戈。", "至今一井如明鏡，時有無風匝匝波。"]'),
('d1a94766-c326-4d2e-bdb2-f619d7b831ee','臨終頌','釋道震','宋','宋诗','song-poetry','','[]','吾年八十三，隨順世言談。',24,'全唐诗/poet.song.83000.json','["吾年八十三，隨順世言談。", "不落思量句，誰人共我參。"]'),
('f81e380f-8aaa-4032-8336-cf76a886432e','重經快閣','范正國','宋','宋诗','song-poetry','','[]','僑寓窮滄海，心棲快閣間。',48,'全唐诗/poet.song.83000.json','["僑寓窮滄海，心棲快閣間。", "煙雲浮四座，几席對千山。", "闌檻何由見，神明悵未還。", "興崇應有待，高躅付誰攀。"]'),
('50437c51-5687-475a-beec-d50248613959','句  其一','范正國','宋','宋诗','song-poetry','','[]','百尺參天隋代柏，可憐終老棟梁材。',16,'全唐诗/poet.song.83000.json','["百尺參天隋代柏，可憐終老棟梁材。"]'),
('b97e5032-653d-4243-9bab-7527e24d4059','句  其二','范正國','宋','宋诗','song-poetry','','[]','雲護儼公塔，天清雷滿池。',12,'全唐诗/poet.song.83000.json','["雲護儼公塔，天清雷滿池。"]'),
('b804d848-9ae1-4a0c-83c8-c2de0a369efe','留題南山寺','吳師能','宋','宋诗','song-poetry','','[]','蒼崖千仞入寒雲，一水分流照眼新。',64,'全唐诗/poet.song.83000.json','["蒼崖千仞入寒雲，一水分流照眼新。", "潭孕蚌胎珠弄月，石藏虹氣玉蒸春。", "輪蹄自老青山路，香火誰閑白日身。", "愧乏涓埃報君祿，蕭條雙鬢滿衣塵。"]'),
('a9a52da8-ed3c-48fb-a9d7-09898c3b4e43','齊雲堂','索逑','宋','宋诗','song-poetry','','[]','巍堂聳太清，日暮倚前楹。',48,'全唐诗/poet.song.83000.json','["巍堂聳太清，日暮倚前楹。", "飛鳥卻在下，落霞相與平。", "眼中窮百越，掌上瞰三城。", "送客一樽酒，懷歸無限情。"]'),
('0ff6148d-6c51-4d30-9b06-c9a87dc32258','大觀間題南京道河亭','史徽','宋','宋诗','song-poetry','','[]','穀雨初晴緣漲溝，落花流水共浮浮。',32,'全唐诗/poet.song.83000.json','["穀雨初晴緣漲溝，落花流水共浮浮。", "東風莫掃榆錢去，爲買殘春更少留。"]'),
('1aef29ee-a2ae-454e-b547-6377cff29fda','夢中作','王珩','宋','宋诗','song-poetry','','[]','杖屨步斜暉，煙村景物宜。',48,'全唐诗/poet.song.83000.json','["杖屨步斜暉，煙村景物宜。", "溪深水馬健，霜重橘奴肥。", "舂罷雞爭黍，人行犬吠籬。", "可憐田舍子，理亂不曾知。"]'),
('3c7b2384-e33a-43dd-8d14-4f270dc614e8','和潘良貴三江亭','王珩','宋','宋诗','song-poetry','','[]','潘郎未覺鬢霜侵，佳致乘閑得得尋。',64,'全唐诗/poet.song.83000.json','["潘郎未覺鬢霜侵，佳致乘閑得得尋。", "古岸渺茫分遠渡，飛甍虛敞快人心。", "融樽想見頻頹玉，季諾由來雅勝金。", "野老固慚東閣客，何妨同作醉翁吟。"]'),
('e25cc6c5-c083-437b-ae4e-7080d4e7a535','五港','張郛','宋','宋诗','song-poetry','','[]','源出金溪北，支分五港開。',48,'全唐诗/poet.song.83000.json','["源出金溪北，支分五港開。", "碧波涵白日，秋水漬蒼苔。", "鱗介多潛育，漁人自溯洄。", "嗟予羈薄宦，因此欲歸來。"]'),
('52f0b2de-6303-45d3-88af-9259d3579f05','翠雲山','張宰','宋','宋诗','song-poetry','','[]','未了人間朱墨緣，強顔荒邑又三年。',32,'全唐诗/poet.song.83000.json','["未了人間朱墨緣，強顔荒邑又三年。", "填胸眯目皆塵土，直到峰頭始豁然。"]'),
('c31bbbf7-e1b5-49db-90a5-2748c9144745','秋日陪郡侯游賢山和眼聽和尚韻','張宰','宋','宋诗','song-poetry','','[]','澹澹秋林掛夕暉，紅塵掃盡白雲飛。',64,'全唐诗/poet.song.83000.json','["澹澹秋林掛夕暉，紅塵掃盡白雲飛。", "不嫌月到常開牖，一任風來自掩扉。", "嘯木山猿如喚夢，啣花石鹿總忘機。", "何人參透其中味，野鶴舒翎天際歸。"]'),
('de452524-1574-4071-82c8-d9d9d714f044','遊南雁','陳經正','宋','宋诗','song-poetry','','[]','雨晴華表插無孤，霧散丹霞落雁湖。',64,'全唐诗/poet.song.83000.json','["雨晴華表插無孤，霧散丹霞落雁湖。", "洞窈不知紅日過，峰危倩得白雲扶。", "人間誰道無蓬島，天地分明有畫圖。", "山鳥罔知人未醒，隔林款款喚提壺。"]'),
('10aaa18e-5e0a-4207-999e-f384f29a63ea','句','張迪','宋','宋诗','song-poetry','','[]','此地從來寒暑偏，扇紈不曾遭棄捐。',16,'全唐诗/poet.song.83000.json','["此地從來寒暑偏，扇紈不曾遭棄捐。"]'),
('94b38bfe-8e9b-49b2-8b98-251aebfb04a1','義了道人昨夢齋','吳表臣','宋','宋诗','song-poetry','','[]','不受塵網纏，祝髪趣幽屏。',36,'全唐诗/poet.song.83000.json','["不受塵網纏，祝髪趣幽屏。", "回觀真夢事，超然得深省。", "寂照涵虛空，夢覺等前境。"]'),
('0728d96d-f607-44ce-9f1a-fa741ec0a95c','句','吳表臣','宋','宋诗','song-poetry','','[]','木落千山瘦，天高一雁橫。',12,'全唐诗/poet.song.83000.json','["木落千山瘦，天高一雁橫。"]'),
('9eaec23c-3b68-413c-b8bf-b2d1e0b4133d','臨平山','沈汝諧','宋','宋诗','song-poetry','','[]','山勢分明飲水鼉，孤峰西轉鬰嵯峨。',32,'全唐诗/poet.song.83000.json','["山勢分明飲水鼉，孤峰西轉鬰嵯峨。", "不須探問山童藥，且揖朝來爽氣多。"]'),
('b83e90ef-0629-481b-81b2-93aceb63cba9','冰谷泉','沈汝諧','宋','宋诗','song-poetry','','[]','甃石纔深數尺餘，一泓清冷若冰壺。',32,'全唐诗/poet.song.83000.json','["甃石纔深數尺餘，一泓清冷若冰壺。", "泉源定與安平接，二水輕甘略不殊。"]'),
('b3668e5b-a77e-4c06-a09c-6a3f9ad6d273','滌慮軒  其一','左譽','宋','宋诗','song-poetry','','[]','過眼浮雲是也非，桔槔俯仰政兒嬉。',32,'全唐诗/poet.song.83000.json','["過眼浮雲是也非，桔槔俯仰政兒嬉。", "欲知身世俱無染，看取蓮花在水時。"]'),
('a8742882-6916-4351-85ee-9d1dcbb417fc','滌慮軒  其二','左譽','宋','宋诗','song-poetry','','[]','洗盡塵機萬慮空，胸中冰鑒許誰同。',32,'全唐诗/poet.song.83000.json','["洗盡塵機萬慮空，胸中冰鑒許誰同。", "今宵正可談風月，借問何人是阿戎。"]'),
('da3908a9-dcbd-4547-b26b-a6cfcf728017','崇教寺筠軒','左譽','宋','宋诗','song-poetry','','[]','夜憶清軒上，都忘居會稽。',48,'全唐诗/poet.song.83000.json','["夜憶清軒上，都忘居會稽。", "秋聲先在竹，月色最宜溪。", "銀漢簷前直，玉繩天外低。", "何人倚欄檻，爲聽下莊雞。"]'),
('f6cd87e4-3bae-49cf-8f61-dda732f03e07','游洞霄','左譽','宋','宋诗','song-poetry','','[]','洞霄九鎖本不扃，天柱一峰非浪名。',224,'全唐诗/poet.song.83000.json','["洞霄九鎖本不扃，天柱一峰非浪名。", "上同天目映寥廓，下與大滌通滄溟。", "誰藏瓊□在石室，真與福地齊金庭。", "遠游飛昇儼遺迹，玄同指向真典刑。", "當年樓臺極縹緲，至今氣象藏深冥。", "已知六月九萬里，箇中一念三千齡。", "金龍玉簡天上降，琳宮絳闕逢相迎。", "紫霞黄雲覆其室，青衣素錦分諸靈。", "虛皇臺高步虛徹，宣科玉音神所聽。", "自憐學道二十年，此心已與湖山盟。", "朅來奉祠北山下，恍若飛昇朝帝庭。", "道人觀妙清且秀，尚指鄉關論赤城。", "何年吏隱奉香火，愧無妙句如丹青。", "木公金母吾未識，且看松根生茯苓。"]'),
('85121971-47a6-4bb5-a2ad-8c84402293d5','句  其一','左譽','宋','宋诗','song-poetry','','[]','孤嶼藏煙迷宿鷺，扁舟和雨駐沙鷗。',16,'全唐诗/poet.song.83000.json','["孤嶼藏煙迷宿鷺，扁舟和雨駐沙鷗。"]'),
('802aa0b8-c2d6-4cf4-81f5-188e799d1829','句  其二','左譽','宋','宋诗','song-poetry','','[]','山色晚來猶入座，藥苗春後自成畦。',16,'全唐诗/poet.song.83000.json','["山色晚來猶入座，藥苗春後自成畦。"]'),
('f1fde084-4bb7-40e1-b30e-f36047638ad3','句','張濃','宋','宋诗','song-poetry','','[]','如今若把菱花照，猶恐相逢是夢中。',16,'全唐诗/poet.song.83000.json','["如今若把菱花照，猶恐相逢是夢中。"]'),
('55966451-5f45-444d-9479-168179f9e4ec','西湖','左鄯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','疊疊山腰繫冷雲，疏疏雨脚弄黄昏。',32,'全唐诗/poet.song.83000.json','["疊疊山腰繫冷雲，疏疏雨脚弄黄昏。", "松聲更带溪聲急，不是離人也斷魂。"]'),
('a4814165-1ab0-4f81-986c-ff45eb4146be','過秦氏舊宅','左鄯','宋','宋诗','song-poetry','','[]','格天閣在人何在，偃月堂深恨亦深。',64,'全唐诗/poet.song.83000.json','["格天閣在人何在，偃月堂深恨亦深。", "不見洛陽圖白髪，但知郿塢積黄金。", "直言動便遭羅纖，舉目寧知有照臨。", "炙手附炎俱不見，可憐泥澤滿牆陰。"]'),
('fc58ab0e-31f2-4192-9548-3f4e15a88712','報澈上人','韓岊','宋','宋诗','song-poetry','','[]','早歲京華聽越吟，聞君江海分逾深。',32,'全唐诗/poet.song.83000.json','["早歲京華聽越吟，聞君江海分逾深。", "他時若寫蘭亭會，莫畫高僧支道林。"]'),
('6496caac-b867-41e3-a7ed-2beefb4b5f45','南雁山','陳經邦','宋','宋诗','song-poetry','','[]','老從神武掛塵冠，要與傍人分碧山。',64,'全唐诗/poet.song.83000.json','["老從神武掛塵冠，要與傍人分碧山。", "障落風前排集雁，影翻日下舞雙鸞。", "雲間隔斷塵寰杳，月牖光通宇宙寬。", "安得此身生羽翼，朗吟飛過萬峰間。"]'),
('fc40476c-a95c-4901-86e0-929f4b420a23','蕭何','馬永卿','宋','宋诗','song-poetry','','[]','創業艱難尚爾爲，太平奢侈可前知。',32,'全唐诗/poet.song.83000.json','["創業艱難尚爾爲，太平奢侈可前知。", "欲令後世無能過，可笑蕭何爾許癡。"]'),
('2d0bf8f6-0e15-459d-a14e-6fe19b866009','謁馮侍御  其一','馬永卿','宋','宋诗','song-poetry','','[]','久知仕宦有升沉，此際門闌不覺深。',64,'全唐诗/poet.song.83000.json','["久知仕宦有升沉，此際門闌不覺深。", "半世人間初識面，一朝林下遽論心。", "依依落日催歸騎，嫋嫋秋風動客襟。", "鄉里小兒何太喜，異鄉流落有知音。"]'),
('2e9dbdb3-bb37-4d82-9569-8f3536a2b3a4','謁馮侍御  其二','馬永卿','宋','宋诗','song-poetry','','[]','珍重吾鄉有異人，後來誰可繼前塵。',64,'全唐诗/poet.song.83000.json','["珍重吾鄉有異人，後來誰可繼前塵。", "久邀乾竺爲心友，未許巢由作外臣。", "桑梓荒殘俱動念，衣冠零落合相親。", "白□碧竹龍華路，茅屋三間願卜鄰。"]'),
('2d7e9fcb-7fb9-47cc-92fc-67160c3db621','贈申孝子世寧','馬永卿','宋','宋诗','song-poetry','','[]','六月烈日日正中，時有叛將號羣兇。',224,'全唐诗/poet.song.83000.json','["六月烈日日正中，時有叛將號羣兇。", "平人血染大溪浪，比屋焰照鵝湖峰。", "白刃紛紛蔽行路，六合茫茫何處去。", "妻見夫亡不敢啼，母棄兒奔那忍顧。", "藥市申翁鬢有霜，臥病經時不下牀。", "平生未省見兵革，出門正爾逢豺狼。", "豺狼滿市如流水，追索金繒心未已。", "可憐累世積陰功，今日將爲兵死鬼。", "世寧孝行何高高，慨慷性命輕鴻毛。", "此時自欲赴黄壤，欣然延頸迎霜刀。", "至孝感兮天地動，白日在光百川湧。", "三刀不死古今稀，一命自月神靈擁。", "羣賢激賞爭作歌，要使汝名長不磨。", "何時上書達天聽，詔加旌表高嵯峨。"]'),
('64de23db-5e2e-472d-8520-0e28dd735653','題大隱堂','陳大任','宋','宋诗','song-poetry','','[]','池面嫩荷初汎水，欄邊新筍欲齊簷。',32,'全唐诗/poet.song.83000.json','["池面嫩荷初汎水，欄邊新筍欲齊簷。", "先生盡景論文飲，不覺斜陽已上簾。"]'),
('2c16710f-4418-45e5-92ed-ebf44db68ca4','句','歐陽識','宋','宋诗','song-poetry','','[]','資水西來兼邵水，龍山橫鶩際梅山。',16,'全唐诗/poet.song.83000.json','["資水西來兼邵水，龍山橫鶩際梅山。"]'),
('066bbb1d-2b33-423b-b99d-fca2874dd1c7','次韻濟川西山避暑','錢紳','宋','宋诗','song-poetry','','[]','西山藴靈異，九曲面崚嶒。',240,'全唐诗/poet.song.83000.json','["西山藴靈異，九曲面崚嶒。", "泉石漱鳴玊，松蘿掛古藤。", "勢雄掀宇宙，地大壓丘陵。", "日永清陰覆，朝來爽氣澄。", "幽尋嘉賞致，結客避歊蒸。", "散髪喧畦畛，支頤倦躡登。", "武陵百慮釋，丹列遠思凝。", "度樾追遐景，煎茶憶若冰。", "土芝青削玉，琬液綠如澠。", "霜氣連蒼昊，冰威鑠鈍蠅。", "心酣醒復醉，意適寢還興。", "蝸角徒爭觸，蜂腰謾逞能。", "纓塵心自濯，松韻響無明。", "自廓倚天劍，愁無繋日繩。", "舒懷高達士，得趣鄙山僧。", "雲態幾相挽，禽音似許譍。", "嵐姿渾欲滴，秋色漸相矜。", "籧笛凉余思，衾禂樂未曾。", "虚閑消毒螫，放曠屏牽仍。", "高興無時盡，何辭興再乘。"]'),
('a45447ee-b8c5-4512-b435-479e93e12205','九月十五日濟川諸公同遊因成長韻','錢紳','宋','宋诗','song-poetry','','[]','好山如佳人，變態百種好。',240,'全唐诗/poet.song.83000.json','["好山如佳人，變態百種好。", "陰晴朝暮間，可愛不可道。", "時時思一見，如垢久不澡。", "我來正清秋，令人豁懷抱。", "秋色佳有餘，俗客迹如掃。", "佳哉二三友，在席毎傾倒。", "杖策窮縈迴，高絕須一到。", "幽尋不厭倦，遇境即窮討。", "堦前千歳松，閲盡衆木槁。", "庭下百尺井，空傳天眼老。", "陸子賞遺味，至今泉浩浩。", "高僧掛衣去，誰識衣中寶。", "九淵深非龍，徒見腓百草。", "衆泉失蹊逕，迸散不可考。", "世事毎如此，所合輙顛倒。", "夜深山色清，更對冰輪皓。", "竹栢影參差，水中交荇藻。", "迴棹艤波心，如在蓬瀛島。", "舉觴望青天，醉鄉得深造。", "兹遊須再嗣，萬事殊未保。"]'),
('0598dac9-5919-43f8-98c3-814e8ab39b57','遊惠山一首','錢紳','宋','宋诗','song-poetry','','[]','挐舟到山寺，詩句偶緣情。',48,'全唐诗/poet.song.83000.json','["挐舟到山寺，詩句偶緣情。", "山自錫無後，寺因泉有名。", "樓陰回夕景，樹色向冬榮。", "就水别茶味，全勝它處烹。"]'),
('329c1fab-538a-402c-8421-ad245f8b1882','題青山寺','錢紳','宋','宋诗','song-poetry','','[]','窈窕招提入翠微，碧波千頃照巖扉。',64,'全唐诗/poet.song.83000.json','["窈窕招提入翠微，碧波千頃照巖扉。", "白頭人向斜陽立，黄帽僧衝細雨歸。", "芳樹遠從湖外見，殘雲紛繞雁邊飛。", "分明一片佳山景，卻憶松邊筍蕨肥。"]'),
('3159631b-4e6a-41eb-993f-36fccec65f58','句','史祖道','宋','宋诗','song-poetry','','[]','明朝送我扁舟去，字水秋風有幾篙。',16,'全唐诗/poet.song.83000.json','["明朝送我扁舟去，字水秋風有幾篙。"]'),
('eef4a665-8192-4af7-8789-bb9fc6b07c7d','遊青城','鄭庭芬','宋','宋诗','song-poetry','','[]','短筇穿白雲，直上孤峰頂。',24,'全唐诗/poet.song.83000.json','["短筇穿白雲，直上孤峰頂。", "下瞰六時崖，前臨七折嶺。"]'),
('c4fd830c-78d8-4e6b-b4f1-4f454a89bea6','陸子泉','鄭庭芬','宋','宋诗','song-poetry','','[]','塔中老宿空留影，湖上嬰兒漫記名。',32,'全唐诗/poet.song.83000.json','["塔中老宿空留影，湖上嬰兒漫記名。", "唯有階前一泓井，至今不改舊時清。"]'),
('8292e459-109c-460b-aad0-ba9693e434c0','題昌州牛尾驛','鄭庭芬','宋','宋诗','song-poetry','','[]','龍尾道中退朝客，雕鞍寶馬黄金勒。',32,'全唐诗/poet.song.83000.json','["龍尾道中退朝客，雕鞍寶馬黄金勒。", "誰憐遠使足馳驅，夜半孤村牛尾驛。"]'),
('79b05970-cadc-4491-bdb2-0c7af0fef7a0','上陳瑩中右司生日詩','韓駒','宋','宋诗','song-poetry','','[]','悠悠大塊間，萬類紛相敵。',264,'全唐诗/poet.song.83000.json','["悠悠大塊間，萬類紛相敵。", "偉哉拔俗人，真宰豈無力。", "六經陷邪說，諸儒用一律。", "天未喪斯文，公生抱絕識。", "著書羅古今，射策開胸臆。", "前輩幾欲盡，後來昧所適。", "天將激頹波，公生秉孤直。", "數諫難居中，三已無愠色。", "海宇屬無虞，天工或曠職。", "天實佑皇帝，公生藴奇德。", "培成棟梁資，一旦壯王國。", "禁網雖小寛，疲俗未全逸。", "天惟念我民，公生冨才術。", "簸揚雲雨勢，諸方待膏澤。", "天既責公深，眉壽天何惜。", "行看佩相印，不羨登仙籍。", "南山雅望重，北斗威聲赫。", "禀生固難朽，吐納自不息。", "惟昔軒冕徒，浪喜山林迹。", "留侯追赤松，志就亦何益。", "傅說爲列星，但已脫寰域。", "孰知我公貴，與國長無極。"]'),
('7c88b96f-05bd-409b-8e6b-3f0c1ae65d70','孫朝散母封彭城郡君賜霞帔以詩賀之','韓駒','宋','宋诗','song-poetry','','[]','孟母壯日家三遷，欻見季子聯朝班。',184,'全唐诗/poet.song.83000.json','["孟母壯日家三遷，欻見季子聯朝班。", "因逢吾君鼓舜絃，不惜一邑榮參騫。", "里門初接金花牋，爭賀羊酒相摩肩。", "不疑平反奉慈歡，壽逾九十留朱顔。", "又逢吾君禮高年，太息加賜彭城田。", "霞冠彩帔麗且閑，復賀羊酒歡如前。", "四時觴客客滿筵，緋衣侍立不笑言。", "飲及二斗已醉眠，起作兒啼衆欣然。", "人間樂事到底偏，夫人此樂人人傳。", "忠臣孝子希兩全，近代只數先生賢。", "從予乞詩費雕鐫，借君詩囊爲君編，那知又有南陔篇。"]'),
('0ea921fd-2206-4aa9-9617-3ebe95c4151e','利濟橋亭詩','韓駒','宋','宋诗','song-poetry','','[]','大夫官業世所驚，老覺軒冕非真榮。',224,'全唐诗/poet.song.83000.json','["大夫官業世所驚，老覺軒冕非真榮。", "斯文自屬吾黨事，正恐無路逃虚名。", "生猶不見皇甫謐，死豈肯投劉禹錫。", "茂陵一幅入漢宮，世間共怪無遺帙。", "哀哉若人用意深，自言身作鶴鳴陰。", "著書遺子千萬軸，人初笑我籯無金。", "萬仞磨崖刊好語，那知百年蒼蘚汙。", "爾來夜夜虹貫天，山下居民未知處。", "周詩不列石鼓歌，後世恐歎遺羲娥。", "於今購市完家集，野老何知亦摩挲。", "川流可平石可腐，只此殺青垂萬古。", "五百驪珠固已奇，插架不知猶幾許。", "公今未暇歸田廬，且當驅童曬蠧魚。", "不辭借取車連軫，要讀人間未見書。"]'),
('eca4f2b9-401c-45e7-932a-94cb8e761ba6','善相陳君持介甫子瞻手字示予戲贈短歌','韓駒','宋','宋诗','song-poetry','','[]','古來相馬失之瘦，仲尼亦作喪家狗。',128,'全唐诗/poet.song.83000.json','["古來相馬失之瘦，仲尼亦作喪家狗。", "唇紅齒白癡小兒，不羞障面欺羣醜。", "鶴冲居士術如神，東走梁宋西峨岷。", "諸公蹭蹬未遇日，坐中知是非常人。", "只今白髪無餘産，短褐逡巡列侯館。", "世人胸中無黑白，不知居士明雙眼。", "嗟予塵貎天所付，不須強覓封侯處。", "書生只倚一片心，他日相逢記裴度。"]'),
('46af4216-8baf-455d-8b5e-392a13a5c375','送葛亞卿欲行不一過僕','韓駒','宋','宋诗','song-poetry','','[]','吾廬偪仄門三尺，慚愧春風巧相覓。',166,'全唐诗/poet.song.83000.json','["吾廬偪仄門三尺，慚愧春風巧相覓。", "叩關惟許葛王孫，有時藉草傾餘瀝。", "汝不如南池主人車載客，紅旗皂蓋行遠陌。", "又不如東郭公子柳藏門，青娥綠髪坐開樽。", "是身牢落終何爲，人不汝嫌汝自嗤。", "伸眉一笑能幾時，忽聞春盡王孫歸。", "春風欲盡猶有情，飄英堕絮俱傷神。", "王孫未歸迹已掃，秣馬膏車何太早。", "明日一杯愁送春，後日一杯愁送君。", "君應萬里隨春去，若到桃源記歸路。"]'),
('f55cc21d-9e0a-42b6-a99f-97e2e19a8028','術者吳毅乞詩欲至塞上','韓駒','宋','宋诗','song-poetry','','[]','少年吳君抱奇識，四海一身求异術。',64,'全唐诗/poet.song.83000.json','["少年吳君抱奇識，四海一身求异術。", "逢時更得玄安文，西方諸侯正須君。", "高賢未遇世亦有，相見爲陳休與咎。", "我自與世如參辰，從來無心怨牛斗。"]'),
('bf8915cd-a8cd-405c-aa80-0b410a624691','陽羨葛亞卿爲海陵尉作葺春軒余爲賦之','韓駒','宋','宋诗','song-poetry','','[]','昔聞先生隱吳儂，當窗十里横烟峰。',208,'全唐诗/poet.song.83000.json','["昔聞先生隱吳儂，當窗十里横烟峰。", "今見先生爲楚吏，繞墻四面縈烟水。", "從來楚俗带吳風，曲折徑路深房櫳。", "舍前繫船柳千丈，舍後參天竹萬叢。", "牙籖插架似蓬館，白拂掛壁如僧宮。", "掃地焚香欣客至，羮魚飯稻愁罇空。", "不溷不清惟寂寞，大笑先生致身錯。", "青衫猶作布衣心，朱門却有田居樂。", "筆回造化天工怒，胸包今古時人愕。", "甘窮自許元次山，蹈海還尋魯仲連。", "吾曹一歡豈易得，世間百歲俱可憐。", "何用北窗翻朽策，且向東亭弄春色。", "我當酌酒壽主人，灘前飛下雙鸂鶒。"]'),
('9f9bcfec-1aee-46a8-a4ee-26ff8d0bffca','謝錢珣仲惠高麗墨','韓駒','宋','宋诗','song-poetry','','[]','王卿贈我三韓紙，白若截肪光照几。',160,'全唐诗/poet.song.83000.json','["王卿贈我三韓紙，白若截肪光照几。", "錢侯繼贈朝鮮墨，黑如點漆光浮水。", "舊傳績溪多老松，奚超既死松亦空。", "易水良工近名世，真材始不歸潘翁。", "蕭然南堂一居士，赤管隃糜無月賜。", "借問玄圭何自來，去年海中持節使。", "明窗晏坐不匆匆，引紙磨墨寒生風。", "自笑平生綰蛇蚓，更慚爾雅注魚蟲。", "殷勤二物從來遠，禆海環瀛眼中見。", "若欲揮寫藏名山，不如却作談天衍。"]'),
('1d5c35c4-c6a9-460a-8d64-b8265071aa42','行次汝墳次韻惇夫天慶觀檜','韓駒','宋','宋诗','song-poetry','','[]','紛紛物態逞，檜獨不自奇。',120,'全唐诗/poet.song.83000.json','["紛紛物態逞，檜獨不自奇。", "雨露長鶴骨，風霜痩龍皮。", "要經摧暴力，豈顧合抱遲。", "雖無艾納香，不著寄生枝。", "結根已千丈，凛凛誰寒之。", "其下羽客居，同睨歲月移。", "君行叩玄關，豈但息馬疲。", "高材笑小草，異質憐孤姿。", "思古而嗟今，皇皇不磷緇。", "微言怨不亂，似爲賤子施。"]'),
('421f1b0a-011c-4e40-b7d4-4400b8e91b2f','京口同蘇景謨游招隱寺','韓駒','宋','宋诗','song-poetry','','[]','居閑從散吏，尋幽詣精廬。',96,'全唐诗/poet.song.83000.json','["居閑從散吏，尋幽詣精廬。", "城陰徑綠野，谷口橋清渠。", "稍稍叢竹合，依依昔人居。", "輕雲起釋嶠，細水鳴循除。", "聞鴉問長老，豎拂談真如。", "振衣念新浴，曲肱欣飯蔬。", "兹游尚倥偬，再至期躊躇。", "獨行豈辭遠，徐步當乘車。"]'),
('872455f1-ce54-4b2e-a5d0-8d970be72777','送松陵老農','韓駒','宋','宋诗','song-poetry','','[]','呼舟越洪濤，笑識江南山。',96,'全唐诗/poet.song.83000.json','["呼舟越洪濤，笑識江南山。", "此行爲子來，正擬一笑歡。", "相逢不忍别，丘壑同躋攀。", "如何舍我去，使我心悁悁。", "子實名家後，翰墨素所便。", "老農雖自謂，念子安知田。", "世故亦已足，擾擾徒自憐。", "天寒歲且盡，趣駕扁舟還。"]'),
('9c5af84a-e00f-4258-b473-5664d570c6e2','贈俞清老','韓駒','宋','宋诗','song-poetry','','[]','偃卧一茆屋，給事兩胡奴。',48,'全唐诗/poet.song.83000.json','["偃卧一茆屋，給事兩胡奴。", "日喫脫粟飯，時乘下澤車。", "人生但如此，其實足自娛。", "過此誠更樂，不及復何如。"]'),
('d5a21d28-0aa3-47b7-8fa0-0ae36e2b380c','謝人寄梅花瑞香花二首  其一','韓駒','宋','宋诗','song-poetry','','[]','殷勤江南客，折花良慰予。',48,'全唐诗/poet.song.83000.json','["殷勤江南客，折花良慰予。", "炯晝孤光冷，曜夜清影疏。", "連林玩不足，一枝清有餘。", "諒無和羮用，飄落将何如。"]'),
('12cf6062-9977-4882-a1f2-4e1e6fcbfa19','謝人寄梅花瑞香花二首  其二','韓駒','宋','宋诗','song-poetry','','[]','道人不愛色，而愛聞清香。',48,'全唐诗/poet.song.83000.json','["道人不愛色，而愛聞清香。", "方春謝凡卉，凌晨玩孤芳。", "以兹蘭蕙質，種彼葵藿場。", "常恐亂微馥，采采歸幽房。"]'),
('5ffe7f05-28ad-493c-907d-f8c3aed352c7','淮上書事','韓駒','宋','宋诗','song-poetry','','[]','平楚盡積水，長淮多奇峰。',72,'全唐诗/poet.song.83000.json','["平楚盡積水，長淮多奇峰。", "蕭條月曜夜，浩蕩風鳴冬。", "客行未可歸，敝裘那得重。", "寒氣搜病骨，清潭貌衰容。", "遠游有滯念，將老無歡悰。", "故國渺萬里，去此嗟誰從。"]'),
('82552004-f4bc-470f-b88e-d8b5b13a8b5d','至國門聞蘇文饒將出都戲贈長句兼簡其兄世美','韓駒','宋','宋诗','song-poetry','','[]','去年夷門十月雪，九衢日昃行人絕。',288,'全唐诗/poet.song.83000.json','["去年夷門十月雪，九衢日昃行人絕。", "騎驢兀兀無所之，破袖迎風手龜裂。", "度橋並塹得君家，入門脫帽猶凛冽。", "急燃濕束暖我寒，徐出清酤寧我渴。", "君家自無儋石儲，蟹黄熊白能俱設。", "平生見酒唇不濡，是夕連觥耳方熱。", "羣奴夜僵喚不聞，我亦鼾鼻眠東閣。", "明朝起過城南翁，尚記新聲一笑發。", "東歸每嘆懷抱真，西來又喜顔色接。", "方將慷慨豁心胸，未用峥嶸驚歳月。", "城南詩翁况遠來，門前雪泥又活活。", "豈知萬事不可期，却樹吳檣背城闕。", "人生動若參與商，咫尺無論限秦粤。", "君聞吾語雖少留，但恐一歡成電掣。", "念昔相見無他娛，誦詩徵事相誇捷。", "氣凌俗子旁若無，偶坐時聞竊嚅囁。", "扵今落落誰汝憐，老屋陳編自怡悅。", "寄言詩翁儻留滯，歲晚勤迂故人轍。"]'),
('4458e5a2-f006-4baf-87fa-2bf96426eb80','題中寂堂','韓駒','宋','宋诗','song-poetry','','[]','虎卧文公廬，鳥巢道林室。',144,'全唐诗/poet.song.83000.json','["虎卧文公廬，鳥巢道林室。", "本自無俗喧，何由辨真寂。", "逃溺必登山，避燔必趨澤。", "君看好静人，萬慮固未息。", "是心儻已刳，對境起亦得。", "上人早聞道，晚順世間迹。", "振衣下靈巖，飛錫來上國。", "高堂亦何有，萬卷繞四壁。", "客來倚風廊，晤語終日夕。", "莫言門如市，中有忘機客。", "吾曹詩酒汙，此道誰目擊。", "唯應寂時趣，獨有清士識。"]'),
('a63f3089-366f-48bc-bf79-10abc0aa0e5a','題李伯時畫昭君圖','韓駒','宋','宋诗','song-poetry','','[]','昭君十七進御時，舉步弄影颺蛾眉。',166,'全唐诗/poet.song.83000.json','["昭君十七進御時，舉步弄影颺蛾眉。", "自憐窈窕出絕域，八年未許承丹墀。", "在家不省闚門戶，豈知萬里從胡虜。", "豐容靚飾亦何心，尚欲君王一回顧。", "君不見班姬奉養長信宮，又不見昭儀舉袂前當熊。", "盛時寵幸只如此，分甘委弃匈奴中。", "春風漢殿彈絲手，持鞭却趁奚鞍走。", "莫道單于無復情，一見纖腰爲回首。", "含悲遠嫁來天涯，不知夔州處女髽。", "寄語雙鬟負薪女，炙面慎勿輕離家。"]'),
('289280f6-f53b-4921-957f-1f8cfad1ca86','送子飛弟歸荆南','韓駒','宋','宋诗','song-poetry','','[]','往在東堂時，唯汝年尚少。',288,'全唐诗/poet.song.83000.json','["往在東堂時，唯汝年尚少。", "木槍鬭羣兒，竹弓射飛鳥。", "今來跨鞍馬，昂然丈夫表。", "入門恍莫識，與語意方了。", "脫汝來時装，夜闌酌清醥。", "當歌喜未定，感舊色已悄。", "念我三年官，自裹衣中麨。", "東去盡勾吳，北行薄全趙。", "汝亦上岷峨，大江窮浩渺。", "一年兩附書，皮筒到家少。", "那知此相遇，乾鵲果前兆。", "我性本齊緩，汝資誠楚慓。", "相逢各相規，一月語連曉。", "憶汝初結髪，讀書先尉繚。", "謂須壮執殳，單于壘時挑。", "豈期尚羈旅，但存雙目瞭。", "我恨緣詩窮，賃屋隘而湫。", "尚容三尺牀，使汝眠奥穾。", "二升糴祿粟，醜婢羮荼蓼。", "時時得鶉兔，傍竈親燔燎。", "纔爲十日歡，鄰里厭煩擾。", "朝來著戎服，數匝絲絛繞。", "辭我出門去，歸袖風矯矯。", "還家對寒食，渚宮聞雉鷕。"]'),
('bcb1acf1-5187-458b-91ed-99c2c291dc3e','贈鄒醫','韓駒','宋','宋诗','song-poetry','','[]','華陀一卷世不留，玉函三十龍宮收。',216,'全唐诗/poet.song.83000.json','["華陀一卷世不留，玉函三十龍宮收。", "奇方异訣上帝求，稚川肘後真悠悠。", "東京仲景儒家流，韻疏思密豈自由。", "妙技乃與俞跗侔，後來繼之有髯鄒。", "二子天授非人謀，內經歳久誤弗讐。", "髯獨覃思窮披搜，草木寒温脉沉浮。", "如磁取鐵無虚投，朅來游梁自高郵，翰林雜試推君優。", "天廷錫带塗精鏐，我窮羈旅古汴溝。", "有婦抱病柴門幽，巫醫百請不頷頭。", "卒然邀君爲停輈，决去沉痾如决疣。", "自言不取千金酬，只求一詩當琳璆。", "高風絕藝兩罕儔，我才不迨前人羞。", "祝君尚壮勉勿休，自致名譽傾公侯。"]'),
('214d269c-4290-4f81-b828-aea86f030803','津上人蝸舍','韓駒','宋','宋诗','song-poetry','','[]','昔在焦居士，野宿蝸牛廬。',96,'全唐诗/poet.song.83000.json','["昔在焦居士，野宿蝸牛廬。", "今津又繼之，結草王城居。", "容膝審易安，蓋頭無復餘。", "心澄動境寂，意遠陋室虚。", "我家數畝田，荒薈自墾除。", "茆簷正如此，日入歸荷鋤。", "一朝寓華屋，慨然念村墟。", "疵物儻有激，投老同歸歟。"]'),
('f3e86856-27ed-4d6f-97a1-062a95100556','夏日過中寂堂','韓駒','宋','宋诗','song-poetry','','[]','苦熱倦中夜，黎明與雞興。',96,'全唐诗/poet.song.83000.json','["苦熱倦中夜，黎明與雞興。", "匪云事干謁，庶以逃炎蒸。", "駕言城東廬，停軌日未升。", "白簟帷薄縠，青盆水寒冰。", "凉飇從天來，一掃槃中蠅。", "聊除咂膚厄，諒豈棕拂能。", "攬衣念歸去，謂是天候澄。", "超視尚午景，世故何相仍。"]'),
('7708f73b-e5f7-4c4e-a103-2d308e5be178','送蜀僧潮音歸鄉','韓駒','宋','宋诗','song-poetry','','[]','野水有善溉，山雲忽爲霖。',96,'全唐诗/poet.song.83000.json','["野水有善溉，山雲忽爲霖。", "古來出世士，亦有利物心。", "上人成都來，袈裟塵土侵。", "兩屨踏京國，一鉢提叢林。", "諸公握手舊，孰不低垂簪。", "尚陋湯休詩，肯鼓庭蘭琴。", "獨說衆妙行，聽者開煩襟。", "我作五字偈，彌天識潮音。"]'),
('aa9ed4df-b92d-408f-9a46-5c5be865c487','贈蔡伯世','韓駒','宋','宋诗','song-poetry','','[]','君家夫人林下風，長齋繡佛鳴金鐘。',192,'全唐诗/poet.song.83000.json','["君家夫人林下風，長齋繡佛鳴金鐘。", "侍兒百指亦清浄，凌晨梵唄聲摩空。", "潭潭大第依喬木，日午捲簾按絲竹。", "古調猶歌于蒍于，麗詞不唱新翻曲。", "有美一子天麒麟，孟嘉外孫見淵明。", "掃地焚香坐絃誦，不聞梵唄連歌聲。", "俗子何由共杯酒，容我叩門呼小友。", "欲求百萬錢買鄰，倒囊只有詩千首。", "安得一把茆蓋頭，榆林從君父子游。", "敢期絲竹娛下客，但喜白業同精修。", "秃襟短帽紛紛是，眼明見此裦衣士。", "和詩論道有餘閑，爲語故家遺俗事。"]'),
('f3bfc4c1-6c38-4676-92a6-08949174f371','贈趙伯魚','韓駒','宋','宋诗','song-poetry','','[]','昔君叩門如啄木，深衣青純帽方屋。',112,'全唐诗/poet.song.83000.json','["昔君叩門如啄木，深衣青純帽方屋。", "謂是諸生延入門，坐定徐言出公族。", "爾曹氣味那有此，要是胸中期不俗。", "荆州早識高與黄，誦二子句聲琅琅。", "後生好學果可畏，僕常倦談殊未詳。", "學詩當如初學禪，未悟且遍參諸方。", "一朝悟罷正法眼，信手拈出皆成章。"]'),
('686704f0-1393-43d2-ba91-596f7ea1c2c6','答蔡伯世食筍','韓駒','宋','宋诗','song-poetry','','[]','蓴絲化鹽豉，槐葉資新麵。',204,'全唐诗/poet.song.83000.json','["蓴絲化鹽豉，槐葉資新麵。", "豈知苦竹萌，風味常獨擅。", "昔我居錦城，屢喫田家飯。", "扶杖自入箐，煨此犢角蠒。", "後參鶴林禪，餽我桑門饌。", "烝烝沸鼎中，亂下白玉片。", "惟無他物乘，始覺真味現。", "三年客東都，錦籜寧復見。", "千金洛陽來，惟充大官饍。", "前時過君食，欣逢故人面。", "那知列仙臞，已雜蒯通雋。", "吾寧飽甘肥，憤吒那忍嚥。", "請歸謂主孟，廚人後當諫。", "苦苣雜嘉蔬，沉香和甲煎。", "柯亭既誤椽，畫障或遭練。", "古來可歎事，千載寄明辨。", "作詩弔籜龍，助子當食歎。"]'),
('9751e615-9530-49e3-a7bc-b13b40760272','食煮菜簡呂居仁','韓駒','宋','宋诗','song-poetry','','[]','曉謁呂公子，解带浮屠宮。',192,'全唐诗/poet.song.83000.json','["曉謁呂公子，解带浮屠宮。", "留我具朝餐，喚奴求晚菘。", "洗箸點鹽豉，鳴刀芼薑葱。", "俄頃香馥坐，雨聲傳鼎中。", "方觀翠浪涌，忽變黄雲濃。", "爭貪歙鉢暖，不覺定碗空。", "憶登金山頂，僧飯與此同。", "還家不能學，永費烹調功。", "硬恐動牙頰，冷愁傷肺胸。", "君獨得其妙，堪持餉衰翁。", "異時聞豪氣，愛客行庖豐。", "殷勤故煮菜，知我林下風。", "人生各有道，旨蓄用禦冬。", "今我無所營，枵腹何由充。", "豈惟臺無餽，菜把尚不蒙。", "念當勤致此，亦足慰途窮。"]'),
('24dcdba6-7d5b-46f3-abdb-3fceb8f22d18','送倪巨濟將仕','韓駒','宋','宋诗','song-poetry','','[]','汴流六月翻黄沙，小舟兀浪如乘槎。',240,'全唐诗/poet.song.83000.json','["汴流六月翻黄沙，小舟兀浪如乘槎。", "赤日下照烘朝霞，腹鳴肩舉氣喘呀。", "亂眠僕夫股相加，柁樓晨飯羮黄茄。", "時時矯首望土岸，木末殷轉江州車。", "渴逢石泉不得汲，椎鼓催發無停檛。", "問君何爲趣還家，答云五載居京華。", "夜窗讀書眼生花，每食不飽潛咨嗟。", "母髪半白弟髻丫，有妹久闕躬絲麻。", "寄書細字如昏鴉，問胡眷戀歸期賒。", "來時書笈手自拏，今歸上堂兩脚靴。", "壽觴要及開霜瓜，子志如此良可嘉。", "勸子博學如横罝，麋麟兔鹿盡所遮。", "或典而法浮而葩，要歸於正謹去邪。", "行如種植慎萌芽，念當務實勿求誇。", "我行買犢耕三巴，佇子佳譽來天涯。"]'),
('6dd1349d-55ff-4c8c-97ac-2ae71750f082','蒲城即事','韓駒','宋','宋诗','song-poetry','','[]','鄙夫世長物，未老宜幽棲。',96,'全唐诗/poet.song.83000.json','["鄙夫世長物，未老宜幽棲。", "一朝起蓬屋，著籍通金閨。", "遇合始僥倖，非才終見擠。", "尚想歐陽公，罪棄荆山西。", "步行意方盛，庭趨顔遂低。", "行趨豈云異，喜愠自不齊。", "微官何足論，等求飽糠粞。", "三徑如可卜，歲晚歸扶犂。"]'),
('d346e85f-06e8-4123-bee6-63f89069a43e','題分秀堂','韓駒','宋','宋诗','song-poetry','','[]','南山有佳色，偃蹇誰能分。',96,'全唐诗/poet.song.83000.json','["南山有佳色，偃蹇誰能分。", "如何公子堂，卧看南山雲。", "公子秀公族，高標出塵氛。", "總戎亦何事，晏坐參罏薫。", "晴空萬劍戟，衛此明將軍。", "鄙夫在蒲城，簿書劇絲棼。", "青山不到眼，終日無一欣。", "寄聲幸分我，與子同清芬。"]'),
('e89f6c52-d373-48a8-abb3-be516b6b2110','題默軒','韓駒','宋','宋诗','song-poetry','','[]','李君誦兵法，辨若懸河流。',120,'全唐诗/poet.song.83000.json','["李君誦兵法，辨若懸河流。", "時平棄不用，胸中欝奇謀。", "三年蓮勺鹵，一室藏深幽。", "默翁笑自謂，晏坐無餘求。", "不言非真默，但與木石儔。", "說默默時說，吾聞諸前修。", "君看古宗密，妙義難爲酬。", "及談不二門，則卷機鋒收。", "我以辨自喜，窮思戒摩兠。", "君宜尚勉旃，負杖從吾游。"]'),
('ef79191b-8de1-4581-a93f-bf8997b51b42','題王內翰家李伯時畫太一姑射圖二首  其一','韓駒','宋','宋诗','song-poetry','','[]','太一真人蓮葉舟，脫巾露髪寒颼飀。',128,'全唐诗/poet.song.83000.json','["太一真人蓮葉舟，脫巾露髪寒颼飀。", "輕風爲帆浪爲檝，卧看玉宇浮中流。", "中流蕩漾翠綃舞，穩如龍驤萬斛舉。", "不是峰頭十丈花，世間那得蓮如許。", "龍眠畫手老入神，尺素幻出真天人。", "恍然坐我水仙府，蒼烟萬頃波粼粼。", "玉堂學士今劉向，禁直岧嶤九天上。", "不須對此融心神，會植青藜夜相訪。"]'),
('3febd24c-b6ec-4d9f-9b50-89f0873653e5','題王內翰家李伯時畫太一姑射圖二首  其二','韓駒','宋','宋诗','song-poetry','','[]','海上仙山邈雲水，神居縹緲凌虚起。',128,'全唐诗/poet.song.83000.json','["海上仙山邈雲水，神居縹緲凌虚起。", "風餐露宿不知年，八極浮游一彈指。", "何人紙筆作此圖，細看尚恐冰爲膚。", "便欲憑軒問連叔，却愁掛壁驚肩吾。", "雖有此圖傳自古，矯矯真容那得覩。", "萬里中州不少留，曉發咸池暮玄圃。", "而今玉殿開珠宮，鸞旗鶴馭紛長空。", "神兮早御飛龍下，願賜千秋年穀豐。"]'),
('d5224fe4-2f13-4b11-ad7a-856871bb9995','出宰分寧别舊同舍五首  其一','韓駒','宋','宋诗','song-poetry','','[]','公車八千言，自獻十二旒。',72,'全唐诗/poet.song.83000.json','["公車八千言，自獻十二旒。", "落筆中書罷，石渠並英游。", "方欣洛陽遇，已慨周南留。", "明堂多楩柟，詎須汝薪槱。", "三年望龍斷，艱難身百憂。", "鬢髪五分白，更落天南陬。"]'),
('5e8f76ef-bcf5-409a-8326-3d675c88b52c','出宰分寧别舊同舍五首  其二','韓駒','宋','宋诗','song-poetry','','[]','念我行老矣，才拙世所捐。',72,'全唐诗/poet.song.83000.json','["念我行老矣，才拙世所捐。", "青綾未頻直，黄紬且安眠。", "飽聞縣西寺，修椽壓山巓。", "中谷五百衆，上堂鼓闐闐。", "王程儻餘暇，玆焉著幽禪。", "自擷雙井茶，與僧酌雲泉。"]'),
('08a4acc6-337c-4711-9547-f07d5a639154','出宰分寧别舊同舍五首  其三','韓駒','宋','宋诗','song-poetry','','[]','昔慚芸閣姿，斥守蒲城市。',72,'全唐诗/poet.song.83000.json','["昔慚芸閣姿，斥守蒲城市。", "五占天雞星，未抆逐臣淚。", "歸聞長樂鐘，疲馬思一試。", "挈挈今又東，敝邑臨無地。", "人生縛微官，大似侏儒戲。", "升沉各幾時，怨欣兩當置。"]'),
('04f160bf-7998-4f4c-b966-79a0cfb22133','出宰分寧别舊同舍五首  其四','韓駒','宋','宋诗','song-poetry','','[]','益昌剗移文，道州拙催科。',72,'全唐诗/poet.song.83000.json','["益昌剗移文，道州拙催科。", "我愚象二子，將奈分寧何。", "吾君放勛姿，於今萬邦和。", "縣令但拱手，排衙鼓鳴鼉。", "故人怒挽船，勸勿凌江波。", "君其謝故人，我亦聊絃歌。"]'),
('ac700490-a3a2-4db3-9dc2-b4a180adf63b','出宰分寧别舊同舍五首  其五','韓駒','宋','宋诗','song-poetry','','[]','陽山昔御史，夷陵前校書。',72,'全唐诗/poet.song.83000.json','["陽山昔御史，夷陵前校書。", "坐法竄未久，遇赦罪已除。", "故時同舍郎，半直承明廬。", "獨奔江西縣，道里三千餘。", "皇明燭幽隱，儻復哀臣愚。", "念當脫江瘴，與子聯朝裾。"]'),
('8e2c985d-c55e-4c00-8a18-234abfe54f4a','西山梅花二首  其一','韓駒','宋','宋诗','song-poetry','','[]','空山有佳人，寒林弄孤芳。',48,'全唐诗/poet.song.83000.json','["空山有佳人，寒林弄孤芳。", "晚分天女白，夜奪嫦娥光。", "亭亭照清淺，欲渡横無梁。", "微風起復滅，爲我傳幽香。"]'),
('9180aa14-5b78-45c0-93ce-628fd5d6b635','西山梅花二首  其二','韓駒','宋','宋诗','song-poetry','','[]','紛紛月彩動，炯炯霜容開。',48,'全唐诗/poet.song.83000.json','["紛紛月彩動，炯炯霜容開。", "不覩散清影，寧知花底來。", "平明忽天風，磵谷空蒼苔。", "惆悵有餘馥，繁英安在哉。"]'),
('102623a8-bdb1-4053-8d99-677e209d8d7d','入鳴水洞循源至山上','韓駒','宋','宋诗','song-poetry','','[]','崇山蓄靈泉，萬古去不息。',144,'全唐诗/poet.song.83000.json','["崇山蓄靈泉，萬古去不息。", "瀦爲百斛深，散入千渠溢。", "其東滙民田，又北尋山腋。", "斷崖如破瓜，飛瀑中蕩激。", "大聲或雷霆，細者亦竽瑟。", "末流垂半山，十里見沸白。", "得非拖天紳，常恐浮地脉。", "呂梁丈人老，尚與汨偕出。", "我欲蹋驚湍，下窮齦齶石。", "惜哉意徒然，屬此歲凛慄。", "安得汝南周，斷取白蛟脊。", "歸之龍泉峰，山門夜喧席。"]'),
('4e7f9df0-f68d-4c8d-957a-74bd748fab5d','黄龍山中','韓駒','宋','宋诗','song-poetry','','[]','未雨萬木翳，既雨羣山開。',72,'全唐诗/poet.song.83000.json','["未雨萬木翳，既雨羣山開。", "山神若眷予，一掃風中埃。", "摩雲夾路松，禪伯手自栽。", "我來植拄杖，聽度松風哀。", "幽賞未云足，暮色蒼然來。", "何當白玉輪，碾上西南垓。"]'),
('ec28f7ff-961a-4696-b7d3-3b51b4c92f93','分寧大竹取爲酒罇短頸寛大腹可容二升而漆其外戲爲短歌','韓駒','宋','宋诗','song-poetry','','[]','此君少日青而癯，爾來黑肥如瓠壺。',128,'全唐诗/poet.song.83000.json','["此君少日青而癯，爾來黑肥如瓠壺。", "縮肩短帽壓兩耳，無乃戲學騶侏儒。", "人言腹大中何有，不獨容君更容酒。", "未須常要託後車，滑稽且作先生友。", "少陵匏罇安在哉，次山石臼空飛埃。", "茆簷對客夜驚笑，麴生叩門何自來。", "老向人間不稱意，但覺淵明酒多味。", "乞取田家老瓦盆，伴我年年竹根醉。"]'),
('d2a15b72-2f98-47e7-a7d3-645c3ea1a8f4','湖南有大竹世號貓頭取以作枕仍爲賦詩','韓駒','宋','宋诗','song-poetry','','[]','湖南人家養貍奴，夜出相乳肥其膚。',128,'全唐诗/poet.song.83000.json','["湖南人家養貍奴，夜出相乳肥其膚。", "買魚穿柳不蒙聘，深蹲地底老欲枯。", "誰將作枕置榻上，擁腫似慣眠氍毹。", "慵便玉枕分已無，孫生洗耳非良圖。", "茆齋紙帳施團蒲，與我同歸夜相娛。", "更長月黑試附卧，鼠目尚爾驚睢盱。", "坐令先生春睡美，夣魂直繞赤沙湖。", "更煩黄妳好看取，走入旁舍無人呼。"]'),
('d03a0f4f-bb3c-4e6a-8350-d7a7688c85e2','竹爐','韓駒','宋','宋诗','song-poetry','','[]','蘇州平生淡無欲，長物從來博山足。',64,'全唐诗/poet.song.83000.json','["蘇州平生淡無欲，長物從來博山足。", "斵石燒磁俱碌碌，削筒爲之方絕俗。", "净名居士眠胡牀，夢餘竹齋春晝長。", "不知柏子起烟縷，但覺細細風吹香。"]'),
('15f8cfd7-a9df-46eb-822b-6d2a027e9233','題梅蘭圖二首  其一','韓駒','宋','宋诗','song-poetry','','[]','寒梅在空谷，本自凌冰霜。',72,'全唐诗/poet.song.83000.json','["寒梅在空谷，本自凌冰霜。", "託根傲衆木，開花陋羣芳。", "遙風遞清氣，迥水涵孤光。", "美實初可口，採掇升巖廊。", "念爾如傅說，和羮初見嘗。", "不須羨幽蘭，深林自吹香。"]'),
('6db6a143-c208-43c8-9ae5-0f8253893ebc','題梅蘭圖二首  其二','韓駒','宋','宋诗','song-poetry','','[]','幽蘭不可見，羅生雜榛菅。',72,'全唐诗/poet.song.83000.json','["幽蘭不可見，羅生雜榛菅。", "微風一披拂，餘香被空山。", "凡卉與春競，念爾意獨閑。", "弱質雖自保，孤芳諒難攀。", "高標如湘纍，歲晚投澄灣。", "不須羨寒梅，粉骨鼎鼐間。"]'),
('63ad572a-9bbc-420a-9262-b7a898d2e5e9','題湖南清絕圖','韓駒','宋','宋诗','song-poetry','','[]','故人來從天柱峰，手提石廪與祝融。',130,'全唐诗/poet.song.83000.json','["故人來從天柱峰，手提石廪與祝融。", "兩山坡陀幾百里，安得置之行李中。", "下有瀟湘水清瀉，平沙側岸搖丹楓。", "漁舟已入浦溆宿，客帆日暮猶爭風。", "我方騎馬大梁下，怪此物象不與常時同。", "故人謂我乃絹素，粉墨妙手煩良工。", "都將湖南萬古愁，與我頃刻開心胸。", "詩成畫往默惆悵，老眼復厭京塵紅。"]'),
('f8d2879e-07d2-4779-ac49-151704eb675a','送鄉人李元景歸蜀','韓駒','宋','宋诗','song-poetry','','[]','問君游梁今幾歲，歸去聊爲羨于計。',64,'全唐诗/poet.song.83000.json','["問君游梁今幾歲，歸去聊爲羨于計。", "入門四壁妻子空，恍若游仙墮塵世。", "令兄文價如相如，世人但知千里駒。", "不知更有八百里，看取蹴蹋辭鹽車。"]'),
('b007af21-ba8c-47e6-86bf-bfffe1e42d11','蜀張氏賜書詩','韓駒','宋','宋诗','song-poetry','','[]','張公昔蹋中朝班，夜隨仙官上九關。',128,'全唐诗/poet.song.83000.json','["張公昔蹋中朝班，夜隨仙官上九關。", "再拜天皇少却立，手掣雲漢歸人間。", "鈎陳熟視不呵責，坐令光耀驚塵寰。", "至今公家蜀江上，紫氣夜屬岷峨山。", "昭回斷缺久未補，女媧鍊石亦已艱。", "似聞天上列星怒，下問雲漢何時還。", "丁寧賢孫善拂拭，不用構閣深防閑。", "爲公作詩刻堅石，可使萬古驅神奸。"]'),
('8e8652bd-9b29-4d1b-a411-509bd7b57c0e','送嘉申父佐岷州','韓駒','宋','宋诗','song-poetry','','[]','大梁初見公，萬卷不離目。',96,'全唐诗/poet.song.83000.json','["大梁初見公，萬卷不離目。", "五年再見之，萬卷已在腹。", "字體畫沙新，詩篇翻水速。", "閉門誰與娛，翛然數椽屋。", "白頭揚子雲，久合居天祿。", "誰令佐山州，路遠車脫輻。", "近聞皇華使，漕米出深谷。", "有能推挽公，可敵千章木。"]'),
('0a1d1207-ad4c-4a9a-8432-2bd8ccbf5945','次韻程致道館中桃花','韓駒','宋','宋诗','song-poetry','','[]','桃花如昭君，服飾靚以豐。',144,'全唐诗/poet.song.83000.json','["桃花如昭君，服飾靚以豐。", "徘徊顧清影，似爲悅已容。", "數枝有餘妍，窈窕禁省中。", "何如武陵岸，繽紛落天風。", "我夢泛舟去，春流濯鳬翁。", "豈知限重門，風搖鋪首銅。", "憶汝初破萼，時當樓雪融。", "亭亭怯餘寒，賴此赤日烘。", "蓬山十載夢，翬飛左昇龍。", "重來迹已換，一掃凡花空。", "髪有今歲白，顔無故時紅。", "三嗅三歎息，繁英爲誰穠。"]'),
('c1a85311-f665-4c84-847d-ee2b93575b88','次韻黑氈歌','韓駒','宋','宋诗','song-poetry','','[]','黝奴生長西南夷，朅來中國蒙公知。',176,'全唐诗/poet.song.83000.json','["黝奴生長西南夷，朅來中國蒙公知。", "提攜十年行萬里，寵愛肯爲新人移。", "但願結髪爲玄妻，不願能歌名雪兒。", "夜寒僮僕盡僵縮，我獨嫵媚呈餘姿。", "只慚家世不可考，辯舌推源煩惠施。", "苦言瀘水異京水，生女那復白如脂。", "或疑烏几定乃祖，又言黑貂爲姆師。", "託身似與青女約，薦枕常須黄妳隨。", "長伸兩脚得安卧，莫作杜老憐腰支。", "他年老朽幸勿棄，從來弱質不自持。", "賢哉翁詩善名我，不須更換崑崙詩。"]'),
('f7cae3e7-d688-483e-85d7-0da3b1c45950','送許少卿出守邠州','韓駒','宋','宋诗','song-poetry','','[]','長安北走彭原路，白葦黄茆列亭戍。',128,'全唐诗/poet.song.83000.json','["長安北走彭原路，白葦黄茆列亭戍。", "山形漸險溪水流，行人可肯回車去。", "豈知中有古邠州，十里沙平水漫流。", "鴈飛蔽野葡萄曉，馬放連雲苜蓿秋。", "次卿卧聽朝雞久，請試從來撥煩手。", "未許相如喻蜀歸，且看魏尚臨邊守。", "雜花撩亂草鮮明，二月春風卷旆旌。", "燕寝凝香無一事，樂哉飲酒莫論兵。"]'),
('ec925968-7b1a-4f16-a2f1-88c4c3b56cd0','送趙承之秘監出守南陽','韓駒','宋','宋诗','song-poetry','','[]','繁臺十月寒颼飀，置酒共祖南陽侯。',160,'全唐诗/poet.song.83000.json','["繁臺十月寒颼飀，置酒共祖南陽侯。", "九士一客相獻酬，皆言南陽山水幽。", "菊泉釀酒不論石，土酥醍醐出肥牛。", "使君樓前橘柚古，丞相堂下蒲蓮稠。", "夜燃蠟炬賓醉舞，春風欹眠百花洲。", "各持一觴勸公飲，此行樂矣公何求。", "我獨倚杖商聲謳，此公人間第一流。", "方今羣賢從法駕，金狨塞路嘶驊騮。", "獨令此公守一州，臨分慷慨淚莫收。", "南陽南陽樂復樂，歸來歸來無久留。"]'),
('504a9f32-0834-4e97-91f6-03fec21b7af3','次韻館中諸公游慈雲寺','韓駒','宋','宋诗','song-poetry','','[]','嘉蔬隨客庖，香飯出僧甑。',156,'全唐诗/poet.song.83000.json','["嘉蔬隨客庖，香飯出僧甑。", "聊爲一飽謀，未暇談禪病。", "二公當代豪，詞林氣方盛。", "五言謹詩律，百罰嚴酒令。", "樂與同舍郎，共此給園浄。", "想像斜川游，何如舞雩詠。", "甘瓜自雍丘，肥芡來新鄭。", "肴果各有攜，笑我室懸磬。", "陋質謝不往，實愧瓊瑤映。", "人生一車足，那須富千乘。", "有興驅短轅，寧辭沮洳徑。", "及時速行樂，莫待苦脚脛。", "炎暑忽已闌，當念時難更。"]'),
('9a4d5185-12cb-4a2d-b153-64b6e469a9a1','飲酒次人韻','韓駒','宋','宋诗','song-poetry','','[]','淺瀨見魚游，澄潭知鶴没。',192,'全唐诗/poet.song.83000.json','["淺瀨見魚游，澄潭知鶴没。", "疑乘青霞珮，徑墮白銀闕。", "平生探學海，中年悟禪悅。", "應須臨渺瀰，庶以稱超越。", "回塘大圓鏡，新蒲細于髪。", "綠扇互低昂，玉顔爭秀發。", "良辰宴觴豆，炎曦脫巾韈。", "荷聲過急雨，竹影敷凉月。", "緩行躡芳草，移坐蔭深樾。", "何當酒拍浮，恣聽舟搖兀。", "而我方抱鉛，上馬自腰笏。", "叩門不聞呼，造席無乃咄。", "詎敢陵崆屼，幸許窺剞劂。", "願公開迷雲，令我入理窟。", "雄篇出月脇，妙思露天骨。", "蹇步那由追，眢井愧先竭。"]'),
('fb2a4648-3ded-4782-bcfc-159308f150f2','榮事堂詩','韓駒','宋','宋诗','song-poetry','','[]','安陽太守韓公子，曉带魚符出卿寺。',194,'全唐诗/poet.song.83000.json','["安陽太守韓公子，曉带魚符出卿寺。", "一朝帝語傳人間，轉覺公家有榮事。", "公家請從忠獻論，高牙大冊來疏恩。", "往時醉白堂中醉，手自列戟留諸孫。", "諸孫盡是璠璵器，悃愊無華漢循吏。", "大錢方送使君歸，竹馬爭迎細侯至。", "公不見大小二鄭公，五十年間風化同。", "豈如五馬來接武，作堂崔嵬刊帝語。", "又不見韋家兩世侯，父出傳舍子入州。", "豈如世作本郡守，坐令卓異驚千秋。", "安陽遺民識忠獻，眼見王孫四封傳。", "請公静夜占此堂，定有榮光屬天半。"]'),
('34876e5b-c155-47dd-90ca-bb2ed860a68c','題采菊圖  其一','韓駒','宋','宋诗','song-poetry','','[]','黄菊有何好，且寄平生懷。',48,'全唐诗/poet.song.83000.json','["黄菊有何好，且寄平生懷。", "遇酒興不淺，無酒意亦佳。", "此理誰復明，自昔寡所諧。", "空餘采菊圖，寂寞懸高齋。"]'),
('c60d9bc2-e54e-4bef-986b-5e8aa5e84896','題采菊圖  其二','韓駒','宋','宋诗','song-poetry','','[]','今日菊始華，叢雁鳴相和。',48,'全唐诗/poet.song.83000.json','["今日菊始華，叢雁鳴相和。", "若無一觴酒，如此重九何。", "悠然數酌盡，會心豈在多。", "醒來不復記，散髪東山阿。"]'),
('3a245f96-444f-4cf2-9e51-7f50cd7a2716','次韻胡元茂館中直宿','韓駒','宋','宋诗','song-poetry','','[]','我老百念冷，饑餐困來眠。',72,'全唐诗/poet.song.83000.json','["我老百念冷，饑餐困來眠。", "寄聲同學兒，莫作舊眼看。", "春風石渠水，小雨生微瀾。", "知君直宿夜，夣憶朐山泉。", "起裁五字詩，意如溟渤寛。", "白頭和高唱，回光覺酸寒。"]'),
('728a4abe-a5b1-4898-aee1-18bbe9d0feae','靖康元年自南都移黄州八月十六日華藏民老渡江見訪於定山下院一夕别去以詩送之','韓駒','宋','宋诗','song-poetry','','[]','大師遊華藏，法席雄諸方。',96,'全唐诗/poet.song.83000.json','["大師遊華藏，法席雄諸方。", "而我因夙緣，數入憂患場。", "道眼宜見絕，交情未相忘。", "呼舟渡宣化，訪我山之陽。", "夜榻蒲蒻穩，秋山蕙蘭香。", "問我當何之，笑指郡守章。", "莫言千里殊，共此圓寂光。", "脫有雲水客，附書及滄浪。"]'),
('ac98de5e-a983-4a89-8e6b-53b20bfd06e0','去冬除守歷陽未上召還西掖今夏自應天尹移知齊安道由歷陽珪老相訪奉柬一首','韓駒','宋','宋诗','song-poetry','','[]','嘗聞歷陽郡，寺有褒禪山。',168,'全唐诗/poet.song.83000.json','["嘗聞歷陽郡，寺有褒禪山。", "及我分竹符，欲往窮躋攀。", "驅車發半道，尺一喚我還。", "歎息巗下水，何時照衰顔。", "復持齊安節，稅駕臨通闤。", "屬有行役累，無由叩僧關。", "珪公岷峨秀，逸韻超人寰。", "攜詩遠過我，殷勤請加刪。", "少年意氣盛，笑我毛髪斑。", "夜語不知寢，起看江月彎。", "浮生浪擾擾，萬法本自閑。", "爲吏何足論，逝將老榛菅。", "買田未及議，我實貧非慳。", "奉乞一菴地，往來泉石間。"]'),
('5606c448-9fab-4448-9296-633bc3f1b17d','二十九日戎服按軍城外向儀曹亦至戲贈一首','韓駒','宋','宋诗','song-poetry','','[]','旌旗雜沓鐃鼓鳴，使君小隊來郊坰。',64,'全唐诗/poet.song.83000.json','["旌旗雜沓鐃鼓鳴，使君小隊來郊坰。", "舊時視草判花手，今學操劍驅民丁。", "逆胡未滅壮士耻，子雖年少有典型。", "短衣匹馬肯從我，與子北涉單于庭。"]'),
('a073d33c-09fc-43a1-96b0-e6701a531281','陶氏一經堂詩','韓駒','宋','宋诗','song-poetry','','[]','古來儒術士，豈爲勝籝金。',48,'全唐诗/poet.song.83000.json','["古來儒術士，豈爲勝籝金。", "更求紫與青，陋哉徒苦心。", "有兒如少翁，但可汙儒林。", "我歌勸學詩，以爲鄒魯鍼。"]'),
('04084a59-530b-47f5-90d2-c43efa489397','遜子生日','韓駒','宋','宋诗','song-poetry','','[]','閑居識時令，愛此重九名。',72,'全唐诗/poet.song.83000.json','["閑居識時令，愛此重九名。", "况我長頭兒，正用兹辰生。", "汝性既已剛，汝氣又已清。", "應須萬卷讀，勉力爲家榮。", "俗物非汝喜，壺罇鑄新成。", "壽汝白玉腴，可服黄金英。"]'),
('0c9f3188-bb6e-4ef1-8344-bd174349f290','次韻趙德夫龍圖送李諌議','韓駒','宋','宋诗','song-poetry','','[]','嘗聞中興日，補衮用老儒。',168,'全唐诗/poet.song.83000.json','["嘗聞中興日，補衮用老儒。", "亂離歲月駛，如隙過白駒。", "慷慨請擊賊，艱難論遷都。", "百謀未一試，去國秋云初。", "歸來視青鏡，老色上鬢鬚。", "新亭對茂弘，建鄴懷伯符。", "古來興廢地，俯仰再嗚呼。", "使君亦偉人，獨我慚非夫。", "邂逅得參語，僧坊飯伊蒲。", "誰云異鄉縣，契合連簪裾。", "我有一葉舟，可釣宣溪魚。", "如君醫國手，寧當墮江湖。", "燕雀尚紛拏，志士極欷歔。", "時哉更搏擊，饑鷹思草枯。"]'),
('deeae591-99ca-4ff4-b01f-3e8188b99f40','題大姑山','韓駒','宋','宋诗','song-poetry','','[]','小姑已嫁彭郎去，大姑長隨女兒住。',64,'全唐诗/poet.song.83000.json','["小姑已嫁彭郎去，大姑長隨女兒住。", "寂寞荒山春復秋，但見空濛結愁霧。", "行商再拜祈神休，插花買粉姑應羞。", "不如一酹杯中物，與爾閑消萬古愁。"]'),
('a2f4994b-fb8d-4215-b369-e529c11617a0','送僧歸蜀','韓駒','宋','宋诗','song-poetry','','[]','巴江之中有尺鯉，揚波鼓浪三千里。',32,'全唐诗/poet.song.83000.json','["巴江之中有尺鯉，揚波鼓浪三千里。", "早知辛苦上龍門，不如歸戲巴江水。"]'),
('24151005-bba4-4ff8-8c8d-40077789c3d3','武寧道中','韓駒','宋','宋诗','song-poetry','','[]','小灘嘈嘈大灘惡，朝行羊膓暮鹿角。',64,'全唐诗/poet.song.83000.json','["小灘嘈嘈大灘惡，朝行羊膓暮鹿角。", "盡日拖舟不得前，忽然笪斷千尋落。", "上梁左側石子多，兩舷與石鳴相摩。", "卧聽溪師倚篙哭，將如四十二灘何。"]'),
('95720a80-fd8a-4bbb-872d-07bee2bde071','送深老住芭蕉寺','韓駒','宋','宋诗','song-poetry','','[]','中歲厭凡子，結交惟道人。',96,'全唐诗/poet.song.83000.json','["中歲厭凡子，結交惟道人。", "况此喪亂中，益信空門真。", "老深龍岫來，意恐非常鱗。", "與語果英特，掣電翻機輪。", "巖頭路久絕，賴爾拈提新。", "莫言兹山小，是間無一塵。", "生逢世道難，無地置此身。", "何當架茆竹，永託芭蕉鄰。"]'),
('a2677df5-b82c-44d4-bbe4-d8f3ef660ddc','再用前韻簡圓通止老妙慧光老一首','韓駒','宋','宋诗','song-poetry','','[]','蜀光在京國，說法驚天人。',96,'全唐诗/poet.song.83000.json','["蜀光在京國，說法驚天人。", "曾屈多口鍳，得非點胸真。", "深林鎩遠翮，巨壑藏修鱗。", "蕭然幽遽菴，伎倆付老輪。", "諸君五字偈，亦各呈尖新。", "世界夢幻爾，豈特爲微塵。", "更營露電軀，庇此泡影身。", "尚喜圓通師，教我吞儀鄰。"]'),
('3e4c476b-478f-402d-96f1-0ce1957f6a72','次韻高大中侍郎罷郡書懷','韓駒','宋','宋诗','song-poetry','','[]','公詩如秋聲，蕭蕭薄炎熾。',156,'全唐诗/poet.song.83000.json','["公詩如秋聲，蕭蕭薄炎熾。", "我窮卧荒山，無復文墨事。", "兹焉和高唱，出語愧蕪累。", "五馬一花驄，得非天廐駟。", "會當親戎行，一快平生志。", "雖云鬻千金，此計恐非遂。", "人生行樂耳，屢空何用愧。", "况今紛紜時，一笑豈云易。", "求船真戲言，換妾乃深意。", "梅堂極虚明，壺漿有新餽。", "何時具杯杓，洗我色憔悴。", "李侯飲中仙，亦有塵外思。", "藜杖方叩門，君歸與徐議。"]'),
('87bf1d14-538d-43c2-9d44-ca0bbd49ca6d','次韻曾通判登擬峴臺','韓駒','宋','宋诗','song-poetry','','[]','朝攜筇杖來，瞑倚胡牀坐。',168,'全唐诗/poet.song.83000.json','["朝攜筇杖來，瞑倚胡牀坐。", "循墻讀遺碑，歲久苔蘚涴。", "烈風無時休，于兹騐真箇。", "曾郎吐佳句，勢突黄初過。", "交游得詩流，吾儕可相賀。", "念昔逢大梁，一别九鑽火。", "再見疑前身，居然客愁破。", "世久無若人，子豈伯休那。", "千山厭露宿，一壑期雲卧。", "子少方鵬騫，吾衰作鳶墮。", "篇成不敢出，畏子詩眼大。", "惟當事深禪，諸方參作麽。", "文章真綺語，季緒徒瑣瑣。", "安得京口歸，秋江細扶柁。"]'),
('49c45c00-5950-472f-b45a-e9fa4487750e','戲作冷語三首  其一','韓駒','宋','宋诗','song-poetry','','[]','北風刮地寒陰凝，鐵馬夜蹋黄河冰。',48,'全唐诗/poet.song.83000.json','["北風刮地寒陰凝，鐵馬夜蹋黄河冰。", "凍鳶瑟縮烏凌兢，破廬卧雪僵不興。", "嚴霜透屋衣生稜，未若冷語銷炎蒸。"]'),
('51c9eb6a-db28-454c-8216-0a1dbef38e54','戲作冷語三首  其二','韓駒','宋','宋诗','song-poetry','','[]','五更和霜蹋積雪，冰堅滑道行人絕。',48,'全唐诗/poet.song.83000.json','["五更和霜蹋積雪，冰堅滑道行人絕。", "邊城十月地凍裂，兩崖雨冰萬木折。", "琉璃爲家白銀闕，未若冷語祛炎熱。"]'),
('d24030e0-b4a9-4f06-ac50-523cf2e6c1f4','戲作冷語三首  其三','韓駒','宋','宋诗','song-poetry','','[]','石崖蔽天雪塞空，萬仞陰壑號悲風。',48,'全唐诗/poet.song.83000.json','["石崖蔽天雪塞空，萬仞陰壑號悲風。", "纖絺不御當玄冬，霜寒墮落冰溪中。", "斵冰直侵河伯宮，未若冷語清心胸。"]'),
('941a5cef-b5ff-4c35-8c9f-7c4c08932d81','送鄂州劉使君','韓駒','宋','宋诗','song-poetry','','[]','昔在史館中，地禁無經過。',120,'全唐诗/poet.song.83000.json','["昔在史館中，地禁無經過。", "唯君直廬近，退食同委蛇。", "至今夢催班，九門鬰嵳峨。", "傷心望金馬，極目悲銅駞。", "脫身來此郡，見公擁琱戈。", "猛士三千人，旌旜相蕩摩。", "男兒晚有此，世儒安足多。", "少來謬秉筆，報國終無他。", "聞當向夏口，秋風水增波。", "願子静荆峽，送我歸江沱。"]'),
('d2e1f21b-5668-48ec-b230-88ca0b4ed2e9','題蕃騎圖','韓駒','宋','宋诗','song-poetry','','[]','塞上漠漠黄雲秋，黄鬚胡兒騎紫騮。',64,'全唐诗/poet.song.83000.json','["塞上漠漠黄雲秋，黄鬚胡兒騎紫騮。", "一馬攙前弄風走，胡兒掣轡空驤首。", "迴鞭慎莫向南馳，漢家將軍方打圍。", "奪弓射汝猶可脫，奪汝善馬何由歸。"]'),
('a36f940a-7b35-48e5-aeb1-e8ed5f735aae','題韓晃沈本作滉畫瀛洲學士圖','韓駒','宋','宋诗','song-poetry','','[]','咸陽中天開帝居，羣公下直承明廬。',96,'全唐诗/poet.song.83000.json','["咸陽中天開帝居，羣公下直承明廬。", "長鞦短轡裦衣裾，蒼頭廬兒爭走趨。", "韓侯畫此時無虞，瀛洲仙人樂有餘。", "我生不及貞觀初，忽思十年身校書。", "吟詩天街騎蹇驢，爾來戎馬方馳驅。", "眼厭繡䘿蒙諸于，把卷未展先欷歔。"]'),
('6d784923-b8ba-4e35-be4b-bfa1faa82a4e','送韓將仕自撫之衢','韓駒','宋','宋诗','song-poetry','','[]','故人有令子，高義摩雲天。',72,'全唐诗/poet.song.83000.json','["故人有令子，高義摩雲天。", "邂逅亦未久，航湖背臨川。", "謂我老世故，數數求言詮。", "豈知愚闇姿，一生憂患纒。", "讀書千萬言，不若摩兠鞬。", "願子善自愛，無忘說車篇。"]'),
('b726e7c3-adb1-4078-bd41-6bf149cc8156','次韻呂居仁贈一上座兼簡居仁昆仲','韓駒','宋','宋诗','song-poetry','','[]','上人出山時，稻穫雲水白。',168,'全唐诗/poet.song.83000.json','["上人出山時，稻穫雲水白。", "囷倉未云滿，已有稅租迫。", "崎嶇走檀施，不畏道里隔。", "坐令衆浮圖，聽法無餒色。", "爾來閉幽戶，此道深自索。", "佛法本無多，未悟常自責。", "孤雲忽南飛，過我江上宅。", "信知道人心，不斷思想百。", "邂逅逢故人，涕淚說艱厄。", "驅車更何之，悵望王土窄。", "應須屏塵累，問此忘機客。", "憂來莫飲酒，酒薄空住鬲。", "何時營一丘，伐竹開新陌。", "待子田舍成，吾當理輕策。"]'),
('5bea7290-7914-4c21-a474-6da03974ed6c','順老寄菜花乾戲作長句','韓駒','宋','宋诗','song-poetry','','[]','道人禪餘自鉏菜，小摘黄花日中曬。',64,'全唐诗/poet.song.83000.json','["道人禪餘自鉏菜，小摘黄花日中曬。", "峨嵋㮕脯久不來，麴糝薑絲典型在。", "封題寄我紙作囊，中有巴蜀齋廚香。", "起炊曉甑八月白，配此春盤一掬黄。"]'),
('206660e1-3f0c-40ed-9df6-3330da2ca1b2','戲留圓首座元上人','韓駒','宋','宋诗','song-poetry','','[]','老夫晏坐菩提坊，二士接迹來升堂。',80,'全唐诗/poet.song.83000.json','["老夫晏坐菩提坊，二士接迹來升堂。", "疏眉哆口辯舌張，問胡至此皆同鄉。", "少年發足參諸方，爾來馬解高掛墻。", "資雖東川近陵陽，左綿稍遠亦相望。", "不辭煼飯豉作湯，肯更十日留山房。"]'),
('7d58e1bb-f87e-40b8-bcab-368739216f77','李氏娛書齋','韓駒','宋','宋诗','song-poetry','','[]','欲樂誑凡夫，須臾皆變壞。',120,'全唐诗/poet.song.83000.json','["欲樂誑凡夫，須臾皆變壞。", "惟書有真樂，意味久猶在。", "李君名家流，事業窺前輩。", "澹然無他娛，開卷與心會。", "憶吾童稚時，書亦甚所愛。", "傳抄春復秋，諷誦晝連晦。", "飲食忘辛鹹，汙垢失盥頮。", "爾來歡喜處，乃在文字外。", "卷藏二萬籖，棐几静相對。", "此樂君未知，狂言勿吾怪。"]'),
('7179e90d-68d4-4029-bc4c-3bf61ae414f3','送王秘閣二首  其一','韓駒','宋','宋诗','song-poetry','','[]','烏衣諸王吾早聞，晚塗獨識和州孫。',64,'全唐诗/poet.song.83000.json','["烏衣諸王吾早聞，晚塗獨識和州孫。", "風流沓拖欲垂盡，文采陸離今尚存。", "奉祠乃是衰翁事，如君胡爲亦爲此。", "僕夫在門君疾驅，往獻天子平邊書。"]'),
('20b82ac3-32bb-496d-8999-4fbb84350b78','送王秘閣二首  其二','韓駒','宋','宋诗','song-poetry','','[]','右軍池頭鶬鴰呼，康樂臺下杉檉疏。',64,'全唐诗/poet.song.83000.json','["右軍池頭鶬鴰呼，康樂臺下杉檉疏。", "碧山學士此築室，白髪散人來卜居。", "身隨沙鷗卧烟雨，十年無書上公府。", "枉作西班老從臣，看君才華不能舉。"]'),
('065b3e20-ad89-4eec-9132-58b2d79438d5','送里人陳會往見江西漕使','韓駒','宋','宋诗','song-poetry','','[]','勸君少留持一觴，與君鄉里皆陵陽。',96,'全唐诗/poet.song.83000.json','["勸君少留持一觴，與君鄉里皆陵陽。", "兒童共戲苦鹽岸，老大相逢烏石岡。", "拾遺平生丈人行，拊我謂我能文章。", "豈知今無一絲長，但餘顛華面顔蒼。", "君行往見玉節郎，感時憂國歌慨慷。", "餉師十萬西平羌，笑我挾筴山中藏。"]'),
('6c3909c0-750d-4495-8d4b-96b46e26f4f7','夜與疏山清公對語因設果供戲成長句','韓駒','宋','宋诗','song-poetry','','[]','落葉屑窣鳴風廊，四無人聲夜未央。',192,'全唐诗/poet.song.83000.json','["落葉屑窣鳴風廊，四無人聲夜未央。", "道人過我談真常，客舍有底相迎將。", "竹爐篝火曲木牀，烏桕爲燭楓脂香。", "青棃纍纍飣坐光，黄甘十子近著霜。", "醯梅蜜杏經年藏，紅糝綴枝加柘漿。", "蓴藕藷芋蘘荷薑，堆盤滿桉次第嘗。", "憶初見翁修水旁，轉頭八十鬚眉蒼。", "爾時尊宿略喪亡，屹如樅檜老不僵。", "而我昔漫參朝行，十年投閑坐老狂。", "人生一夣炊黄粱，諸法本閑人自忙。", "况今世故甚擾攘，與翁幸憩菩提坊。", "夜闌一酌餘甘湯，他年此樂不可忘。"]'),
('75504ea6-028a-44cf-a405-ffded957358e','昔與道顔智俱二僧居武寧明心寺未幾與俱避賊山中顔幾不免紹興三年復會於廣壽寺偶作一首','韓駒','宋','宋诗','song-poetry','','[]','昔與二子居明心，避賊夜走南山陰。',128,'全唐诗/poet.song.83000.json','["昔與二子居明心，避賊夜走南山陰。", "天寒更蹋沮洳徑，月黑錯墮楊梅林。", "歷險登危四三里，少復前行過溪水。", "平明乞火野人家，十日身藏巖窟裏。", "閩俱歎我装齎空，蜀顔轉陷妖氛中。", "誰言性命脫鍼孔，沉憂傷人衰疾同。", "春風酣酣柳邊寺，相對夢中論夢事。", "莫嫌薄飯一莖虀，郡國而今無鼓鼙。"]'),
('deeb9ff2-7588-4d00-ae04-1a3a2666a6f6','送賢上人歸雲門菴','韓駒','宋','宋诗','song-poetry','','[]','雲門秀色連雲居，石林參天冬不枯。',128,'全唐诗/poet.song.83000.json','["雲門秀色連雲居，石林參天冬不枯。", "溪迴彷彿菜葉下，路轉崔嵬茆屋孤。", "上人一口盡諸佛，肯顧世上羣兒愚。", "獨尋龐老不憚遠，此事古有今人無。", "我窮活計依精廬，千年香火勤朝晡。", "遠來無物可祗待，苦筍淡粥同齋盂。", "翻然别我出門去，春雨趁耕薑芋區。", "不須領衆強自苦，一庵高卧真良圖。"]'),
('dee95f95-e42f-4101-9c24-1f2d4cec47cf','送秀老住南嶽上封寺','韓駒','宋','宋诗','song-poetry','','["\u8861\u5c71"]','人生孰不營，世事復見羈。',72,'全唐诗/poet.song.83000.json','["人生孰不營，世事復見羈。", "獨有山居佳，古語不我欺。", "君今視霄漢，已與諸佛期。", "而我在泥滓，未免高人嗤。", "勸君安此山，老大將何之。", "底處不相見，勿言長别離。"]'),
('d3efd126-e863-41f3-9c2d-b4cc6e1e54bc','久雨溪漲壽朋惠示長句次韻一首','韓駒','宋','宋诗','song-poetry','','[]','緣雲細路投僧坊，路邊松柟森自行。',208,'全唐诗/poet.song.83000.json','["緣雲細路投僧坊，路邊松柟森自行。", "初來紫竹半含籜，白花忽已吹垂楊。", "念昔聯翩背京洛，於時初登君子堂。", "還朝我執太史筆，侍宴君持光祿觴。", "由來用舍判殊路，玉堂絳闕遙相望。", "公車推輪下庾嶺，我舟捩柁辭黄岡。", "艱難晚厄汝溪上，天雨屬聞頽院墻。", "不憂漏濕有新句，醉墨在紙猶淋浪。", "桃花水漲鳥不渡，安得奮飛來我旁。", "夜來顛風起天末，起占初日照屋梁。", "明窗洗硯午陰寂，前榮觀棋春晝長。", "百年未滿且挈挈，萬緣頓息寧皇皇。", "更能伴我千鍾飲，徑欲因公倒槖装。"]'),
('d0bbbafa-47f7-4760-abe5-7fec1d84303e','送溈山顯化士往印經','韓駒','宋','宋诗','song-poetry','','[]','石路天新雨，問僧何日來。',48,'全唐诗/poet.song.83000.json','["石路天新雨，問僧何日來。", "云求法舍利，庶用鎮崔嵬。", "我有一句子，不從黄卷開。", "相逢未可舉，佇子卞山回。"]'),
('d94f27fc-a1a4-47f0-894b-b7a1ec85e6e1','謝彰上人遠自雲門見訪','韓駒','宋','宋诗','song-poetry','','[]','君參雲門禪，不遠爲君說。',48,'全唐诗/poet.song.83000.json','["君參雲門禪，不遠爲君說。", "千里訪衰翁，草鞋三寸雪。", "此間禪亦無，一味有衰拙。", "乞君煮菜方，歸與雲門啜。"]'),
('f2ae6bda-3aaa-4346-946e-2fe7a47e1f4e','上泰州使君陳瑩中','韓駒','宋','宋诗','song-poetry','','[]','當年賢路雜薫蕕，歎息諸公善自謀。',64,'全唐诗/poet.song.83000.json','["當年賢路雜薫蕕，歎息諸公善自謀。", "今日在前皆鼎鑊，後來知我獨春秋。", "海邊已擊師襄磬，湖上新逢范蠡舟。", "惟有書生最無事，不妨挾册更西游。"]'),
('77613167-d421-4c0a-a791-c7ed4bae0c33','聞富鄭公少時隨侍至此讀書景德寺後人爲作祠堂因跋余舊詩後以自嘲  其一','韓駒','宋','宋诗','song-poetry','','[]','藤牀瓦枕快清風，破悶文書亦漫供。',64,'全唐诗/poet.song.83000.json','["藤牀瓦枕快清風，破悶文書亦漫供。", "鄉信未傳霜後雁，羈懷生怯晚來鐘。", "淹留已辦三年計，流落應無萬戶封。", "猶有壁間詩句在，他時誰肯寫塵容。"]'),
('f71f1188-8701-4304-aefc-b22f89b679c4','聞富鄭公少時隨侍至此讀書景德寺後人爲作祠堂因跋余舊詩後以自嘲  其二','韓駒','宋','宋诗','song-poetry','','[]','海氣昏昏又嘯風，一杯扶病要時供。',64,'全唐诗/poet.song.83000.json','["海氣昏昏又嘯風，一杯扶病要時供。", "三年閉戶兒童怪，千古閑情我輩鍾。", "若得黄甘應手種，更求青李莫函封。", "疏頑自笑將安適，寄謝江山好見容。"]'),
('f922f5b6-f08a-4482-9020-287b4ffd9c9b','食蟹','韓駒','宋','宋诗','song-poetry','','[]','海上奇烹不計錢，枉教陋質上金槃。',64,'全唐诗/poet.song.83000.json','["海上奇烹不計錢，枉教陋質上金槃。", "饞涎不避吳儂笑，香稻兼償楚客餐。", "寄遠定須宜酒債，嘗新猶喜及霜寒。", "先生便腹唯思睡，不用殷勤破小團。"]'),
('c6eedc94-f376-4b8b-ab77-1b53daf4aa2e','次韻師白中秋會飲且餞予行','韓駒','宋','宋诗','song-poetry','','[]','樓高應在月明邊，目斷西山萬里天。',64,'全唐诗/poet.song.83000.json','["樓高應在月明邊，目斷西山萬里天。", "擬喚謫仙歸貝闕，翻愁快馬蹋瓊田。", "詞鋒易破孤虛陣，酒令難欺賞罰權。", "放盞成空君莫歎，明年千里共嬋娟。"]'),
('62e92daa-93b1-4b50-8577-f39510ed97a2','次韻留别南公','韓駒','宋','宋诗','song-poetry','','[]','天遣吾曹與世疏，那將窮技學黔驢。',64,'全唐诗/poet.song.83000.json','["天遣吾曹與世疏，那將窮技學黔驢。", "只今年少身多病，是處愁深淚濺裾。", "此去不須論塞馬，向來猶有葬江魚。", "虚名只用驚兒輩，要作生涯墓誌書。"]'),
('c2fe8a1c-50a7-4782-ace8-4996e2848ff4','至襄城家君有詩命某屬和','韓駒','宋','宋诗','song-poetry','','[]','日月驅車及莽蒼，今朝一眼楚山長。',64,'全唐诗/poet.song.83000.json','["日月驅車及莽蒼，今朝一眼楚山長。", "共看社燕將鶵急，誰見秋鴻刷羽光。", "晚渡河流皆倒影，夜題馹壁作斜行。", "道邊草木應相笑，解笑年來爲底忙。"]'),
('547d9419-90ac-4f44-b3a0-2b78c3b07dbf','次韻雙蓮花云得之城東','韓駒','宋','宋诗','song-poetry','','[]','對鏡佳人艷質同，微風更許暗香通。',64,'全唐诗/poet.song.83000.json','["對鏡佳人艷質同，微風更許暗香通。", "凌波鬬作拖裠綠，行雨翻愁裛臉紅。", "欲寫新圖過淮右，從今勝地自城東。", "有情邢尹空爭寵，豈悟榮枯一瞬中。"]'),
('c04b5fd5-24d3-421a-ba4c-fb71fa105c25','和者既多花已成實矣復作一首','韓駒','宋','宋诗','song-poetry','','[]','人間異物費元功，水與銀河一綫通。',64,'全唐诗/poet.song.83000.json','["人間異物費元功，水與銀河一綫通。", "誰擲兩杯浮淺綠，忽逢丫髻插殘紅。", "澷誇造物偏江北，疑有遺民聚海東。", "天子不收祥瑞奏，坐憂芳質朽泥中。"]'),
('356203b7-1d4b-4792-bf8b-a98093ba4c55','次韻陳師白','韓駒','宋','宋诗','song-poetry','','[]','居士年來浄目塵，空花豈復問陳新。',64,'全唐诗/poet.song.83000.json','["居士年來浄目塵，空花豈復問陳新。", "北游豈識無爲子，東第常叨不速賓。", "憶昔扁舟輕白帝，何年一室老青神。", "飄然又指淮山去，儻更山中得異人。"]'),
('67de9138-b210-4aaa-b1d5-12e36c0e2bb9','次韻薛孟二君唱和','韓駒','宋','宋诗','song-poetry','','[]','河東有句不空傳，但寄襄陽孟浩然。',64,'全唐诗/poet.song.83000.json','["河東有句不空傳，但寄襄陽孟浩然。", "多慮皆能成白髪，一塵莫遣到丹田。", "此身彭澤杯中老，浮世邯鄲枕上眠。", "常恨今時無大雅，看君發憤補亡篇。"]'),
('3bc94260-1006-44c2-9d99-f275b2310295','十絕爲亞卿作  其一','韓駒','宋','宋诗','song-poetry','','[]','離歌三疊最關情，不省從來此地聞。',32,'全唐诗/poet.song.83000.json','["離歌三疊最關情，不省從來此地聞。", "早是春殘心事惡，落花陰裏更辭君。"]'),
('f2f7cceb-c6e2-411f-a2e7-90383b22a995','十絕爲亞卿作  其二','韓駒','宋','宋诗','song-poetry','','[]','君去東山踏亂雲，後車何不載紅裙。',32,'全唐诗/poet.song.83000.json','["君去東山踏亂雲，後車何不載紅裙。", "羅衣浥盡傷春淚，只有無言持送君。"]'),
('e2d36f11-b223-4e99-945f-74d8b0653800','十絕爲亞卿作  其三','韓駒','宋','宋诗','song-poetry','','[]','更欲罇前抵死留，爲君徐唱木蘭舟。',32,'全唐诗/poet.song.83000.json','["更欲罇前抵死留，爲君徐唱木蘭舟。", "臨行翻恨君恩雜，十二金釵淚總流。"]'),
('26920c52-ae73-4af2-bb3d-185ad64c12a7','十絕爲亞卿作  其四','韓駒','宋','宋诗','song-poetry','','[]','世上無情似有情，俱將苦淚點離罇。',32,'全唐诗/poet.song.83000.json','["世上無情似有情，俱將苦淚點離罇。", "人心真處君須會，認取儂家暗斷魂。"]'),
('ff7b2baa-f779-46d2-ace8-17f9405480a0','十絕爲亞卿作  其五','韓駒','宋','宋诗','song-poetry','','[]','君住江濱起畫樓，妾居海角送潮頭。',32,'全唐诗/poet.song.83000.json','["君住江濱起畫樓，妾居海角送潮頭。", "潮中有妾相思淚，流到樓前更不流。"]'),
('49199c7f-611a-43a3-b682-3b1d83e900f7','十絕爲亞卿作  其六','韓駒','宋','宋诗','song-poetry','','[]','憶汎郎舟共採蓮，今來揮淚送郎船。',32,'全唐诗/poet.song.83000.json','["憶汎郎舟共採蓮，今來揮淚送郎船。", "回書儻寄新翻曲，湖上何人爲扣舷。"]'),
('38f2dd1f-40db-4e05-bf41-81790de65da6','十絕爲亞卿作  其七','韓駒','宋','宋诗','song-poetry','','[]','一夢巫陽樂已窮，三年猶復怨匆匆。',32,'全唐诗/poet.song.83000.json','["一夢巫陽樂已窮，三年猶復怨匆匆。", "倐雲驟雨成何事，未必三年抵夢中。"]'),
('a96f65d7-401a-410a-9767-c45fbba723c4','十絕爲亞卿作  其八','韓駒','宋','宋诗','song-poetry','','[]','妾願爲雲逐畫檣，君言十日看歸航。',32,'全唐诗/poet.song.83000.json','["妾願爲雲逐畫檣，君言十日看歸航。", "恐君回首高城隔，直倚江樓過夕陽。"]'),
('15da2c0f-5d3b-40da-abf5-d4398c39897e','十絕爲亞卿作  其九','韓駒','宋','宋诗','song-poetry','','[]','初合雙鬟觸事羞，離筵酌酒強回頭。',32,'全唐诗/poet.song.83000.json','["初合雙鬟觸事羞，離筵酌酒強回頭。", "縱言眼軟偏饒淚，莫道心癡不解愁。"]'),
('d7ae1c12-a89d-40a4-8d6e-388528465382','十絕爲亞卿作  其一○','韓駒','宋','宋诗','song-poetry','','[]','強整雙鬟說後期，相盟不在已相知。',32,'全唐诗/poet.song.83000.json','["強整雙鬟說後期，相盟不在已相知。", "來時休落春風後，却漫嘲儂子滿枝。"]'),
('257c7a06-16f1-49d4-aeb4-d032230f87b2','送俞仲寛赴宿倅','韓駒','宋','宋诗','song-poetry','','[]','年少場中晚節寒，去年揮手下天關。',64,'全唐诗/poet.song.83000.json','["年少場中晚節寒，去年揮手下天關。", "何人肯蹋風波路，自古難言骨肉間。", "十里即應歸漢闕，一帆從此别淮山。", "艤舟如得僧伽印，未用將身付等閑。"]'),
('2f1aa6be-aefc-40be-b211-756d00a2452c','便衣訪徐師川坐定陳瑩中太守亦至余避入室已而同語良久戲呈師川','韓駒','宋','宋诗','song-poetry','','[]','兩都賓主盡雄名，我獨何人共宴榮。',64,'全唐诗/poet.song.83000.json','["兩都賓主盡雄名，我獨何人共宴榮。", "微服豈宜從刺史，瓦巾端爲訪先生。", "山陰甚愧羣賢集，蜀客初無一坐傾。", "庾亮興來殊不淺，臨風數語逼人清。"]'),
('5dcc0fe9-b567-41a0-913e-085f7b55e586','次韻師川見和','韓駒','宋','宋诗','song-poetry','','[]','使君直氣舊凌空，帳下森森已八龍。',64,'全唐诗/poet.song.83000.json','["使君直氣舊凌空，帳下森森已八龍。", "倒屣休迎王節信，同舟未許郭林宗。", "我無草舍容朱轂，君有詩聲抵素封。", "危坐正衿殊不慣，歸從短褐醉千鍾。"]'),
('b0bfb4d3-9335-42a4-b512-71bdeb6bddfb','五月八日游北禪師川登塔盡七級僕能三級而已晚過公晦偶作二首  其一','韓駒','宋','宋诗','song-poetry','','[]','徐郎胸次已冰清，北寺清游更絕塵。',64,'全唐诗/poet.song.83000.json','["徐郎胸次已冰清，北寺清游更絕塵。", "不欲茹葷緣道友，肯來出郭是詩人。", "憐君遠客情能爾，看我題名墨尚新。", "誰有好方扶脚力，故鄉歸去蹋峨岷。"]'),
('b03f4f60-5237-4364-80b6-a1f093b091a4','五月八日游北禪師川登塔盡七級僕能三級而已晚過公晦偶作二首  其二','韓駒','宋','宋诗','song-poetry','','[]','鐵鏁銅鐶一一開，肩輿不問主人來。',64,'全唐诗/poet.song.83000.json','["鐵鏁銅鐶一一開，肩輿不問主人來。", "已登白塔吾休矣，更上紅亭子壮哉。", "世外清歡須邂逅，城頭落日共徘徊。", "雲樓五月滄洲趣，羞殺初無八斗才。"]'),
('6c0342f4-9e8e-40c1-870b-da29f638c99f','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一','韓駒','宋','宋诗','song-poetry','','[]','去蜀初游楚，吾方十二三。',24,'全唐诗/poet.song.83000.json','["去蜀初游楚，吾方十二三。", "無成今長大，送汝不勝慚。"]'),
('00bc70ed-caa6-442e-861f-4efb36e2410d','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其二','韓駒','宋','宋诗','song-poetry','','[]','還家儻無事，莫負故園春。',24,'全唐诗/poet.song.83000.json','["還家儻無事，莫負故園春。", "衣錦兒嬉爾，從來笑買臣。"]'),
('32c98335-1b28-429d-81ae-b21bd0f8dbf5','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其三','韓駒','宋','宋诗','song-poetry','','[]','艤舟不能前，已復日西没。',24,'全唐诗/poet.song.83000.json','["艤舟不能前，已復日西没。", "贈子以幽蘭，秋風正披拂。"]'),
('cf63ef23-9a17-405b-a3c1-ad9bc421bcb6','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其四','韓駒','宋','宋诗','song-poetry','','[]','野宿月團欒，風餐氣蕭颯。',24,'全唐诗/poet.song.83000.json','["野宿月團欒，風餐氣蕭颯。", "從來對牀地，只今懸一榻。"]'),
('aff129a1-f6a7-44df-bebe-2c9bcd806fb3','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其五','韓駒','宋','宋诗','song-poetry','','[]','入蜀尋幽迹，應先到浣花。',24,'全唐诗/poet.song.83000.json','["入蜀尋幽迹，應先到浣花。", "誠知錦城樂，亦記早還家。"]'),
('e2156249-c400-4d7e-b265-640897626807','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其六','韓駒','宋','宋诗','song-poetry','','[]','魚游因餌得，鳥困坐黐黏。',24,'全唐诗/poet.song.83000.json','["魚游因餌得，鳥困坐黐黏。", "顧我今如此，空懷石井鹽。"]'),
('39242939-11a7-4ce2-9ffc-a33c7d06f546','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其七','韓駒','宋','宋诗','song-poetry','','[]','逢年要力耕，善舞須長袖。',24,'全唐诗/poet.song.83000.json','["逢年要力耕，善舞須長袖。", "北山休移文，南山歸種豆。"]'),
('79d8dc48-a1e5-4a1d-8759-81a7e598dfe9','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其八','韓駒','宋','宋诗','song-poetry','','[]','一棹送君歸，酒醒秋江午。',24,'全唐诗/poet.song.83000.json','["一棹送君歸，酒醒秋江午。", "正是蓴鱸時，思君在何許。"]'),
('209428bb-1e69-4c48-9837-6a512a9021fb','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其九','韓駒','宋','宋诗','song-poetry','','[]','明月落帆時，荒山孤夜夜。',24,'全唐诗/poet.song.83000.json','["明月落帆時，荒山孤夜夜。", "回首白雲飛，吾親在其下。"]'),
('e75f4075-7d4c-4166-bf62-c6bdb6f50e0d','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一○','韓駒','宋','宋诗','song-poetry','','[]','客行宜努力，時亦近醇醪。',24,'全唐诗/poet.song.83000.json','["客行宜努力，時亦近醇醪。", "一盞熏人醉，雲安米正淘。"]'),
('1ed5e591-2e01-4bc1-8ff2-8286268d2e7f','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一一','韓駒','宋','宋诗','song-poetry','','[]','爾去逢諸父，髯霜貎渥丹。',24,'全唐诗/poet.song.83000.json','["爾去逢諸父，髯霜貎渥丹。", "貧窮宜此報，冨貴却難安。"]'),
('f5492ecf-c1ba-430c-ad0b-e798ca230ca1','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一二','韓駒','宋','宋诗','song-poetry','','[]','揚州十里春，峨嵋半輪月。',24,'全唐诗/poet.song.83000.json','["揚州十里春，峨嵋半輪月。", "兹游真不凡，詩成想清絕。"]'),
('badd4a4e-8054-4daf-9207-154b88a2453e','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一三','韓駒','宋','宋诗','song-poetry','','[]','吾祖屯田公，遺書悉安在。',24,'全唐诗/poet.song.83000.json','["吾祖屯田公，遺書悉安在。", "爲我謝諸兄，蠧魚時一曬。"]'),
('5821bb7b-eb51-493e-b0e2-e0c020952831','曾大父有詩云三春拂榻花黏袖午夜淘丹月在池舍弟子飛歸蜀與語及此因取爲韻  其一四','韓駒','宋','宋诗','song-poetry','','[]','故山不可到，歸夢到天池。',24,'全唐诗/poet.song.83000.json','["故山不可到，歸夢到天池。", "想見山中叟，磨崖待我詩。"]'),
('29c291b5-7197-42e3-9ff6-16fe113e846d','次韻參寥  其一','韓駒','宋','宋诗','song-poetry','','[]','此身不擬墮塵緣，長恐驚鴻落響弦。',64,'全唐诗/poet.song.83000.json','["此身不擬墮塵緣，長恐驚鴻落響弦。", "蹋盡世間千澗壑，歸來胸次一山川。", "深宮木末猶秋色，故國天涯只暮烟。", "憑仗道人分石甃，要看庭下玉龍旋。"]'),
('7f93a788-7fcc-4d49-8bbf-7ff760a50823','次韻參寥  其二','韓駒','宋','宋诗','song-poetry','','[]','且向家山一笑懽，從來烈士直如弦。',64,'全唐诗/poet.song.83000.json','["且向家山一笑懽，從來烈士直如弦。", "君今振錫歸千頃，我亦收身入兩川。", "短世驚人如掣電，浮雲過眼亦飛烟。", "何當與子超塵域，下視紛紛蟻磨旋。"]'),
('8ab88949-5a33-4a39-8133-6abe26968086','游定林寺','韓駒','宋','宋诗','song-poetry','','[]','定林何有惟脩竹，急喚清樽趁午陰。',64,'全唐诗/poet.song.83000.json','["定林何有惟脩竹，急喚清樽趁午陰。", "曲檻以南青嶂合，高堂其上白雲深。", "人猶未識官曹意，風自能披我輩襟。", "是夜琴彈醉翁操，笑呼明月作知音。"]'),
('8ceb8afa-48d7-4b8f-90d7-6fd02b2878a6','題鶺鴒圖','韓駒','宋','宋诗','song-poetry','','[]','有弟留南楚，經年不寄書。',24,'全唐诗/poet.song.83000.json','["有弟留南楚，經年不寄書。", "天涯數行淚，獨對鶺鴒圖。"]'),
('82720479-2a4e-4ddf-9dda-c0e4eaf9f165','題絳帳圖','韓駒','宋','宋诗','song-poetry','','[]','豈有青雲士，而居絳帳間。',24,'全唐诗/poet.song.83000.json','["豈有青雲士，而居絳帳間。", "諸生獨何事，不上會稽山。"]'),
('657d38fb-a5fd-4e0d-95ff-06da10b01733','泰興道中','韓駒','宋','宋诗','song-poetry','','[]','縣郭連青竹，人家蔽綠蘿。',48,'全唐诗/poet.song.83000.json','["縣郭連青竹，人家蔽綠蘿。", "地偏春事少，山迥夕陽多。", "暗水批崖出，輕舠掠岸過。", "傳呼細扶柁，吾老怯風波。"]'),
('c747f55a-ec30-4030-8ca1-f419f68f7ff0','偶書','韓駒','宋','宋诗','song-poetry','','[]','雪如羞明夜方密，風似擺花春更多。',32,'全唐诗/poet.song.83000.json','["雪如羞明夜方密，風似擺花春更多。", "竟日吟詩安用許，今朝止酒奈寒何。"]'),
('3165858a-62a4-41a7-9910-28e3d3f6b484','題畫雪雀  其一','韓駒','宋','宋诗','song-poetry','','[]','寂寂黄山處士居，空林急雪鳥相呼。',32,'全唐诗/poet.song.83000.json','["寂寂黄山處士居，空林急雪鳥相呼。", "不知此子何由見，歸與先生作畫圖。"]'),
('b104356b-0a9b-45bb-8e9a-0c7aa3bc5536','題畫雪雀  其二','韓駒','宋','宋诗','song-poetry','','[]','只畫山禽依雪竹，斯人用意復誰知。',32,'全唐诗/poet.song.83000.json','["只畫山禽依雪竹，斯人用意復誰知。", "肯來禁籞圖神爵，應已傳呼作畫師。"]'),
('2fdc94b6-cfc2-4d30-8dfd-8dbcb95b44fa','題王充道清芬亭亭前瑞香花數百本','韓駒','宋','宋诗','song-poetry','','[]','著葉團青蓋，開花炷寶熏。',48,'全唐诗/poet.song.83000.json','["著葉團青蓋，開花炷寶熏。", "遙知三徑馥，尚隔數家聞。", "但取芳菲襲，無勞灌溉勤。", "藉令搖落盡，子自有清芬。"]'),
('97eaef06-f14a-4e9f-b9b2-a828db86f245','智勇師歸永嘉自言所居在萬竹間乞詩送行','韓駒','宋','宋诗','song-poetry','','[]','上人歸去家何許，萬竹深圍一把茆。',64,'全唐诗/poet.song.83000.json','["上人歸去家何許，萬竹深圍一把茆。", "蹋盡叢林參白足，却來江檻俯青郊。", "夜階蔌蔌風翻籜，春路冥冥雨放梢。", "肯拚清陰分百十，暮年思與子論交。"]'),
('9fd00cd0-bf64-4fa7-a8bd-15e2d6a33e99','題修師陽關圖','韓駒','宋','宋诗','song-poetry','','[]','風烟錯漠路崎崯，倦客羈臣淚滿襟。',32,'全唐诗/poet.song.83000.json','["風烟錯漠路崎崯，倦客羈臣淚滿襟。", "何事道人常把玩，只應無復去來心。"]'),
('5055c363-c61e-4fdf-a322-893772b27f50','題趙君發牧牛圖','韓駒','宋','宋诗','song-poetry','','[]','王孫豈識田家趣，妙畫聊因好古收。',32,'全唐诗/poet.song.83000.json','["王孫豈識田家趣，妙畫聊因好古收。", "惟有野人開卷笑，憶騎牛背下西疇。"]'),
('2d3c96fc-dc92-44dd-b75f-148861d928de','李少愚母輓詩','韓駒','宋','宋诗','song-poetry','','[]','石窌恩雖渥，潘輿恨已遙。',48,'全唐诗/poet.song.83000.json','["石窌恩雖渥，潘輿恨已遙。", "南天丹旐濕，朔吹繐帷飄。", "不復迎船筍，驚聞引葬簫。", "九原封若斧，淚溢冶城潮。"]'),
('c5d715c3-b425-469f-8dc3-644df93666ac','贈張景方','韓駒','宋','宋诗','song-poetry','','[]','斯文萬古照乾坤，削簡沉碑僅免燔。',64,'全唐诗/poet.song.83000.json','["斯文萬古照乾坤，削簡沉碑僅免燔。", "在處自應神物護，從來難爲俗人言。", "仙官下取餘無幾，夾壁深藏尚半存。", "異日亡書購三篋，吾知漢相有賢孫。"]'),
('0bce2cce-524a-4709-b383-68b2aa7150f2','題花光長老畫  其一','韓駒','宋','宋诗','song-poetry','','[]','曉出花光寺，雲沙照眼新。',24,'全唐诗/poet.song.83000.json','["曉出花光寺，雲沙照眼新。", "歸來看圖畫，借問若爲真。"]'),
('0ead969f-c956-4e08-a227-a83112d6e3d7','題花光長老畫  其二','韓駒','宋','宋诗','song-poetry','','[]','昨欲浮湘去，褰裳望九疑。',24,'全唐诗/poet.song.83000.json','["昨欲浮湘去，褰裳望九疑。", "清湘今入手，一棹更何之。"]'),
('6c7b7bee-64ea-40ba-920d-31233ece4599','送黄若虚下第歸湖南','韓駒','宋','宋诗','song-poetry','','[]','時人會傍高門走，獨肯來游翰墨場。',64,'全唐诗/poet.song.83000.json','["時人會傍高門走，獨肯來游翰墨場。", "已有哲兄如叔度，定知吾子勝文強。", "長淮白浪搖春枕，故國青山接夜航。", "乞得功名歸遺母，未應深羨綠衣郎。"]'),
('1a8e8e3a-3b5a-4b65-82af-83dd38889ef9','館中直宿書事  其一','韓駒','宋','宋诗','song-poetry','','[]','十載名山慣杖藜，清都直宿夢魂疑。',32,'全唐诗/poet.song.83000.json','["十載名山慣杖藜，清都直宿夢魂疑。", "卧聞長樂鐘聲近，尚憶寒山半夜時。"]'),
('5b4abb3c-8533-4516-92ec-ccd74680c51e','館中直宿書事  其二','韓駒','宋','宋诗','song-poetry','','[]','北風吹馬襲貂裘，薄雪連雲凍未收。',32,'全唐诗/poet.song.83000.json','["北風吹馬襲貂裘，薄雪連雲凍未收。", "銀闕晝開禽鳥白，信知三館是瀛洲。"]'),
('d466868d-9cd8-4327-a1d4-997b0f0a3895','走筆謝人送酒','韓駒','宋','宋诗','song-poetry','','[]','此身投老倦黄埃，傍水柴扉晚自開。',32,'全唐诗/poet.song.83000.json','["此身投老倦黄埃，傍水柴扉晚自開。", "百萬愁城攻不破，正須從事斬關來。"]'),
('29fdbc4b-f12f-4b32-a0f8-96a8c84e33c0','留别館中諸公','韓駒','宋','宋诗','song-poetry','','[]','暫謫人間去，羣仙莫浪猜。',24,'全唐诗/poet.song.83000.json','["暫謫人間去，羣仙莫浪猜。", "塵緣吾未斷，不是薄蓬萊。"]'),
('11127ee0-ecad-44d4-a267-b43108f16828','行至華陰呈舊同舍','韓駒','宋','宋诗','song-poetry','','[]','落日同騎款段游，倦依松石弄清流。',32,'全唐诗/poet.song.83000.json','["落日同騎款段游，倦依松石弄清流。", "蓬萊漢殿春分手，一笑相逢太華秋。"]'),
('b2b1fa09-6e86-48fa-98d6-e69849614d54','金粟堆','韓駒','宋','宋诗','song-poetry','','[]','少陵金粟堆前淚，歎息開元萬事空。',32,'全唐诗/poet.song.83000.json','["少陵金粟堆前淚，歎息開元萬事空。", "今日我來愁又絕，更無松竹鳥呼風。"]'),
('5069c377-8a0c-49ce-a186-46939fec7a9f','謝人寄小胡孫','韓駒','宋','宋诗','song-poetry','','[]','致爾自何處，初來猶索騰。',48,'全唐诗/poet.song.83000.json','["致爾自何處，初來猶索騰。", "真宜少陵覓，未解柳州憎。", "婢喜常儲果，奴嗔屢掣繩。", "報君無一物，試爲斸寒藤。"]'),
('36bd0e65-1df3-4198-8900-803fd43a6038','醉中走筆留别楊將軍','韓駒','宋','宋诗','song-poetry','','[]','山西老將尚童顔，曾臂紅旗到賀蘭。',32,'全唐诗/poet.song.83000.json','["山西老將尚童顔，曾臂紅旗到賀蘭。", "今日樽前惆悵别，梨花風雨一枝寒。"]'),
('55b28ec9-bea1-4dd2-9f86-f4b682f707dd','賦曲江禁柳','韓駒','宋','宋诗','song-poetry','','[]','照水纖柯拂地明，東風初試舞腰輕。',32,'全唐诗/poet.song.83000.json','["照水纖柯拂地明，東風初試舞腰輕。", "人間豈識長門恨，霧鬢烟鬟綰不成。"]'),
('27599c57-ac11-4d6a-abe2-8200ebce9460','次韻思聰','韓駒','宋','宋诗','song-poetry','','[]','欲問琴聰水鏡篇，朅來端爲著幽禪。',64,'全唐诗/poet.song.83000.json','["欲問琴聰水鏡篇，朅來端爲著幽禪。", "五更下馬呼殘夢，數面成親似宿緣。", "伏腦憐君有犀骨，騰身笑我不鳶肩。", "白頭奔走襄陽道，空誦新詩憶浩然。"]'),
('0a31728c-2be8-4c33-9974-cc464572de7a','和李上舍冬日書事','韓駒','宋','宋诗','song-poetry','','[]','北風吹日晝多陰，日暮擁階黄葉深。',64,'全唐诗/poet.song.83000.json','["北風吹日晝多陰，日暮擁階黄葉深。", "倦鵲繞枝翻凍影，飛鴻摩月墮孤音。", "推愁不去如相覓，與老無期稍見侵。", "顧藉微官少年事，病來那復一分心。"]'),
('68dc60c5-4569-482f-80d1-76d7e577f31d','謝人寄茶筅子','韓駒','宋','宋诗','song-poetry','','[]','立玉干雲百尺高，晚年何事困鉛刀。',32,'全唐诗/poet.song.83000.json','["立玉干雲百尺高，晚年何事困鉛刀。", "看君眉宇真龍種，猶解横身戰雪濤。"]'),
('41d6d812-d566-44ee-be77-c148c7c15063','偶書二絕呈館中舊同舍  其一','韓駒','宋','宋诗','song-poetry','','[]','去年看曝石渠書，內酒均頒白玉腴。',32,'全唐诗/poet.song.83000.json','["去年看曝石渠書，內酒均頒白玉腴。", "今日醉登延閣望，幾人回首憶窮途。"]'),
('97235ea9-6217-4ac9-929f-0b94cd2afce5','偶書二絕呈館中舊同舍  其二','韓駒','宋','宋诗','song-poetry','','[]','御本曾看錦帕舒，醉驚飛閣上凌虛。',32,'全唐诗/poet.song.83000.json','["御本曾看錦帕舒，醉驚飛閣上凌虛。", "而今卧病衡門底，自曬茆簷幾卷書。"]'),
('3039a508-4257-4c4e-b891-8d6ccdfb747a','題明皇上馬圖','韓駒','宋','宋诗','song-poetry','','[]','翠華欲幸長生殿，立馬樓前待貴妃。',32,'全唐诗/poet.song.83000.json','["翠華欲幸長生殿，立馬樓前待貴妃。", "尚覓君王一回顧，金鞍欲上故遲遲。"]'),
('0714579f-0bb4-401d-95d3-74b5d036318c','次韻倪巨濟夏夜二首  其一','韓駒','宋','宋诗','song-poetry','','[]','慵便紗帽滑，病起葛衣輕。',48,'全唐诗/poet.song.83000.json','["慵便紗帽滑，病起葛衣輕。", "白露含花動，黄流带月清。", "思君開酒陣，是夕破愁城。", "但恐何平叔，常談笑老生。"]'),
('00d59fa5-2377-45b9-80a2-3f5cb4da3c81','次韻倪巨濟夏夜二首  其二','韓駒','宋','宋诗','song-poetry','','[]','卧病京華客，塵緣種種輕。',48,'全唐诗/poet.song.83000.json','["卧病京華客，塵緣種種輕。", "共誰傾蓋舊，之子逼人清。", "筆倒三江水，詩專五字城。", "白頭聽諷誦，渾覺黑絲生。"]'),
('f1021b6d-3c4e-4982-b082-946784d92e45','送蘇世美東歸  其一','韓駒','宋','宋诗','song-poetry','','[]','東游兩見鶴林春，晚愧先生作並鄰。',64,'全唐诗/poet.song.83000.json','["東游兩見鶴林春，晚愧先生作並鄰。", "罇俎每留倉猝客，典型猶識老成人。", "繫舟一笑都門外，賣劍歸耕潁水濱。", "意氣年來類兒女，别離不覺淚横巾。"]'),
('d5bcd2f1-81b3-49e3-9a70-b12e40614594','送蘇世美東歸  其二','韓駒','宋','宋诗','song-poetry','','[]','京口尋山毎見攜，鶴林問法更追隨。',64,'全唐诗/poet.song.83000.json','["京口尋山毎見攜，鶴林問法更追隨。", "本無物累那成癖，肯借人書未必癡。", "食粥往年容乞米，一罇今日細論詩。", "邗溝好去春風暖，莫忘椎冰共載時。"]'),
('e714af28-3dc9-414b-945a-7938ebd0981a','次韻蘇文饒待舟書事','韓駒','宋','宋诗','song-poetry','','[]','公才豈止劇曹郎，肯向明時氏庾倉。',64,'全唐诗/poet.song.83000.json','["公才豈止劇曹郎，肯向明時氏庾倉。", "會有綾衾趨漢署，不須錦纜繫吳檣。", "青箱教子書千卷，白髪思親天一方。", "看我飄然五湖去，棧羊篩酒送歸艎。"]'),
('1be3576d-9095-492e-8ad3-98c1f7917814','次韻蘇彦師見寄','韓駒','宋','宋诗','song-poetry','','[]','長年眼力怯看書，每見先生愧腹虚。',64,'全唐诗/poet.song.83000.json','["長年眼力怯看書，每見先生愧腹虚。", "猶覺是身多净業，欲投禪客問真如。", "向來水馹分襟罷，常記河梁握手初。", "從此論交同畢杜，巷南巷北莫相疏。"]'),
('54060e87-8a90-43d5-9ce2-b3188634af74','題萬松亭  其一','韓駒','宋','宋诗','song-poetry','','[]','北窗欹枕雨濛濛，夢破青山落眼中。',32,'全唐诗/poet.song.83000.json','["北窗欹枕雨濛濛，夢破青山落眼中。", "喚取隱居來此住，人間却有萬松風。"]'),
('2d6ce879-865f-46c2-b80e-6c575b4347d8','題萬松亭  其二','韓駒','宋','宋诗','song-poetry','','[]','老夫愛此摩雲幹，欲下黄岡尚據鞍。',32,'全唐诗/poet.song.83000.json','["老夫愛此摩雲幹，欲下黄岡尚據鞍。", "一疋猶無好東絹，憑誰貎出萬松看。"]'),
('79fdd3a8-3b75-4232-b26c-d5508eff6250','道中絕句  其一','韓駒','宋','宋诗','song-poetry','','[]','淺黛依依臨水笑，挼藍脉脉抱山流。',32,'全唐诗/poet.song.83000.json','["淺黛依依臨水笑，挼藍脉脉抱山流。", "他年定作寒溪夢，夢載支郎雪滿舟。"]'),
('f476b55a-da47-49bf-9530-30c66be895db','道中絕句  其二','韓駒','宋','宋诗','song-poetry','','[]','野岸黄榆三萬栽，枯根斷處水容開。',32,'全唐诗/poet.song.83000.json','["野岸黄榆三萬栽，枯根斷處水容開。", "隋堤二月春如許，看取柔條拂面來。"]'),
('4b72c942-2359-4fc8-b194-568f7dcb6d0e','道中絕句  其三','韓駒','宋','宋诗','song-poetry','','[]','青羅带上玉花飛，不用天山一尺圍。',32,'全唐诗/poet.song.83000.json','["青羅带上玉花飛，不用天山一尺圍。", "欲上釣船沙際宿，前旌何苦喚人歸。"]'),
('4d56f2ab-680d-4f49-b798-7efa138fd0b1','梅花八首  其一','韓駒','宋','宋诗','song-poetry','','[]','山居有幽事，小雪破梅心。',48,'全唐诗/poet.song.83000.json','["山居有幽事，小雪破梅心。", "的皪明陰壑，玲瓏挂晚林。", "吹香撩遠興，弄影慰孤斟。", "剩欲留長在，霜枝半不禁。"]'),
('9c8ba321-79c0-411d-95bf-596409441ac8','梅花八首  其二','韓駒','宋','宋诗','song-poetry','','[]','蔕是團青蠟，花非刻素紈。',48,'全唐诗/poet.song.83000.json','["蔕是團青蠟，花非刻素紈。", "直言南雪少，猶自北枝寒。", "白髪遲明折，清香带暝看。", "有情亭午日，慎莫苦摧殘。"]'),
('e5d8b14b-1523-4d82-819e-27666fa70048','梅花八首  其三','韓駒','宋','宋诗','song-poetry','','[]','的皪林間白，風霜莫浪催。',24,'全唐诗/poet.song.83000.json','["的皪林間白，風霜莫浪催。", "江南春不雪，似是一枝梅。"]'),
('7727f4af-2264-4bf8-b05b-c70f9d16b074','梅花八首  其四','韓駒','宋','宋诗','song-poetry','','[]','雪裏尋梅蕊，多應傍水開。',24,'全唐诗/poet.song.83000.json','["雪裏尋梅蕊，多應傍水開。", "那知是花處，但覓暗香來。"]'),
('0255b656-6d6a-4a4b-99c1-4b128c6185cd','梅花八首  其五','韓駒','宋','宋诗','song-poetry','','[]','江南歲晚雪漫漫，磵谷梅花巧耐寒。',32,'全唐诗/poet.song.83000.json','["江南歲晚雪漫漫，磵谷梅花巧耐寒。", "幸有幽香當供給，不辭三載滯西安。"]'),
('561d335e-ebf9-4335-b273-71f0284b1584','梅花八首  其六','韓駒','宋','宋诗','song-poetry','','[]','雲根細路繞溪斜，日出烟銷水見沙。',32,'全唐诗/poet.song.83000.json','["雲根細路繞溪斜，日出烟銷水見沙。", "只度關山魂已斷，何須疏雨濕梅花。"]'),
('8f10b280-5468-4779-8d82-6d9e9fc6aa42','梅花八首  其七','韓駒','宋','宋诗','song-poetry','','[]','籃輿曉入關山路，玉節珠旛次第開。',32,'全唐诗/poet.song.83000.json','["籃輿曉入關山路，玉節珠旛次第開。", "白髪微官何用許，似憐身出道山來。"]'),
('8ba40a51-6d6a-45ba-8c9e-de61e7fd487e','梅花八首  其八','韓駒','宋','宋诗','song-poetry','','[]','漢宮鉛粉浄無痕，蠟點寒梢水畔村。',64,'全唐诗/poet.song.83000.json','["漢宮鉛粉浄無痕，蠟點寒梢水畔村。", "忍犯雪霜凌竹栢，尚憑風月弔蘭蓀。", "騷人折去清詩健，驛使持歸舊典存。", "病眼渾驚春思早，一枝聊洗畫圖昏。"]'),
('da7e3923-84fa-41f1-8923-e9b0361301f0','夜泊寧陵','韓駒','宋','宋诗','song-poetry','','[]','汴水日馳三百里，扁舟東下便開帆。',64,'全唐诗/poet.song.83000.json','["汴水日馳三百里，扁舟東下便開帆。", "旦辭杞國風微北，夜泊寧陵月正南。", "老樹挾霜鳴窣窣，寒花垂露落毿毿。", "茫然不悟身何處，水色天光共蔚藍。"]'),
('b42154f1-2e1a-415a-b9b5-83672463df78','題申居士霅溪圖','韓駒','宋','宋诗','song-poetry','','[]','霅溪居士買山圖，碧玉峰前碧玉湖。',32,'全唐诗/poet.song.83000.json','["霅溪居士買山圖，碧玉峰前碧玉湖。", "中有一丘容我老，暮年居士肯分無。"]'),
('0b9501c0-a310-4eb1-8967-fb56cb778562','同趙發運游甘露寺','韓駒','宋','宋诗','song-poetry','','[]','皇華使者下滄洲，十載題輿記舊游。',64,'全唐诗/poet.song.83000.json','["皇華使者下滄洲，十載題輿記舊游。", "欲信隨車翻雨脚，請看轉漕跋船頭。", "飛騰已入西清殿，徙倚猶尋北固樓。", "肯與故人躋石徑，松風聲裏度鳴騶。"]'),
('f9becb2c-cbb5-463f-8492-5c29ba081081','庚子年還朝飲酒六絕句  其一','韓駒','宋','宋诗','song-poetry','','[]','三年逐客卧江臯，自與田翁酌小槽。',32,'全唐诗/poet.song.83000.json','["三年逐客卧江臯，自與田翁酌小槽。", "飲慣茆柴諳苦硬，不知如蜜有香醪。"]'),
('42498809-c7e4-4483-95d6-471fb24ecde6','庚子年還朝飲酒六絕句  其二','韓駒','宋','宋诗','song-poetry','','[]','往時看曝石渠書，內酒均頒白玉腴。',32,'全唐诗/poet.song.83000.json','["往時看曝石渠書，內酒均頒白玉腴。", "落魄十年無復醉，因公今日識官壺。"]'),
('92ff1ab7-4313-4215-ad9b-e65f8c4a8e8f','庚子年還朝飲酒六絕句  其三','韓駒','宋','宋诗','song-poetry','','[]','漢閣重來鬢已蒼，故交強半上鵷行。',32,'全唐诗/poet.song.83000.json','["漢閣重來鬢已蒼，故交強半上鵷行。", "鳴鞭送與黄封酒，似喚幽人入醉鄉。"]'),
('90038e49-8f8d-4226-b702-9c948dcaab4d','庚子年還朝飲酒六絕句  其四','韓駒','宋','宋诗','song-poetry','','[]','愛酒淵明愛也無，無人爲我著錢沽。',32,'全唐诗/poet.song.83000.json','["愛酒淵明愛也無，無人爲我著錢沽。", "起呼老瓦嘗官醖，一炷寒燈夜自娱。"]'),
('45d9dde6-b37b-4326-8760-69a6c3b2c556','庚子年還朝飲酒六絕句  其五','韓駒','宋','宋诗','song-poetry','','[]','舊聞西國蒲萄酒，走送柴門不待求。',32,'全唐诗/poet.song.83000.json','["舊聞西國蒲萄酒，走送柴門不待求。", "飲罷愁城無處立，故應一斗直凉州。"]'),
('ab27429d-6049-4ca1-b076-c180aeca4364','庚子年還朝飲酒六絕句  其六','韓駒','宋','宋诗','song-poetry','','[]','五侯池沼卷東風，釀作真珠滴小紅。',32,'全唐诗/poet.song.83000.json','["五侯池沼卷東風，釀作真珠滴小紅。", "但怪外邊春色曉，濃華都在沁園中。"]'),
('ccf55764-dfea-4ffe-9532-de8f06faf113','題韓幹畫馬','韓駒','宋','宋诗','song-poetry','','[]','古畫仍藏古錦囊，故人攜得自瞿塘。',32,'全唐诗/poet.song.83000.json','["古畫仍藏古錦囊，故人攜得自瞿塘。", "僰僮莋馬應羞見，羌戶方調兩驌驦。"]'),
('fbc97b31-d7a1-4ffe-89ba-9c23a73bf071','送海常化士  其一','韓駒','宋','宋诗','song-poetry','','[]','好去凌空錫杖飛，鳳林關外道場稀。',32,'全唐诗/poet.song.83000.json','["好去凌空錫杖飛，鳳林關外道場稀。", "莫言衲子籃無底，盛取江南骨董歸。"]'),
('1b8420de-4c63-42f8-9530-35cfed4138ad','送海常化士  其二','韓駒','宋','宋诗','song-poetry','','[]','鉢囊空去莫言貧，會見吹毛本分人。',32,'全唐诗/poet.song.83000.json','["鉢囊空去莫言貧，會見吹毛本分人。", "乞得金多未爲貴，歸來著眼看家珍。"]'),
('96e270a7-6554-4a9d-aec4-0f8735989efc','次韻何文縝種竹','韓駒','宋','宋诗','song-poetry','','[]','杜陵窮老覓榿栽，不似何郎種笛材。',64,'全唐诗/poet.song.83000.json','["杜陵窮老覓榿栽，不似何郎種笛材。", "三徑莫憂荒草合，一樽如與故人開。", "未堪急雨枝枝打，便有幽禽日日來。", "坐誦東坡食無肉，詩腸日午轉饑雷。"]'),
('bb173611-d251-4884-aa22-5c950223f937','虞童子七歲能誦書部使者聞諸朝既至京師會更制不果試其歸也以二小詩送之  其一','韓駒','宋','宋诗','song-poetry','','[]','七歲瀾翻數萬言，饑鷹引子望騰鶱。',32,'全唐诗/poet.song.83000.json','["七歲瀾翻數萬言，饑鷹引子望騰鶱。", "時平不用甘羅輩，寂寞提書歸故園。"]'),
('4c0c7c18-cc8f-457e-ba19-ba37d6f4c5b9','虞童子七歲能誦書部使者聞諸朝既至京師會更制不果試其歸也以二小詩送之  其二','韓駒','宋','宋诗','song-poetry','','[]','不作西京童子郎，時人已自識黄香。',32,'全唐诗/poet.song.83000.json','["不作西京童子郎，時人已自識黄香。", "還家更誦五千卷，十八重來詣太常。"]'),
('24939187-7a7b-4fc1-af23-230bd9622cf8','次韻李希聲館中上元直宿','韓駒','宋','宋诗','song-poetry','','[]','海上飛來百尺山，三呼萬歲亦迎鑾。',64,'全唐诗/poet.song.83000.json','["海上飛來百尺山，三呼萬歲亦迎鑾。", "春連禁籞常年早，夜近清都特地寒。", "不見星橋開鐵鎖，似聞雷鼓落銅丸。", "起呵凍筆哦詩罷，月傍蓬萊漢閣殘。"]'),
('1d39c12e-9628-467b-b8a2-96003ed52838','次韻王給事觀殿試唱名  其一','韓駒','宋','宋诗','song-poetry','','[]','已對丹墀眼尚生，金莖曉露逼人清。',64,'全唐诗/poet.song.83000.json','["已對丹墀眼尚生，金莖曉露逼人清。", "非關董相三篇切，自是重華四目明。", "勇似風摧山嶽勢，罷如雷卷海波聲。", "曾叨應奉宮門外，老去空驚歲籥更。"]'),
('686831ed-e104-4ae8-a52c-ad34cf60937e','次韻王給事觀殿試唱名  其二','韓駒','宋','宋诗','song-poetry','','[]','馬革包尸誓此生，豈知今日塞塵清。',64,'全唐诗/poet.song.83000.json','["馬革包尸誓此生，豈知今日塞塵清。", "強隨舉子論兵要，直爲君王下詔明。", "老將猶能賈餘勇，少年未分怯先聲。", "元戎十乘他時事，莫厭邊亭夜報更。"]'),
('18eb1fbd-4cf2-4d94-b182-37cbd0932233','次韻王給事觀殿試唱名  其三','韓駒','宋','宋诗','song-poetry','','[]','漠漠春雲晚自生，廣寒宮裏未爲清。',64,'全唐诗/poet.song.83000.json','["漠漠春雲晚自生，廣寒宮裏未爲清。", "花深曲水潺湲出，柳暗長廊朧𦝰明。", "月近頻移鳷鵲影，庭空自樂鳥烏聲。", "此時欲寄王摩詰，字字煩君子細更。"]'),
('205c6a96-143a-4841-bc88-f0fd144c2d9c','次韻王給事觀殿試唱名  其四','韓駒','宋','宋诗','song-poetry','','[]','集英春殿唱諸生，日轉觚稜曉色清。',64,'全唐诗/poet.song.83000.json','["集英春殿唱諸生，日轉觚稜曉色清。", "近侍皆分金带赤，內人爭看雪衣明。", "罷朝詔賜羣公坐，合殿歡傳萬歲聲。", "我老倦隨宮漏永，江南歸去聽鼉更。"]'),
('69186b50-2d0c-44be-8eaf-d7f50ac026b7','先大夫元豐間及進士第榮州伯父喜而賦詩宣和四年信道兄登科某時爲著作郎侍立集英殿與觀唱名未幾信道兄調而歸某謹次伯父韻以送之','韓駒','宋','宋诗','song-poetry','','[]','坐看連名策太常，青雲穩上不須忙。',64,'全唐诗/poet.song.83000.json','["坐看連名策太常，青雲穩上不須忙。", "盡收騏驥無中駟，别揀楩柟有豫章。", "玉殿桂留今日影，瓊林花記昔年香。", "聞君補吏成都去，更與重尋舊草堂。"]'),
('d33f12a3-4a7b-4326-be5d-3796c9c1859b','送王左丞宣撫河北','韓駒','宋','宋诗','song-poetry','','[]','百里煙雲墮目中，天戈直擣大槐宮。',64,'全唐诗/poet.song.83000.json','["百里煙雲墮目中，天戈直擣大槐宮。", "已煩寵數褒申伯，更遣羌戎識晉公。", "玉帳旌旗皆喜色，鐵林鼓吹自春風。", "應磨萬丈燕山石，獨攬宣和第一功。"]'),
('9a9654e9-afb0-4426-b033-a50743483570','次韻翁監再來館中','韓駒','宋','宋诗','song-poetry','','[]','歸老江湖久自盟，睡餘且復對空枰。',64,'全唐诗/poet.song.83000.json','["歸老江湖久自盟，睡餘且復對空枰。", "重來內閣人初健，慣蹋天街馬不驚。", "已喜劉歆分七略，尚傳韓愈誨諸生。", "太平潤色須公等，應許吾兼吏隱名。"]'),
('3ff1a7bc-889f-4b5c-9b88-6eefe81328c1','臣𣓨以御畫鵲示臣某謹再拜稽首賦詩','韓駒','宋','宋诗','song-poetry','','[]','君王妙畫出神機，弱翅爭巢並語時。',64,'全唐诗/poet.song.83000.json','["君王妙畫出神機，弱翅爭巢並語時。", "想見春風鳷鵲觀，一雙飛占萬年枝。", "舍人簪筆上蓬山，輦路春風從駕還。", "天上飛來兩烏鵲，爲傳喜色到人間。"]'),
('2d1ecd0e-5ceb-48b0-a8d0-6c58904e2ffc','送權師謁蒋山華藏二長老','韓駒','宋','宋诗','song-poetry','','[]','祇園寺裏長連榻，衲被蒙頭坐五年。',64,'全唐诗/poet.song.83000.json','["祇園寺裏長連榻，衲被蒙頭坐五年。", "忽憶山中有尊宿，欲來言下覓真詮。", "蕭蕭野店雲生鉢，渺渺江津月入船。", "一段孤湖千里去，不知何事苦參禪。"]'),
('d8c40a58-2ac9-4e13-b969-6509f68a1659','送聰師往蜀中乞錢','韓駒','宋','宋诗','song-poetry','','[]','早學湯休句，中參魯祖禪。',48,'全唐诗/poet.song.83000.json','["早學湯休句，中參魯祖禪。", "舉花曾有省，持鉢尚隨緣。", "雪滿商山屨，風號灞水船。", "誰憐功行苦，乞與一囊錢。"]'),
('92893153-5bf7-4475-be2d-dc5b7dd175ce','次韻館中上元游葆真宮觀燈  其一','韓駒','宋','宋诗','song-poetry','','[]','百千燈射水精簾，尚覺游人意未厭。',32,'全唐诗/poet.song.83000.json','["百千燈射水精簾，尚覺游人意未厭。", "多病只思田舍樂，夜歸烟火望茆簷。"]'),
('5a7a7b19-165c-4d38-b2ee-4ef01f3b5898','次韻館中上元游葆真宮觀燈  其二','韓駒','宋','宋诗','song-poetry','','[]','玉作芙蕖院院明，博山香度小峥嶸。',32,'全唐诗/poet.song.83000.json','["玉作芙蕖院院明，博山香度小峥嶸。", "直言水北人稀到，也有槃姍勃窣行。"]'),
('c2e7313a-a918-4c19-b99e-c44ba56d0fec','次韻館中上元游葆真宮觀燈  其三','韓駒','宋','宋诗','song-poetry','','[]','鴨綠未全生曲沼，鵝黄先已上柔柯。',32,'全唐诗/poet.song.83000.json','["鴨綠未全生曲沼，鵝黄先已上柔柯。", "故應春物撩詩思，白髪明朝一倍多。"]'),
('ccc96233-411d-445b-9961-c1eb3e09104a','次韻館中上元游葆真宮觀燈  其四','韓駒','宋','宋诗','song-poetry','','[]','開卷愛公如李益，解言明月逐人來。',32,'全唐诗/poet.song.83000.json','["開卷愛公如李益，解言明月逐人來。", "多情如共春流轉，刻燭題詩又一回。"]'),
('e9ae31c4-75da-4427-9e93-ac65474966e6','次韻館中上元游葆真宮觀燈  其五','韓駒','宋','宋诗','song-poetry','','[]','澹澹新粧带淺啼，催車只待日平西。',32,'全唐诗/poet.song.83000.json','["澹澹新粧带淺啼，催車只待日平西。", "驊騮也自知人意，散入千花了不嘶。"]'),
('ddbafe3c-80e2-4c83-b29f-1b4324c217e3','過左掖門馬上口占','韓駒','宋','宋诗','song-poetry','','[]','十載扁舟自在閑，帝城春物不相關。',32,'全唐诗/poet.song.83000.json','["十載扁舟自在閑，帝城春物不相關。", "却因久住蓬萊閣，贏得年年看綠山。"]'),
('88c2df86-1738-4920-a27f-806313cadddf','蜀僧法聰率然叩門乞詩送行','韓駒','宋','宋诗','song-poetry','','[]','去蜀且萬里，尋師踰十年。',48,'全唐诗/poet.song.83000.json','["去蜀且萬里，尋師踰十年。", "初猶學搜句，老漸欲参禪。", "晏坐蒲團破，游方草屨穿。", "還家何所得，笑上峽中船。"]'),
('781b46c3-ae17-4abd-901f-7852dd63144a','申應時卜居京口名之曰雲棲又曰小築乞詩送行  其一','韓駒','宋','宋诗','song-poetry','','[]','客舍秋來憶舊居，一帆歸去落東吳。',32,'全唐诗/poet.song.83000.json','["客舍秋來憶舊居，一帆歸去落東吳。", "他年寄我新詩句，即是雲棲小築圖。"]'),
('d073c3a6-a3d4-40a5-aa8a-03aae5fb3718','申應時卜居京口名之曰雲棲又曰小築乞詩送行  其二','韓駒','宋','宋诗','song-poetry','','[]','不分西津亭下石，二年輸與白鷗眠。',32,'全唐诗/poet.song.83000.json','["不分西津亭下石，二年輸與白鷗眠。", "而今更恨申居士，占斷旁邊著釣船。"]'),
('08e39b51-2af7-4a79-8179-7376c7568619','故樞密鄭公輓詞  其一','韓駒','宋','宋诗','song-poetry','','[]','舊德凋零盡，惟公尚典型。',48,'全唐诗/poet.song.83000.json','["舊德凋零盡，惟公尚典型。", "遂無宣室對，徒有景鐘銘。", "志欲兼三代，文皆刺六經。", "何由瞻傅說，但覓泰階星。"]'),
('2a27c98c-044e-41b4-9cc7-bf11fc6bec13','故樞密鄭公輓詞  其二','韓駒','宋','宋诗','song-poetry','','[]','義苑曾深入，詞源更力探。',48,'全唐诗/poet.song.83000.json','["義苑曾深入，詞源更力探。", "經綸黄閣再，宥密紫樞三。", "盛德今誰似，高名古所慚。", "傷心舊賓客，望哭府潭潭。"]'),
('e5612f18-0d1d-4005-b23c-73a62104d82c','故樞密鄭公輓詞  其三','韓駒','宋','宋诗','song-poetry','','[]','憶昔平原客，曾叨十九人。',48,'全唐诗/poet.song.84000.json','["憶昔平原客，曾叨十九人。", "懷沙正愁苦，負土更悲辛。", "冊府三年滯，樞庭一見新。", "今來揮涕淚，爲國惜良臣。"]'),
('3ab8f9ca-d661-4b99-9c61-66023480de97','次韻何文縝舍人後省致齋','韓駒','宋','宋诗','song-poetry','','[]','夜直沉沉浴殿南，春風想對百花潭。',64,'全唐诗/poet.song.84000.json','["夜直沉沉浴殿南，春風想對百花潭。", "藤牀轉枕尋餘夢，粉壁題詩倚半酣。", "追記舊游時一笑，勸參真理莫多談。", "白頭粗試絲綸手，歸去扶犂意亦甘。"]'),
('e1dbe67c-adae-4a22-93b1-7fbe037d74ab','故正議李公輓詞  其一','韓駒','宋','宋诗','song-poetry','','[]','內閣論思密，西班步武清。',48,'全唐诗/poet.song.84000.json','["內閣論思密，西班步武清。", "誰無子隆貴，獨被主恩榮。", "带曳黄金重，鞍飛白玉輕。", "舊時行樂地，簫鼓入佳城。"]'),
('02e45694-8b38-4c0f-9e19-49bf8b2e43d5','故正議李公輓詞  其二','韓駒','宋','宋诗','song-poetry','','[]','昔在昭文館，從公侍赭袍。',48,'全唐诗/poet.song.84000.json','["昔在昭文館，從公侍赭袍。", "笑談傾蓋舊，風采照人高。", "便欲參藜杖，那知奠濁醪。", "不堪西北望，松栢暮風號。"]'),
('fe0b2955-7ff1-4891-90b6-cf9fc87730ae','次韻石塔睡菴','韓駒','宋','宋诗','song-poetry','','[]','寺南寺北竹陰濃，背日茆茨雪未融。',64,'全唐诗/poet.song.84000.json','["寺南寺北竹陰濃，背日茆茨雪未融。", "爲厭呢喃說禪病，故將齁䶎現神通。", "殷勤問話非龐藴，邂逅論交得贊公。", "借我蒲團睡今夜，五湖春夢雨聲中。"]'),
('b0bcb14b-a0be-4c5e-9f5d-8ab751bc00d9','送僧化寧吳中行脚  其一','韓駒','宋','宋诗','song-poetry','','[]','我欲游京口，浮家未有船。',24,'全唐诗/poet.song.84000.json','["我欲游京口，浮家未有船。", "羨君無一物，篷底曲肱眠。"]'),
('a0901750-74af-4932-bbfd-e376b3bcc345','送僧化寧吳中行脚  其二','韓駒','宋','宋诗','song-poetry','','[]','渡水穿雲去，神光觸處開。',24,'全唐诗/poet.song.84000.json','["渡水穿雲去，神光觸處開。", "隔江如有得，飛錫早歸來。"]'),
('5a25f9dc-4591-462b-9edc-b35f078f090e','示龜山平老  其一','韓駒','宋','宋诗','song-poetry','','[]','二年三飲龜山井，道上菰蒲亦笑人。',32,'全唐诗/poet.song.84000.json','["二年三飲龜山井，道上菰蒲亦笑人。", "猶覺是身多世累，一菴何日與翁鄰。"]'),
('b75df17a-5a7b-4267-ac5f-ef2eb451e37d','示龜山平老  其二','韓駒','宋','宋诗','song-poetry','','[]','水横絕浦曾爭渡，浪打船頭又少留。',32,'全唐诗/poet.song.84000.json','["水横絕浦曾爭渡，浪打船頭又少留。", "安得一舟淮上釣，水生水落任沉浮。"]'),
('2b8795da-8099-43d1-869d-0dc2945bdf1b','次韻侯思孺將至黄州見簡','韓駒','宋','宋诗','song-poetry','','[]','未用船頭報水程，爲君持酒打愁城。',64,'全唐诗/poet.song.84000.json','["未用船頭報水程，爲君持酒打愁城。", "青山久負當年約，白髪多從客路生。", "點檢轉工新句法，揩磨難减舊風情。", "小留莫道無供給，一味東籬有落英。"]'),
('422e3ecb-e0a0-4060-951d-93314a280ea0','故資政忠惠韓公輓詞  其一','韓駒','宋','宋诗','song-poetry','','[]','籍甚中山守，風流世有人。',48,'全唐诗/poet.song.84000.json','["籍甚中山守，風流世有人。", "獵圍邊月曉，筵蹋塞花春。", "金絮盟猶在，灰釘事已新。", "使公長卧護，何地起胡塵。"]'),
('6047559e-5cd4-488b-b623-c5e55dbd4a7b','故資政忠惠韓公輓詞  其二','韓駒','宋','宋诗','song-poetry','','[]','憶在昭文館，垂紳看立朝。',48,'全唐诗/poet.song.84000.json','["憶在昭文館，垂紳看立朝。", "敢論同自出，但喜識高標。", "有子仍持橐，如公合珥貂。", "傷心鄴城路，宰樹結寒飇。"]'),
('edad1940-946b-4e2a-919d-234b80f6ffa0','以正賜庫蒲萄醅送何斯舉復次其韻  其一','韓駒','宋','宋诗','song-poetry','','[]','歎息蘇公無恙日，坡頭自築小山房。',32,'全唐诗/poet.song.84000.json','["歎息蘇公無恙日，坡頭自築小山房。", "五年不識官壺味，只以春江當酒觴。"]'),
('2a95757e-1223-49ff-b447-da7880e75694','以正賜庫蒲萄醅送何斯舉復次其韻  其二','韓駒','宋','宋诗','song-poetry','','[]','老臣政術不堪論，尚得君王賜酒罇。',32,'全唐诗/poet.song.84000.json','["老臣政術不堪論，尚得君王賜酒罇。", "異日黄州成故事，蒲萄醅熟記初元。"]'),
('b69f9462-03e4-4613-98ad-5783880b0da7','以正賜庫蒲萄醅送何斯舉復次其韻  其三','韓駒','宋','宋诗','song-poetry','','[]','蒲萄酒用春江水，壓倒雲安麴米春。',32,'全唐诗/poet.song.84000.json','["蒲萄酒用春江水，壓倒雲安麴米春。", "未解敲門問奇字，一杯聊醉草玄人。"]'),
('8997daee-a6cf-4482-b4a1-fac8f90bea24','登赤壁磯','韓駒','宋','宋诗','song-poetry','','[]','緩尋翠竹白沙游，更挽藤梢上上頭。',64,'全唐诗/poet.song.84000.json','["緩尋翠竹白沙游，更挽藤梢上上頭。", "豈有危巢與棲鶻，亦無陳迹但飛鷗。", "經營二頃將歸老，眷戀羣山爲少留。", "百日使君何足道，空餘詩句在江樓。"]'),
('a0b565f5-7241-489b-b044-085446e2e44d','次范元長韻兼簡鄭有功博士','韓駒','宋','宋诗','song-poetry','','[]','少年饒舌類豐干，老似鳴蟬不耐寒。',64,'全唐诗/poet.song.84000.json','["少年饒舌類豐干，老似鳴蟬不耐寒。", "無復酒杯同設席，幾思齋鉢共開單。", "便從此去真差易，未有生涯良獨難。", "樗散鄭公官益冷，雪中何以繼朝餐。"]'),
('4e8951ac-b658-4666-8fc6-6aeb19dd6ff8','次韻耿龍圖稜陵書事','韓駒','宋','宋诗','song-poetry','','[]','十月舟藏蘆荻林，客衣頓覺夜寒侵。',64,'全唐诗/poet.song.84000.json','["十月舟藏蘆荻林，客衣頓覺夜寒侵。", "亂離祗有窮途淚，勳業都無過去心。", "敢恨青鞋蹋江浦，近傳黄屋渡淮陰。", "中興氣象須公等，是日頻聞正始音。"]'),
('c14a86a2-d002-4d07-bf28-28438289f3f1','送蜀僧希肇往雲居','韓駒','宋','宋诗','song-poetry','','[]','邂逅他鄉識，艱難此地逢。',48,'全唐诗/poet.song.84000.json','["邂逅他鄉識，艱難此地逢。", "扁舟逆春水，一鉢趁晨鐘。", "便欲依風穴，寧辭上雪峰。", "老禪行履處，著眼看機鋒。"]'),
('c4c9c373-4894-43ad-b0f7-5620d1f150f6','次韻金陵趙德夫使君上元三絕  其一','韓駒','宋','宋诗','song-poetry','','[]','小風吹水漲平湖，屋角殘冰亦已無。',32,'全唐诗/poet.song.84000.json','["小風吹水漲平湖，屋角殘冰亦已無。", "投老只圖春睡足，可須山鳥強招呼。"]'),
('0a362b57-757a-4282-9ad7-7c9d1b0abd2e','次韻金陵趙德夫使君上元三絕  其二','韓駒','宋','宋诗','song-poetry','','[]','卧聽秦淮嗚咽聲，起看江月暮潮平。',32,'全唐诗/poet.song.84000.json','["卧聽秦淮嗚咽聲，起看江月暮潮平。", "舊時憶在延真觀，玉作芙蕖院院明。"]'),
('62cc88cf-7ab2-4e65-934f-0827d4e3846e','次韻金陵趙德夫使君上元三絕  其三','韓駒','宋','宋诗','song-poetry','','[]','憶昨宣和從武皇，春風省識御袍香。',32,'全唐诗/poet.song.84000.json','["憶昨宣和從武皇，春風省識御袍香。", "自從翠蓋巡沙漠，無復徵歌出洞房。"]'),
('78e05f67-1f6b-4f32-a47a-1ff6bd46e1da','蕪湖戲趙德夫','韓駒','宋','宋诗','song-poetry','','[]','西來有客共征途，不恨維舟日日孤。',32,'全唐诗/poet.song.84000.json','["西來有客共征途，不恨維舟日日孤。", "愛子清明似秋月，當塗見了又蕪湖。"]'),
('30b80c7f-3be9-41e3-b8fc-71982f62a421','送顯上人歸蜀  其一','韓駒','宋','宋诗','song-poetry','','[]','楚雨冥冥催入峽，巴雲漠漠伴歸鄉。',32,'全唐诗/poet.song.84000.json','["楚雨冥冥催入峽，巴雲漠漠伴歸鄉。", "只應袖有歐峰錄，萬里神珠照地光。"]'),
('acaebefc-ef62-42d1-8959-372e9855f5fa','送顯上人歸蜀  其二','韓駒','宋','宋诗','song-poetry','','[]','未可西歸白帝城，半天亭下即胡塵。',32,'全唐诗/poet.song.84000.json','["未可西歸白帝城，半天亭下即胡塵。", "他年若悟居山好，一束茆茨老此身。"]'),
('1b7cf7c7-f907-42ce-870f-a5cccb3840cd','爲超然道人作雲卧菴  其一','韓駒','宋','宋诗','song-poetry','','[]','窣堵西頭屋數楹，知君卧占一溪雲。',32,'全唐诗/poet.song.84000.json','["窣堵西頭屋數楹，知君卧占一溪雲。", "老夫亦有緣雲興，應爲情親肯見分。"]'),
('ff6ca56e-cb3a-45fc-a936-73f397a867fc','爲超然道人作雲卧菴  其二','韓駒','宋','宋诗','song-poetry','','[]','一溪清駛到天宮，上有千株偃蓋松。',32,'全唐诗/poet.song.84000.json','["一溪清駛到天宮，上有千株偃蓋松。", "未肯分流下山去，爲君純浸紫霄峰。"]'),
('ee4f7313-0b0f-402c-b575-6bac6c2daa02','次韻南溪觀魚','韓駒','宋','宋诗','song-poetry','','[]','城西鼓檝又城東，不待溪分上下風。',64,'全唐诗/poet.song.84000.json','["城西鼓檝又城東，不待溪分上下風。", "碧樹垂柑間黄綠，冰盤行鱠簇青紅。", "横塘日暮林巒合，斷岸秋來浦溆通。", "安得此身無世累，便隨漁艇入空濛。"]'),
('225811a0-e265-4634-81f8-cf0e1b12e86d','避賊嚴陽山次蜀僧清雅韻  其一','韓駒','宋','宋诗','song-poetry','','[]','苦菜敷新葉，高槐偃舊枝。',24,'全唐诗/poet.song.84000.json','["苦菜敷新葉，高槐偃舊枝。", "三生草菴主，故與此山期。"]'),
('6672a090-71f1-4a9c-be71-4c765e2f024a','避賊嚴陽山次蜀僧清雅韻  其二','韓駒','宋','宋诗','song-poetry','','[]','亂離多探報，荒僻少知聞。',24,'全唐诗/poet.song.84000.json','["亂離多探報，荒僻少知聞。", "白髪如荒草，秋來不可耘。"]'),
('47f04b89-69e4-47b4-aec4-692b466492e0','用遜子游嚴陽庵韻  其一','韓駒','宋','宋诗','song-poetry','','[]','路轉岡頭松柏深，百年唯我獨追尋。',32,'全唐诗/poet.song.84000.json','["路轉岡頭松柏深，百年唯我獨追尋。", "不知尊者真歸處，嶺上浮雲自古今。"]'),
('67d12ad1-f7e0-4bf5-8613-0143806666b8','用遜子游嚴陽庵韻  其二','韓駒','宋','宋诗','song-poetry','','[]','石根路轉白雲深，壞壁遺椽可細尋。',32,'全唐诗/poet.song.84000.json','["石根路轉白雲深，壞壁遺椽可細尋。", "只道來時無一物，尚留陳迹到如今。"]'),
('cbc1de6f-90fb-44bb-be18-b72969dae511','次撫州高使君韻','韓駒','宋','宋诗','song-poetry','','[]','直道居中少，長才舉最頻。',48,'全唐诗/poet.song.84000.json','["直道居中少，長才舉最頻。", "初聞輓紅粟，又往破黄巾。", "代北猶屯虜，山東有未臣。", "看公爲世用，容我任天真。"]'),
('acdb8f4b-e11c-4d6e-a548-f9f3bfaacaac','再次韻兼簡李道夫  其一','韓駒','宋','宋诗','song-poetry','','[]','麥秋宜晚起，况復雨頻頻。',48,'全唐诗/poet.song.84000.json','["麥秋宜晚起，况復雨頻頻。", "桃竹猶能杖，柴車未可巾。", "閑分酒賢聖，静記藥君臣。", "會有騎鯨李，來陪賀季真。"]'),
('0831d717-697d-4d6b-bf78-c424ddf7115d','再次韻兼簡李道夫  其二','韓駒','宋','宋诗','song-poetry','','[]','李侯梨飣坐，風味勝仁頻。',48,'全唐诗/poet.song.84000.json','["李侯梨飣坐，風味勝仁頻。", "投老須鳴玉，相看尚秃巾。", "便應尋木客，何必問波臣。", "不復來城市，從人笑我真。"]'),
('e6ac182f-79e0-43fc-ae2f-e925a983357b','再次韻兼簡李道夫  其三','韓駒','宋','宋诗','song-poetry','','[]','猶記一麾出，敢論三顧頻。',48,'全唐诗/poet.song.84000.json','["猶記一麾出，敢論三顧頻。", "餘生過飛鳥，幻事揑空巾。", "學道無疑怖，憂時有主臣。", "買舟苕霅去，我亦號玄真。"]'),
('e4f148f2-def4-474d-98ed-1f29c8abd0e4','次韻錢遜叔侍郎見簡','韓駒','宋','宋诗','song-poetry','','[]','白頭逢世難，無地可推愁。',48,'全唐诗/poet.song.84000.json','["白頭逢世難，無地可推愁。", "曉日瞻天闕，春風憶御溝。", "他年余老蜀，萬戶子封留。", "尚記臨川郡，谿山爛漫游。"]'),
('52c69765-ab94-490b-8190-6d4790a03b98','往歲自京口與曾公永宏父同行至下蜀因次前韻簡之','韓駒','宋','宋诗','song-poetry','','[]','下蜀追隨日，歡言一散愁。',48,'全唐诗/poet.song.84000.json','["下蜀追隨日，歡言一散愁。", "籃輿轉陂路，小檝渡潮溝。", "萬里家何在，三年淹此留。", "猶欣遲暮眼，見子並英游。"]'),
('799f7dc9-5f30-4cc8-8259-b5ee2942571d','錢遜叔見示小詩次韻  其一','韓駒','宋','宋诗','song-poetry','','[]','邂逅邗溝記昔年，知君跋馬自湘川。',32,'全唐诗/poet.song.84000.json','["邂逅邗溝記昔年，知君跋馬自湘川。", "欲持斗酒洗泥滓，未辦青銅三百錢。"]'),
('184e4f64-a7d6-4ceb-8e7a-d0b915cfca56','錢遜叔見示小詩次韻  其二','韓駒','宋','宋诗','song-poetry','','[]','卜築相依約暮年，向來深駐汨羅川。',32,'全唐诗/poet.song.84000.json','["卜築相依約暮年，向來深駐汨羅川。", "叩門忽送銅山句，知是賦詩人姓錢。"]'),
('ea1a9c68-bbe5-482a-bcec-39286e52025d','錢遜叔見示小詩次韻  其三','韓駒','宋','宋诗','song-poetry','','[]','墮絮飛花又一年，黄梅小雨暗平川。',32,'全唐诗/poet.song.84000.json','["墮絮飛花又一年，黄梅小雨暗平川。", "莫言晚起家何事，日傍南池數綠錢。"]'),
('7f8d4d56-88fc-4346-a6af-29d853ada75b','錢遜叔見示小詩次韻  其四','韓駒','宋','宋诗','song-poetry','','[]','且復江西度歲年，會須投老劍南川。',32,'全唐诗/poet.song.84000.json','["且復江西度歲年，會須投老劍南川。", "日長一局枯棋罷，卧看兒童學意錢。"]'),
('f29287b6-f1e6-4c33-81a1-4ca1bbed57fb','撫州邂逅彦正提刑道舊感歎輙書長句奉呈','韓駒','宋','宋诗','song-poetry','','[]','憶在昭文並直廬，與君三歲侍皇居。',64,'全唐诗/poet.song.84000.json','["憶在昭文並直廬，與君三歲侍皇居。", "花開輦路春迎駕，日轉蓬山曉曝書。", "學士南來尚巖穴，神州北望已丘墟。", "愁逢漢節滄江上，握手秋風淚滿裾。"]'),
('49bb11bc-8222-46ab-9f02-451613f3527a','題伯時所畫宮女  其一','韓駒','宋','宋诗','song-poetry','','[]','只道春風閉掖廷，朝來綰結髻鬟新。',32,'全唐诗/poet.song.84000.json','["只道春風閉掖廷，朝來綰結髻鬟新。", "蛾眉不是專君寵，試觸君衣鸚鵡嗔。"]'),
('cc8d1d31-29bd-429b-8eae-2fcd35d41aed','題伯時所畫宮女  其二','韓駒','宋','宋诗','song-poetry','','[]','睡起昭陽暗淡粧，不知緣底背斜陽。',32,'全唐诗/poet.song.84000.json','["睡起昭陽暗淡粧，不知緣底背斜陽。", "若教轉盼一回首，三十六宮無粉光。"]'),
('692437f4-5c87-408b-b02c-2d90d8da27e0','次韻游橘陂  其一','韓駒','宋','宋诗','song-poetry','','[]','水邊盧舍寺，朱實繞霜榮。',48,'全唐诗/poet.song.84000.json','["水邊盧舍寺，朱實繞霜榮。", "棘刺防來密，筠籠贈豈輕。", "誰爲嘉橘誦，自擬渼陂行。", "莫訝歸時黑，吾兼吏隱名。"]'),
('5ac26911-e5f0-43e2-80c1-eab9f9e44a28','次韻游橘陂  其二','韓駒','宋','宋诗','song-poetry','','[]','緩尋隨父老，偷折飫僮奴。',48,'全唐诗/poet.song.84000.json','["緩尋隨父老，偷折飫僮奴。", "的皪連僧舍，馨香到客廚。", "題詩郡丞至，問俗使華俱。", "只道千縑易，良田豈易圖。"]'),
('f32ce940-9fe5-454b-b15d-4702d83f30f3','送曾宏父  其一','韓駒','宋','宋诗','song-poetry','','[]','見子京江尚少年，大梁重見已翩翩。',64,'全唐诗/poet.song.84000.json','["見子京江尚少年，大梁重見已翩翩。", "頃來更覺文章進，他日寧容老病先。", "梅谷舊題幽谷引，橘陂新和渼陂篇。", "常慚散吏空稱賞，不敢吹嘘上九天。"]'),
('dde1b55d-e324-43f8-82be-77b030acc9b3','送曾宏父  其二','韓駒','宋','宋诗','song-poetry','','[]','乃翁名見豫章詩，學術傳家有大兒。',64,'全唐诗/poet.song.84000.json','["乃翁名見豫章詩，學術傳家有大兒。", "四海共推文賦早，三年應訝省郎遲。", "生逢側席求賢日，即是摩霄聳壑時。", "若到朝廷問衰朽，爲言藏縮畏人知。"]'),
('fdb0e451-d3d7-4fb6-813f-0f06642fb582','題雙牛圖  其一','韓駒','宋','宋诗','song-poetry','','[]','騃牛蹢躅知何事，定自春山細雨來。',32,'全唐诗/poet.song.84000.json','["騃牛蹢躅知何事，定自春山細雨來。", "漫漫平沙相逐去，可無人掣鼻頭回。"]'),
('14565b25-afa7-48b3-bfb7-405c7c8ee970','題雙牛圖  其二','韓駒','宋','宋诗','song-poetry','','[]','好事誰如公子賢，千金買盡亦欣然。',32,'全唐诗/poet.song.84000.json','["好事誰如公子賢，千金買盡亦欣然。", "老夫若有沉牛二，春雨歸耕負郭田。"]'),
('1133b2c1-44c6-449b-80ef-b15e19d183e9','次韻錢遜叔侍郎見簡  其一','韓駒','宋','宋诗','song-poetry','','[]','掃地焚香元自喜，傍門騎馬向來慵。',64,'全唐诗/poet.song.84000.json','["掃地焚香元自喜，傍門騎馬向來慵。", "田園此去須安枕，海岱今年不舉烽。", "已分痩藤扶病骨，生憎明鏡寫衰容。", "兩公故是經綸手，只問腰金早晚重。"]'),
('399f415c-35c3-4090-b565-cb4e33b367c7','次韻錢遜叔侍郎見簡  其二','韓駒','宋','宋诗','song-poetry','','[]','排悶徑須沽酒飲，貯愁端爲作詩慵。',64,'全唐诗/poet.song.84000.json','["排悶徑須沽酒飲，貯愁端爲作詩慵。", "連聲倦聽城頭角，落點驚飛塞上烽。", "聞道久閑金騕褭，有時高卧繡芙容。", "年來自說無尤物，已結維摩按兩重。"]'),
('97933e80-7fec-4d76-b248-d44c6fda42fe','次韻錢遜叔侍郎見簡  其三','韓駒','宋','宋诗','song-poetry','','[]','開心未用飲門冬，老去何妨萬事慵。',64,'全唐诗/poet.song.84000.json','["開心未用飲門冬，老去何妨萬事慵。", "胡虜近聞歸絕漠，洛陽無復化爲烽。", "休官昔愧陶彭澤，受祿今慚邴曼容。", "誰似侍郎春思亂，解言花影日高重。"]'),
('f9b141ad-c25f-440e-8c18-e7a5436ab535','信州連使君惠酒戲書二絕謝之  其一','韓駒','宋','宋诗','song-poetry','','[]','上饒籍甚文章守，曾共紫薇花下杯。',32,'全唐诗/poet.song.84000.json','["上饒籍甚文章守，曾共紫薇花下杯。", "鈴閣晝閑思老病，故教從事送春來。"]'),
('e4021f3b-d945-4f6d-9240-ecc10b6ea2db','信州連使君惠酒戲書二絕謝之  其二','韓駒','宋','宋诗','song-poetry','','[]','憶傾南庫官供酒，共賞西京勅賜花。',32,'全唐诗/poet.song.84000.json','["憶傾南庫官供酒，共賞西京勅賜花。", "白髪逢春醒復醉，豈知流落在天涯。"]'),
('34762282-efa5-4bd6-8651-1588fc763648','次韻錢遜叔謝曾使君送酒','韓駒','宋','宋诗','song-poetry','','[]','誰憐定武故将軍，醉舞狂歌老更真。',32,'全唐诗/poet.song.84000.json','["誰憐定武故将軍，醉舞狂歌老更真。", "好事時分小槽酒，殘樽也到白頭人。"]'),
('fcd8d2ef-7328-47be-a8f5-655654f91453','次韻曾寺丞觀早朝上徐諫議','韓駒','宋','宋诗','song-poetry','','[]','憶昨飄然下葉闉，十年江海望嚴宸。',64,'全唐诗/poet.song.84000.json','["憶昨飄然下葉闉，十年江海望嚴宸。", "遙知駐蹕艱危地，尚有憂時老大臣。", "已起陽城司諫諍，又傳陸贄掌絲綸。", "爲公細數能文士，幾箇麒麟閣上人。"]'),
('c0bee437-d0b4-4f57-890a-500b3ce21120','次韻徐翰林','韓駒','宋','宋诗','song-poetry','','[]','遠聞仙伯上神山，始覺升平氣象還。',64,'全唐诗/poet.song.84000.json','["遠聞仙伯上神山，始覺升平氣象還。", "一夢休論玉堂事，兩行曾綴紫宸班。", "想燒椽燭書天詔，看剪花騣出帝閑。", "尚憶平生故人否，夜驅黄犢在田間。"]'),
('ae56a861-1425-40c3-8da8-b340352bc414','送僧住梅山  其一','韓駒','宋','宋诗','song-poetry','','[]','寺門岑寂知何許，想對千巖萬壑開。',32,'全唐诗/poet.song.84000.json','["寺門岑寂知何許，想對千巖萬壑開。", "待得梅山梅子熟，不辭先寄一枝來。"]'),
('ee13f3fc-7405-4550-8195-e9e8abbe9f25','送僧住梅山  其二','韓駒','宋','宋诗','song-poetry','','[]','近聞僧說宜黄寺，一道松門夜不關。',32,'全唐诗/poet.song.84000.json','["近聞僧說宜黄寺，一道松門夜不關。", "投老有禾三百把，亦隨君去住梅山。"]'),
('6008d332-ab48-4811-a006-12223f7ab733','某頃知黄州墨卿爲州司錄今八年矣邂逅臨川送别二首  其一','韓駒','宋','宋诗','song-poetry','','[]','自罷黄州守，殊方任轉流。',48,'全唐诗/poet.song.84000.json','["自罷黄州守，殊方任轉流。", "寧論九年謫，已判一生休。", "此士真材傑，諸公定挽留。", "儻歸存老病，車騎擁西疇。"]'),
('ca9f665d-c8dc-4e25-8999-76dc5053d2f3','某頃知黄州墨卿爲州司錄今八年矣邂逅臨川送别二首  其二','韓駒','宋','宋诗','song-poetry','','[]','盜賊猶如此，蒼生困未蘇。',48,'全唐诗/poet.song.84000.json','["盜賊猶如此，蒼生困未蘇。", "今年起安石，不用哭包胥。", "子去朝行在，人應問老夫。", "髭鬚衰白盡，痩地日攜鉏。"]'),
('522b07c4-efcc-4d79-b5c1-a232e897885e','送雲門妙喜游雪峰  其一','韓駒','宋','宋诗','song-poetry','','[]','憶宰分寧日，逢師溪水頭。',48,'全唐诗/poet.song.84000.json','["憶宰分寧日，逢師溪水頭。", "裁書訪彭澤，倚杖話荆州。", "幻世吾方夢，迷津子作洲。", "禪心如密付，更爲小淹留。"]'),
('b715a8af-01a4-4eb0-a157-762f160aa3cf','送雲門妙喜游雪峰  其二','韓駒','宋','宋诗','song-poetry','','[]','不謂英靈漢，猶憐老病翁。',48,'全唐诗/poet.song.84000.json','["不謂英靈漢，猶憐老病翁。", "回舟殘破岸，駐錫涅槃宮。", "復作千山去，真成一段空。", "直愁林下樂，從此更誰同。"]'),
('d502dc07-5e59-4cf0-ab59-7bf0e415efdd','送雲門妙喜游雪峰  其三','韓駒','宋','宋诗','song-poetry','','[]','老子幽棲地，勞君久見存。',48,'全唐诗/poet.song.84000.json','["老子幽棲地，勞君久見存。", "夜氈從栗爆，午盌看茶翻。", "舊事時追憶，深禪得細論。", "還應雪峰老，領衆待雲門。"]'),
('2ae8639f-d392-43fa-a734-cc615e6e96ed','送東林珪老游閩五絕句  其一','韓駒','宋','宋诗','song-poetry','','[]','平時訪我烏江上，亂後逢君汝水濱。',32,'全唐诗/poet.song.84000.json','["平時訪我烏江上，亂後逢君汝水濱。", "欲問龍門真在否，大千沙界邈全身。"]'),
('d6a0221c-41ae-4a8f-9932-aed3c8599621','送東林珪老游閩五絕句  其二','韓駒','宋','宋诗','song-poetry','','[]','少年高掇老龐科，未必龍門衆角多。',32,'全唐诗/poet.song.84000.json','["少年高掇老龐科，未必龍門衆角多。", "幕府三招三不去，唯將一鉢渡娑婆。"]'),
('5f29d9c6-6a68-4ae5-beac-05ee3a866845','送東林珪老游閩五絕句  其三','韓駒','宋','宋诗','song-poetry','','[]','北風捲地雪漫天，慚愧君來住過年。',32,'全唐诗/poet.song.84000.json','["北風捲地雪漫天，慚愧君來住過年。", "日與鄰翁同展鉢，老夫時復聽談禪。"]'),
('6080e663-d28b-454f-a902-09ff60a29f4b','送東林珪老游閩五絕句  其四','韓駒','宋','宋诗','song-poetry','','[]','直自三湘到七閩，無人不道竹菴名。',32,'全唐诗/poet.song.84000.json','["直自三湘到七閩，無人不道竹菴名。", "詩如雪竇加奇峭，禪似雲居更妙明。"]'),
('2261cf84-2b6f-4c22-8bbb-b84a7baa2155','送東林珪老游閩五絕句  其五','韓駒','宋','宋诗','song-poetry','','[]','竹庵端爲故人留，尚許衰翁預勝流。',32,'全唐诗/poet.song.84000.json','["竹庵端爲故人留，尚許衰翁預勝流。", "寄語叢林好清客，未宜輕輥雪峰毬。"]'),
('142554d0-2711-4e74-befe-89b294a53583','示珪上人','韓駒','宋','宋诗','song-poetry','','[]','自識雲門老，經時水石間。',24,'全唐诗/poet.song.84000.json','["自識雲門老，經時水石間。", "尚嫌聞法少，隨度七閩山。"]'),
('c76a8ab2-20c1-4e14-9d9f-cf59cdb81cef','即席送呂居仁','韓駒','宋','宋诗','song-poetry','','[]','一樽相屬兩華顛，落日臨分更泫然。',64,'全唐诗/poet.song.84000.json','["一樽相屬兩華顛，落日臨分更泫然。", "蹀躞鳴珂君得路，伶俜散策我歸田。", "近聞南國生涯盡，厭見西江殺氣纒。", "欲買扁舟吳越去，看山看水樂餘年。"]'),
('6aff8e06-b982-4701-87cd-3f6ebe7cabae','余往歲與遜叔侍郎同寓廣陵靖康元年遜叔守符離余被召過焉未幾余守南都遜叔移真定過留數日紹興二年復同寓臨川感念疇昔奉送一首','韓駒','宋','宋诗','song-poetry','','[]','廣陵三歲共祠宮，二月帆開上水風。',64,'全唐诗/poet.song.84000.json','["廣陵三歲共祠宮，二月帆開上水風。", "北渚蕩舟公醉我，南湖張樂我留公。", "豈知去國千山外，又得連墻一笑同。", "喪亂難堪重離别，可無書札問衰翁。"]'),
('eee1c4ab-b5be-47e5-a87f-1ca55b566213','送李獻可奉使湖南','韓駒','宋','宋诗','song-poetry','','[]','客居蓬藋繞門深，兩歲頻聞車馬音。',64,'全唐诗/poet.song.84000.json','["客居蓬藋繞門深，兩歲頻聞車馬音。", "子壮飛騰日無那，吾衰瘴癘久相侵。", "舊知文力雄青土，想有詩聲動綠林。", "歸傍玉皇香案立，莫忘江閣共登臨。"]'),
('06db648e-cd03-4b8d-afe4-18365acb616a','余爲著作郎如瑩爲司令官舍皆在左掖門外高頭坊紹興四年如瑩持節江西道撫相訪輙成長句','韓駒','宋','宋诗','song-poetry','','[]','邂逅都城接下風，官居總在日華東。',64,'全唐诗/poet.song.84000.json','["邂逅都城接下風，官居總在日華東。", "門瞻曲角趨朝近，路轉高頭出局同。", "今日繡衣新使者，晚塗霜鬢舊鄰翁。", "一杯無復當時樂，赤縣黄圖淚眼中。"]'),
('b18e76b0-636d-4c38-bb54-1f8a502f8c65','次韻曾吉父見簡','韓駒','宋','宋诗','song-poetry','','[]','往歲滄波轉地流，是身如沫信沉浮。',64,'全唐诗/poet.song.84000.json','["往歲滄波轉地流，是身如沫信沉浮。", "初聞盜賊奔他境，漸見衣冠集此州。", "病欲深耕歸谷口，禪須末句問巗頭。", "膺門也自知人喜，有客清真似子不。"]'),
('0fe50375-0651-4763-b7e4-d6d3ed45873b','六月二十一日子文待制見訪熱甚追記館中納凉故事漫成一首','韓駒','宋','宋诗','song-poetry','','[]','漢閣西頭千步廊，與君長夏對胡牀。',64,'全唐诗/poet.song.84000.json','["漢閣西頭千步廊，與君長夏對胡牀。", "陰陰檜色連宮草，寂寂棋聲度苑墻。", "細乳分茶紋簟冷，明珠擘芡小荷香。", "身今老病投炎瘴，最憶冰盤貯蔗漿。"]'),
('faa2af21-0f5f-482d-a3dd-cadf7ed338b2','送子文待制歸蜀','韓駒','宋','宋诗','song-poetry','','[]','家近錦江歸未得，見人之蜀便凄然。',64,'全唐诗/poet.song.84000.json','["家近錦江歸未得，見人之蜀便凄然。", "聞君細說開州好，勸我來依刺史賢。", "當路尚多屯虎兕，遠湖曾否息戈鋋。", "何時萬里雲沙静，穩上沙頭上水船。"]'),
('4feb0568-047b-46e3-8467-5cf0d7183d48','世謂七夕後雨爲洗車雨又七夕後鵲頂毛落俗謂架橋致然戲作二絕  其一','韓駒','宋','宋诗','song-poetry','','[]','雲階月地一相過，未抵經年别恨多。',32,'全唐诗/poet.song.84000.json','["雲階月地一相過，未抵經年别恨多。", "最恨明朝洗車雨，不令回脚渡天河。"]'),
('61b4f973-d54c-463b-b177-2a1b13fa886d','世謂七夕後雨爲洗車雨又七夕後鵲頂毛落俗謂架橋致然戲作二絕  其二','韓駒','宋','宋诗','song-poetry','','[]','上界鸞驂鳯駕多，不消野翮強填河。',32,'全唐诗/poet.song.84000.json','["上界鸞驂鳯駕多，不消野翮強填河。", "可憐無數顛毛落，只得雲軿一再過。"]'),
('5fe93e9d-6aaa-4fcc-a519-5649487ea0d7','夏夜廣壽寺偶書  其一','韓駒','宋','宋诗','song-poetry','','[]','水濁山昏暑未清，風枝不動月微明。',32,'全唐诗/poet.song.84000.json','["水濁山昏暑未清，風枝不動月微明。", "忽驚零露先秋戒，更放蟭蟟一月鳴。"]'),
('1220082c-8e6b-4aef-a017-16a90a6f007b','夏夜廣壽寺偶書  其二','韓駒','宋','宋诗','song-poetry','','[]','城郭初鳴定夜鐘，苾芻過盡法堂空。',32,'全唐诗/poet.song.84000.json','["城郭初鳴定夜鐘，苾芻過盡法堂空。", "移牀獨向西南角，卧看琅璫動晚風。"]'),
('5a07b187-1ebd-4414-bc93-ec8212d54eea','送范叔器次路公弼韻','韓駒','宋','宋诗','song-poetry','','[]','晚塗淹泊向誰論，白髪名卿肯見存。',64,'全唐诗/poet.song.84000.json','["晚塗淹泊向誰論，白髪名卿肯見存。", "雒邑風流餘此老，故家文獻有諸孫。", "寺連狹徑曾傾蓋，船擁清谿尚一罇。", "小駐鄱陽未宜遠，欲憑書尺問寒温。"]'),
('fe59b2fa-49da-43a9-834a-19131b46e047','送范生','韓駒','宋','宋诗','song-poetry','','[]','萬里投殊俗，餘生老一丘。',48,'全唐诗/poet.song.84000.json','["萬里投殊俗，餘生老一丘。", "尚憐之子秀，能慰此翁愁。", "只欲連墻住，胡爲下邑留。", "黄塵詩思盡，乞與四山秋。"]'),
('52b4bf47-4e94-4bfd-b2a5-e934a2fcffb2','夏日謝人送酒','韓駒','宋','宋诗','song-poetry','','[]','木末炎風晚更無，火雲低傍古城隅。',32,'全唐诗/poet.song.84000.json','["木末炎風晚更無，火雲低傍古城隅。", "正嫌酒作鷄冠赤，洗琖驚看白玉腴。"]'),
('1efaf90e-f1f2-43bf-ac07-34e749677236','又謝送鳯團及建茶  其一','韓駒','宋','宋诗','song-poetry','','[]','白髪前朝舊史官，風爐煮茗暮江寒。',32,'全唐诗/poet.song.84000.json','["白髪前朝舊史官，風爐煮茗暮江寒。", "蒼龍不復從天下，拭淚看君小鳯團。"]'),
('bf8c8b15-e874-42a8-b13c-77f009bf9742','又謝送鳯團及建茶  其二','韓駒','宋','宋诗','song-poetry','','[]','山瓶慣識露芽香，細蒻勻排訝許方。',32,'全唐诗/poet.song.84000.json','["山瓶慣識露芽香，細蒻勻排訝許方。", "猶喜晚塗官様在，密羅深碾看飛霜。"]'),
('bc4e1d76-04c6-4b0d-b0b0-9cb37ab27720','嘲蚊','韓駒','宋','宋诗','song-poetry','','[]','物微深可憫，畏雨復兼風。',24,'全唐诗/poet.song.84000.json','["物微深可憫，畏雨復兼風。", "適見傳呼寵，俄成撲地空。"]'),
('19ca6c75-b13f-46fa-b1e1-6f887a365322','嘲蟬','韓駒','宋','宋诗','song-poetry','','[]','資身惟朽壤，得意只繁陰。',24,'全唐诗/poet.song.84000.json','["資身惟朽壤，得意只繁陰。", "浪自聲凄急，人誰聽汝音。"]'),
('4a55abc0-8319-46a8-a770-2a37127b87d3','嘲螢','韓駒','宋','宋诗','song-poetry','','[]','孤光辭腐草，強擬帖天飛。',24,'全唐诗/poet.song.84000.json','["孤光辭腐草，強擬帖天飛。", "中路霜風急，還尋腐草歸。"]'),
('ff95cc0a-c49d-4171-99bf-73c3e476222b','嘲蠅','韓駒','宋','宋诗','song-poetry','','[]','憶昔趨閶闔，朝雞促曉聲。',24,'全唐诗/poet.song.84000.json','["憶昔趨閶闔，朝雞促曉聲。", "何關蠅輩事，也復強飛鳴。"]'),
('5188dc36-8141-491c-bd40-f30d1d93aec9','頃年侍立集英殿見周表卿唱名第二客居臨川表卿爲宜黄丞歲滿訪别以詩送之','韓駒','宋','宋诗','song-poetry','','[]','往時束带侍明光，曾看揮毫點御牀。',64,'全唐诗/poet.song.84000.json','["往時束带侍明光，曾看揮毫點御牀。", "只道驊騮已騰蹋，不知鵰鶚尚摧藏。", "官居四合峰巒雨，驛路千林橘柚霜。", "莫爲艱難歸故里，漢庭今重甲科郎。"]'),
('18af1fc6-3d04-4a47-9166-19267702cb3f','問江西漕使乞酒及牛乳  其一','韓駒','宋','宋诗','song-poetry','','[]','中郎玉節駐江西，飲慣黄封厭赤泥。',32,'全唐诗/poet.song.84000.json','["中郎玉節駐江西，飲慣黄封厭赤泥。", "寄與衰翁時一醉，四山搖落雨凄凄。"]'),
('a618e262-6b39-470e-9467-726f383f52fb','問江西漕使乞酒及牛乳  其二','韓駒','宋','宋诗','song-poetry','','[]','近聞酥酪出中廚，想肯分留寄病夫。',32,'全唐诗/poet.song.84000.json','["近聞酥酪出中廚，想肯分留寄病夫。", "不爲長齋飯麄糲，暮年消渴亦時須。"]'),
('d1c7a488-e177-4aa1-bd61-372c65247a38','冬青','韓駒','宋','宋诗','song-poetry','','[]','離宮見爾近天墀，雨露常私養種時。',32,'全唐诗/poet.song.84000.json','["離宮見爾近天墀，雨露常私養種時。", "寂寞一株嵐霧裏，無人識是萬年枝。"]'),
('17d59c98-2cc6-490c-9d01-12f837c67bc2','謝江州陸簽判寄糖蟹  其一','韓駒','宋','宋诗','song-poetry','','[]','故人書札訪林泉，郭索相隨到酒邊。',32,'全唐诗/poet.song.84000.json','["故人書札訪林泉，郭索相隨到酒邊。", "未擘團臍先一笑，二螯能覆兩觥船。"]'),
('cb9a4dff-fe81-45ba-95a5-2007f061f20a','謝江州陸簽判寄糖蟹  其二','韓駒','宋','宋诗','song-poetry','','[]','只訝平原驛使稀，不嗔彭澤寄來遲。',32,'全唐诗/poet.song.84000.json','["只訝平原驛使稀，不嗔彭澤寄來遲。", "勸君莫以無腸故，忍見紛紛躁擾時。"]'),
('8b1926a7-5a63-4dd9-b840-94c85425157c','次韻吉父曾園梅花  其一','韓駒','宋','宋诗','song-poetry','','[]','路入君家百步香，隔簾初識漢宮粧。',32,'全唐诗/poet.song.84000.json','["路入君家百步香，隔簾初識漢宮粧。", "只疑夢到昭陽殿，一簇輕紅繞淡黄。"]'),
('906350ec-9f13-4b99-a999-6a8c08fd5264','次韻吉父曾園梅花  其二','韓駒','宋','宋诗','song-poetry','','[]','春風併力著寒梅，淺白輕黄一道開。',32,'全唐诗/poet.song.84000.json','["春風併力著寒梅，淺白輕黄一道開。", "竹屋西頭如有路，扶藜不問主人來。"]'),
('237c92bd-602f-429f-9d3e-42ae5558f85c','奉酬泉使君寄荔枝子魚  其一','韓駒','宋','宋诗','song-poetry','','[]','爛紅初擘使君盤，走送柴門色未乾。',32,'全唐诗/poet.song.84000.json','["爛紅初擘使君盤，走送柴門色未乾。", "著意裁詩終不近，遙憐醉眼若爲看。"]'),
('e525fea6-64a7-43ef-a1f4-117220980bda','奉酬泉使君寄荔枝子魚  其二','韓駒','宋','宋诗','song-poetry','','[]','驛騎持書自海旁，開籃剩喜子魚香。',32,'全唐诗/poet.song.84000.json','["驛騎持書自海旁，開籃剩喜子魚香。", "紅螺紫蛤俱羞避，獨許渠儂近酒觴。"]'),
('4d2eccfc-efed-46a1-8b49-b1b96657d027','送李大夫移宰新喻','韓駒','宋','宋诗','song-poetry','','[]','治聲臨潁復臨川，籍甚臨江已預傳。',64,'全唐诗/poet.song.84000.json','["治聲臨潁復臨川，籍甚臨江已預傳。", "但怪驊騮在泥滓，會看鴻鴈撇雲天。", "杯翻竹葉深留客，浦漲桃花小繫船。", "别後更誰從此老，頻將書尺問沉綿。"]'),
('20815226-5d76-47bf-981c-b7cce17df6e3','送翁縣丞赴部  其一','韓駒','宋','宋诗','song-poetry','','[]','不謂張羅地，時能問字過。',48,'全唐诗/poet.song.84000.json','["不謂張羅地，時能問字過。", "欲爲衰朽託，將奈别離何。", "比歳開三館，君才中十科。", "待平澶衛了，加思頌元和。"]'),
('863d5ff6-d7eb-48be-8b75-75379f24c040','送翁縣丞赴部  其二','韓駒','宋','宋诗','song-poetry','','[]','昔坐甘陵黨，頻年墮嶮巇。',48,'全唐诗/poet.song.84000.json','["昔坐甘陵黨，頻年墮嶮巇。", "斯文今烜赫，隱吏已衰遲。", "俊茂推之子，飛騰值聖時。", "諸公宜改觀，相國舊深知。"]'),
('d3dc4af9-b979-4309-af12-96a261fb1a3e','似矩尚書帥桂道由臨川賦詩三首貽彦章內翰謹次元韻送行  其一','韓駒','宋','宋诗','song-poetry','','[]','喪亂乖離數，衰慵問訊疏。',48,'全唐诗/poet.song.84000.json','["喪亂乖離數，衰慵問訊疏。", "新霜上鬚鬢，老淚濕襟裾。", "忽報迎車騎，遙知奉璽書。", "豈惟謀郤縠，文亦似相如。"]'),
('ae265fcc-acfb-45ed-ae0a-652a7e0ee97c','似矩尚書帥桂道由臨川賦詩三首貽彦章內翰謹次元韻送行  其二','韓駒','宋','宋诗','song-poetry','','[]','有人談五嶺，崷崒象衡廬。',48,'全唐诗/poet.song.84000.json','["有人談五嶺，崷崒象衡廬。", "地長十尋竹，波跳三尺魚。", "看公羅鈇鉞，笑我老耕鉏。", "敢望頻書札，相望萬里餘。"]'),
('2ef98cac-a305-4411-a294-ccbd26932b83','似矩尚書帥桂道由臨川賦詩三首貽彦章內翰謹次元韻送行  其三','韓駒','宋','宋诗','song-poetry','','[]','郡戟蒼山上，平分二水流。',48,'全唐诗/poet.song.84000.json','["郡戟蒼山上，平分二水流。", "四時無癘氣，五管有賢侯。", "静契羅公遠，禪參帛道猷。", "人生一麾樂，不必向中州。"]'),
('3f39721b-a052-4fd6-b4de-b116b6e84a82','次韻吉父食筍乳長句  其一','韓駒','宋','宋诗','song-poetry','','[]','酪乳抨來自釋宮，流膏散液竹萌中。',32,'全唐诗/poet.song.84000.json','["酪乳抨來自釋宮，流膏散液竹萌中。", "我方厭苦饑虚病，公已深知識界空。"]'),
('728c993d-c406-4db4-b442-8df20d1c9f60','次韻吉父食筍乳長句  其二','韓駒','宋','宋诗','song-poetry','','[]','只漫轑羮送鄰舍，豈能搜句攪詩翁。',32,'全唐诗/poet.song.84000.json','["只漫轑羮送鄰舍，豈能搜句攪詩翁。", "山城異味寧長有，却傍春畦擷芥菘。"]'),
('7bf204f4-2125-4390-98fc-21c999d26e69','次韻程待制見簡','韓駒','宋','宋诗','song-poetry','','[]','病鶴羞垂翅，疲駑困絡頭。',48,'全唐诗/poet.song.84000.json','["病鶴羞垂翅，疲駑困絡頭。", "空懸彭澤印，看上汝南州。", "好去營茆棟，相依老荻洲。", "忘憂得佳句，不敢比扶留。"]'),
('7e905b78-1e70-496f-b38e-082d1d016cda','曹山老送筍蕨與諸禪客同食戲成','韓駒','宋','宋诗','song-poetry','','[]','野寺瓶甖至，吾廬水竹幽。',48,'全唐诗/poet.song.84000.json','["野寺瓶甖至，吾廬水竹幽。", "開緘喜風韻，喚客少淹留。", "蕨带寒山醤，筍兼頭子油。", "誰能知許味，一飽併無憂。"]'),
('c5fed7c6-d0c4-4425-aa75-19fc90a1706b','送宜黄宰任滿赴調  其一','韓駒','宋','宋诗','song-poetry','','[]','故老凋零盡，君猶識了翁。',48,'全唐诗/poet.song.84000.json','["故老凋零盡，君猶識了翁。", "深知名節似，不但里閭同。", "政府方交辟，高賢豈久窮。", "他年汝溪上，伴我釣秋風。"]'),
('3b2e17fb-539d-4051-9dcc-d449fe10d693','送宜黄宰任滿赴調  其二','韓駒','宋','宋诗','song-poetry','','[]','聽說宜黄政，他邦總不如。',48,'全唐诗/poet.song.84000.json','["聽說宜黄政，他邦總不如。", "里門喧誦讀，村落罷追胥。", "縱未分侯印，猶當擁使車。", "此詩無麗句，聊代薦賢書。"]'),
('b9976141-aaaa-4c80-951b-c2312f7e4e17','送張右司赴召','韓駒','宋','宋诗','song-poetry','','[]','老夫晏坐臨川寺，五見君爲萬里行。',64,'全唐诗/poet.song.84000.json','["老夫晏坐臨川寺，五見君爲萬里行。", "病馬不辭遭掣頓，雲鵬那復計期程。", "遙知此去常乖隔，莫惜書來訪死生。", "早與朝廷定巴蜀，故山遲暮欲歸耕。"]'),
('6b94c641-d6c8-4063-a289-d3dc48427d13','令人生日以畫十六大阿羅漢爲壽仍作三頌以祝長年  其一','韓駒','宋','宋诗','song-poetry','','[]','悟得玄機已數年，曾蒙老宿印明禪。',32,'全唐诗/poet.song.84000.json','["悟得玄機已數年，曾蒙老宿印明禪。", "定知凡物難爲壽，故仗高人結勝緣。"]'),
('30cbed93-bf13-4323-80d9-ef5d0741bb13','令人生日以畫十六大阿羅漢爲壽仍作三頌以祝長年  其二','韓駒','宋','宋诗','song-poetry','','[]','數枝西國芬陀利，一瓣南天波律香。',32,'全唐诗/poet.song.84000.json','["數枝西國芬陀利，一瓣南天波律香。", "持作誕辰羅漢供，願如羅漢壽無央。"]'),
('76bd69f1-22b6-40ea-9de6-f5b66d8dccc9','令人生日以畫十六大阿羅漢爲壽仍作三頌以祝長年  其三','韓駒','宋','宋诗','song-poetry','','[]','生朝欲作祈年供，長壽玉圭天上來。',32,'全唐诗/poet.song.84000.json','["生朝欲作祈年供，長壽玉圭天上來。", "定是從今有家慶，世人傳作畫圖開。"]'),
('c713e266-6e84-4f91-b644-939a541b11b9','某已被旨移蔡賊起旁郡未果進發今日上城部分民兵閱視戰艦口號五首  其一','韓駒','宋','宋诗','song-poetry','','[]','永安城外山危立，赤壁磯邊水倒流。',32,'全唐诗/poet.song.84000.json','["永安城外山危立，赤壁磯邊水倒流。", "此地能令阿瞞走，小偷何敢下蘆洲。"]'),
('ec525e62-bc14-4074-ac69-ff8792d70e3b','某已被旨移蔡賊起旁郡未果進發今日上城部分民兵閱視戰艦口號五首  其二','韓駒','宋','宋诗','song-poetry','','[]','病守雖閑鬢未蒼，尚能談笑坐胡床。',32,'全唐诗/poet.song.84000.json','["病守雖閑鬢未蒼，尚能談笑坐胡床。", "指揮一掃妖氛盡，便自關山向汝陽。"]'),
('4a247165-297b-4c2a-a75b-48a9b77d4bde','某已被旨移蔡賊起旁郡未果進發今日上城部分民兵閱視戰艦口號五首  其三','韓駒','宋','宋诗','song-poetry','','[]','昨夜黄州得蠟書，老臣恨已解兵符。',32,'全唐诗/poet.song.84000.json','["昨夜黄州得蠟書，老臣恨已解兵符。", "莫將箭污偷兒血，留與官家北射胡。"]'),
('ac085b87-2583-4331-a87a-6ec4e8303a5d','某已被旨移蔡賊起旁郡未果進發今日上城部分民兵閱視戰艦口號五首  其四','韓駒','宋','宋诗','song-poetry','','[]','百憂前日總薰心，一笑朝來得好音。',32,'全唐诗/poet.song.84000.json','["百憂前日總薰心，一笑朝來得好音。", "絕域不須遮虜障，今年自有殺胡林。"]'),
('4dc01aac-76f7-48fb-bfdc-a7c8cc2f6bf5','某已被旨移蔡賊起旁郡未果進發今日上城部分民兵閱視戰艦口號五首  其五','韓駒','宋','宋诗','song-poetry','','[]','沙場臘送亡胡，澤國春生賀漢年。',31,'全唐诗/poet.song.84000.json','["沙場臘送亡胡，澤國春生賀漢年。", "說與胡兒莫輕出，黄岡直下有戈船。"]'),
('e0379ff6-03f5-49e8-a0ce-ecdb064f981e','咸平生日  其一','韓駒','宋','宋诗','song-poetry','','[]','昔年親擢校書郎，夜夢蒼龍繞屋梁。',32,'全唐诗/poet.song.84000.json','["昔年親擢校書郎，夜夢蒼龍繞屋梁。", "異時那知今日應，六龍深駐載賡堂。"]'),
('7b343d71-8288-44c1-8cc7-1f489716334c','咸平生日  其二','韓駒','宋','宋诗','song-poetry','','[]','已向叢霄侍玉宸，朅來端爲付經綸。',32,'全唐诗/poet.song.84000.json','["已向叢霄侍玉宸，朅來端爲付經綸。", "不須更說人間事，曾是仙中第一人。"]'),
('f0c618a6-eefa-4f51-a0a7-bfa23a285785','題孫邵王摩詰渡水羅漢','韓駒','宋','宋诗','song-poetry','','[]','問渠褰裳欲何往，倉惶徙倚滄江上。',64,'全唐诗/poet.song.84000.json','["問渠褰裳欲何往，倉惶徙倚滄江上。", "至人入水固不濡，何以有此恐怖狀。", "我知摩詰意未真，欲以筆端調世人。", "此水此渡俱非實，摩詰亦未嘗下筆。"]'),
('ebfaabbf-7e35-4afd-8fd3-47b93fd0f081','絕句','韓駒','宋','宋诗','song-poetry','','[]','天寒候雁作行遠，沙晚浴鳬相對眠。',32,'全唐诗/poet.song.84000.json','["天寒候雁作行遠，沙晚浴鳬相對眠。", "松醪朝醉復暮醉，江月上弦仍下弦。"]'),
('65f5642b-4e87-4938-9bb6-8484a541df32','咏太平宰相','韓駒','宋','宋诗','song-poetry','','[]','萬里青霄發軔時，驊騮絕足看奔馳。',32,'全唐诗/poet.song.84000.json','["萬里青霄發軔時，驊騮絕足看奔馳。", "太平宰相何人識，惟有巫咸得預知。"]'),
('12fa7f77-2486-4963-ad48-c892650d54f9','代妓送葛亞卿','韓駒','宋','宋诗','song-poetry','','[]','劉郎底事去匆匆，花有深情只暫紅。',32,'全唐诗/poet.song.84000.json','["劉郎底事去匆匆，花有深情只暫紅。", "弱質未應貪結子，細思須恨五更風。"]'),
('a52a8c60-533a-4698-af53-7b36dd941eb2','贈向巨源','韓駒','宋','宋诗','song-poetry','','[]','老子真祠地，君來覓紙題。',48,'全唐诗/poet.song.84000.json','["老子真祠地，君來覓紙題。", "文如士衡後，年與正平齊。", "聞說鍾陵郡，官居章水西。", "涪翁詩律在，佳處可提攜。"]'),
('e96b488f-d2a8-4395-b727-6c203cbbf0b2','改王智興詩','韓駒','宋','宋诗','song-poetry','','[]','三十年前一乞兒，荆公曾爲替梅詩。',32,'全唐诗/poet.song.84000.json','["三十年前一乞兒，荆公曾爲替梅詩。", "如今輸了無人替，莫向金陵更下棋。"]'),
('557be51a-da82-436c-9c55-eb14f64f34ea','八月十五夜小雨同二弟作','韓駒','宋','宋诗','song-poetry','','[]','去年看月思君處，醉後狂歌和影舞。',67,'全唐诗/poet.song.84000.json','["去年看月思君處，醉後狂歌和影舞。", "今年與君待月時，金樽未盡雨催詩。", "樂事良辰難並有，一生費詩仍費酒。", "君不見綠幕朱簾蠟炬香，何須拂地覓孤光。"]'),
('045f7935-55a1-4db1-a6cf-5c10df6e96de','八月十四日夜作','韓駒','宋','宋诗','song-poetry','','[]','三更欲眠燈掛壁，被冷何曾雙脚直。',112,'全唐诗/poet.song.84000.json','["三更欲眠燈掛壁，被冷何曾雙脚直。", "西風一夜枕邊鳴，令我下牀三嘆息。", "君莫悲秋且自悲，朱顔白髮來相隨。", "天公造作悲歡事，要令百歲如狂癡。", "達人大觀無不可，豈合坐受天公欺。", "我慚無處看明月，一掌荒庭秋草沒。", "去年憶上黄神山，笑看萬里清光發。"]'),
('9cc405a1-5b0e-4a35-bb40-93bc8c941d78','次韻張子文中秋夜月','韓駒','宋','宋诗','song-poetry','','[]','平湖下明月，湛如奩濕銀。',120,'全唐诗/poet.song.84000.json','["平湖下明月，湛如奩濕銀。", "遙憐鍾陵客，臥看繁臺雲。", "我欲故山去，向來車已巾。", "淹留屬中秋，顧愁愁單身。", "停杯問青天，誰駕此玉輪。", "分光到蓬屋，殷勤月夫人。", "張郎嗜讀書，佔畢聞比鄰。", "胡爲嘆今夕，長歌擊匏尊。", "似君豈終窮，努力逢休辰。", "他年和此唱，寄我東南垠。"]'),
('8fa57cbb-a2cc-49f4-9e2e-d6bb34139366','春二首  其一','韓駒','宋','宋诗','song-poetry','','[]','春風吹綠原頭草，草色雨餘晴更好。',64,'全唐诗/poet.song.84000.json','["春風吹綠原頭草，草色雨餘晴更好。", "堂前簾靜燕初忙，江上麥齊蠶欲老。", "腐儒飽食欣自得，日長但酣春晝眠。", "戶屨無人足清絕，覺來幽響落山泉。"]'),
('4ad954e2-f688-41c6-83dd-f66b6cd1e2d6','春二首  其二','韓駒','宋','宋诗','song-poetry','','[]','東風著物猶未驚，忽聽林間鵯鵊鳴。',64,'全唐诗/poet.song.84000.json','["東風著物猶未驚，忽聽林間鵯鵊鳴。", "瀨水生波先泛泛，燒痕破暖漸青青。", "農家且喜春耕足，未曉呼兒飯黄犢。", "誰家躍馬來探春，卻笑瀾翻啼布穀。"]'),
('7ebe83e7-3cfc-427e-80df-d327faaaf0bc','秋','韓駒','宋','宋诗','song-poetry','','[]','秋風淅淅搖密竹，乍覺涼生洗炎溽。',64,'全唐诗/poet.song.84000.json','["秋風淅淅搖密竹，乍覺涼生洗炎溽。", "豆田雨過麥毛肥，蘋渚風輕浪痕蹙。", "田家社日試新篘，相過一飯百在憂。", "卻笑儒生真自苦，髪如衰草不勝秋。"]'),
('1eaf9276-d9d9-4f1d-89e3-cddf21f3b972','題曾公卷采菊圖','韓駒','宋','宋诗','song-poetry','','[]','九日東籬採落英，白衣遙見眼能明。',32,'全唐诗/poet.song.84000.json','["九日東籬採落英，白衣遙見眼能明。", "向令自有杯中物，一段風流可得成。"]'),
('73950024-b1db-4f5a-a1b6-89d15060a8d4','雪','韓駒','宋','宋诗','song-poetry','','[]','此時造化何容易，終日飄零似等閑。',32,'全唐诗/poet.song.84000.json','["此時造化何容易，終日飄零似等閑。", "截斷瓊田餘白水，放開琪樹出青山。"]'),
('f84d410e-ee5d-4e98-b693-163dcf923158','詠千葉桃','韓駒','宋','宋诗','song-poetry','','[]','灼灼開元銷恨花，連昌春苑盛恩華。',32,'全唐诗/poet.song.84000.json','["灼灼開元銷恨花，連昌春苑盛恩華。", "如今妖艷無人比，笑倚東風日自斜。"]'),
('5209077c-2657-43f4-b526-a5a176def2f1','桃','韓駒','宋','宋诗','song-poetry','','[]','雲錦漲春塢，霞綃炫夕陽。',24,'全唐诗/poet.song.84000.json','["雲錦漲春塢，霞綃炫夕陽。", "東風多樂意，不特爲紅芳。"]'),
('2ee8b780-7db0-44ad-8da2-d032935f7ffb','梅','韓駒','宋','宋诗','song-poetry','','["\u897f\u6e56"]','斷塹疏籬一水濱，壓枝冰雪眼中春。',64,'全唐诗/poet.song.84000.json','["斷塹疏籬一水濱，壓枝冰雪眼中春。", "懸知東閣一端興，不減揚州千載人。", "晚歲風霜從慘淡，寒梢氣象自清真。", "此來定做西湖夢，疏影橫斜訪舊鄰。"]'),
('c2366c8e-2dcf-4319-9b69-2eddce66a7f7','巖桂花','韓駒','宋','宋诗','song-poetry','','[]','瀹雪凝酥點嫩黄，薔薇清露染衣裳。',32,'全唐诗/poet.song.84000.json','["瀹雪凝酥點嫩黄，薔薇清露染衣裳。", "西風掃盡狂蜂蝶，獨伴天邊桂子香。"]'),
('3a370bc9-1b7c-4a5f-b001-223881367859','上辛太尉生辰詩','韓駒','宋','宋诗','song-poetry','','[]','昭代羣龍用，名家奕世昌。',289,'全唐诗/poet.song.84000.json','["昭代羣龍用，名家奕世昌。", "儲精生輔佐，挺秀誕忠良。", "鬰鬰充閭瑞，熒熒照室祥。", "蓮花雄址峻，竹箭慶源長。", "碩德宜廊廟，英材合棟梁。", "公清凌顥氣，嚴肅厲秋霜。", "蓮寶符千載，威名瞻贍八方。", "量陂吞玉海，言派瀉銀潢。", "功業彝章顯，謀猷棣萼芳。", "檢身金井潔，落節翠𪤋驤。", "列郡依仁牧，千英服智囊。", "精忠裨主聖，膏澤致時康。", "鄧禹重興漢，汾陽再造唐。", "公心平國是，戮力振朝綱。", "斧鉞安南服，威稜振北疆。", "溫恭謙節著，仁惠德風揚。", "鸑鷟金昆盛，貔貅虎旅強。", "望風辭印綬，當路悚豺狼。", "電掃除妖孽，雷驅息叛亡。", "一心仁以厚，五福壽而臧。", "論議留青簡，勳庸紀太常。", "鴻恩非易報，盛德固難忘。", "便合持樞極，那容著海鄉。", "莊椿祈不老，遼鶴竚來翔。"]'),
('81dded92-a06a-4331-b9f9-f85e50a24cfe','上丘漕司生辰詩','韓駒','宋','宋诗','song-poetry','','[]','淮海鍾神秀，逢時出偉人。',171,'全唐诗/poet.song.84000.json','["淮海鍾神秀，逢時出偉人。", "熊羆符吉夢，弧矢記佳辰。", "瑞世儀丹鳳，占祥得石麟。", "心田平若砥，學海闊無津。", "道任司衡重，儒傳孟氏醇。", "雄文追灝噩，雅意藴經綸。", "大策登商第，英名動搢紳。", "含香登粉署，畫諾擁朱輪。", "畫戟罄竹難書稱遠，星軺寵數頻。", "一時推厚德，列郡仰深仁。", "櫜紫殊恩近，官黄墨詔新。", "風雲看際會，廊廟喜同寅。", "壽斝霞紋細，香蓮露臉勻。", "願賡難老頌，閱歲等莊椿。"]'),
('b7ada85d-2780-4314-bf35-4b09d0420155','上鮮于使君生辰詩','韓駒','宋','宋诗','song-poetry','','[]','惟昔高唐夢，熊羆召吉占。',240,'全唐诗/poet.song.84000.json','["惟昔高唐夢，熊羆召吉占。", "氣鍾西蜀秀，時應仲秋嚴。", "江漢揮麈尾，風雲起筆尖。", "微詞追屈宋，精義到黄炎。", "操履禁寒柏，名聲耿衣蟾。", "擊強雕鶚健，治劇鸊鵜銛。", "使者旌旄易，將軍印綬添。", "鴛鴦隨步武，虎豹入韜鈐。", "錦覆郎官被，彤垂太守襜。", "兩行分蜜炬，十里上珠簾。", "禮士嘗懸榻，誅奸忽奮髯。", "雨堂昏絳帳，風帙亂牙籤。", "銀漢星初煥，金莖露已霑。", "歡聲連北固，壽邑更東漸。", "麗句充文几，奇香溢玉奩。", "簪紳五福具，樽俎四夷兼。", "賤子真殊幸，清標獲屢覘。", "談蒙雕朽木，猥辱畫無鹽。", "嘉運方熙洽，英才豈滯淹。", "佇公歸法從，斯道慰民瞻。"]'),
('62a688e4-e6a6-4b41-8b76-aab483ae79d8','上鍾太守生辰詩','韓駒','宋','宋诗','song-poetry','','[]','道在軻雄出，時平稷契生。',168,'全唐诗/poet.song.84000.json','["道在軻雄出，時平稷契生。", "荆山方秀整，金氣與高明。", "磊落難藏器，崢嶸易得名。", "宏才須視草，大手本調羹。", "欲賦龍驤遠，方看鳳翥橫。", "海門迎五馬，桂嶺換雙旌。", "漸許含香侍，寧爲剖竹行。", "悠悠真任物，擾擾不關情。", "札有十行賜，政應期月成。", "風流前輩似，文采後來傾。", "日月開黄道，雲煙煥赤城。", "還朝充柱石，與世作權衡。", "仙果千年實，洪濤幾度清。", "於公一俯仰，几杖表餘榮。"]'),
('89349f19-12d8-44a4-a23a-f7c80a8f2a50','上趙倅生辰詩','韓駒','宋','宋诗','song-poetry','','[]','世運千齡遇，皇圖永紹休。',168,'全唐诗/poet.song.84000.json','["世運千齡遇，皇圖永紹休。", "天方祚堯舜，家自產伊周。", "戟路炎風轉，弧門喜氣浮。", "九苞惟得鳳，三日已窺牛。", "祖牒綿瓜瓞，親庭結冕旒。", "朱轓資佐理，黄屋得分憂。", "白賀才名遠，毛原德業優。", "維城流雅詠，戲綵晢民謳。", "暫出丞侯度，行歸炳帝猷。", "職堪調玉鉉，名已覆金甌。", "甲第開華旦，瓊筵盛薦羞。", "寶釵分樂隊，珠玉萃賓游。", "龜鶴齊稱壽，觥船遞獻酬。", "後天長不老，仙袂拍浮丘。"]'),
('330e8206-efaf-40ad-9acb-a0438a021e1b','上何太宰生辰詩二首  其一','韓駒','宋','宋诗','song-poetry','','[]','斗杓西揭柄，南呂已飛灰。',48,'全唐诗/poet.song.84000.json','["斗杓西揭柄，南呂已飛灰。", "芝室占熊夢，蓬山挺梓材。", "世欣金鷟見，人慶玉麟來。", "天意非難料，行看位上台。"]'),
('3950c599-29fc-4879-826c-2568cea556bf','上何太宰生辰詩二首  其二','韓駒','宋','宋诗','song-poetry','','[]','皇穹符寶運，嵩嶽降真賢。',48,'全唐诗/poet.song.84000.json','["皇穹符寶運，嵩嶽降真賢。", "明月中秋後，黄花九日前。", "潭潭新紫府，疊疊舊青氈。", "遐想雲椿慶，春秋合幾年。"]'),
('c5774ba2-a486-44ea-8695-6fc63499e5b4','上盧運使生辰二四首  其一','韓駒','宋','宋诗','song-poetry','','[]','有玉山自輝，無蠹木不疾。',48,'全唐诗/poet.song.84000.json','["有玉山自輝，無蠹木不疾。", "人心渺難測，天理坐可必。", "我公仁者靜，壽骨已崷嵂。", "豈比山澤儒，辛苦餌芝朮。"]'),
('af0a81ac-9e16-4be4-8666-75416ae6f338','上盧運使生辰二四首  其二','韓駒','宋','宋诗','song-poetry','','[]','千載一生賢，嘉會不易得。',48,'全唐诗/poet.song.84000.json','["千載一生賢，嘉會不易得。", "自從懸弧矢，稱願傾一國。", "紫芝眉宇秀，見者總歸德。", "正如堯絃風，一鼓解慍色。"]'),
('c7fe02cc-9ad1-48ef-ade0-b4d73fc0a60e','上盧運使生辰二四首  其三','韓駒','宋','宋诗','song-poetry','','[]','袖有調元手，辱使江之湄。',48,'全唐诗/poet.song.84000.json','["袖有調元手，辱使江之湄。", "雅懷兼三王，起問夜何其。", "行當發餘藴，陶鑄皋與夔。", "功名格上帝，黄髪齒復兒。"]'),
('6d498261-818c-4eac-baaa-dd280a938bf0','上盧運使生辰二四首  其四','韓駒','宋','宋诗','song-poetry','','[]','春風桃李花，結實老人候。',48,'全唐诗/poet.song.84000.json','["春風桃李花，結實老人候。", "桃李初不言，人迹自奔走。", "恭惟大雅姿，篤實謝雕鏤。", "使之立本朝，一世可仁壽。"]'),
('7b5f77c2-f91f-4c78-a7e5-1949f019b27f','上富樞密生辰詩','韓駒','宋','宋诗','song-poetry','','[]','嘗聞鄭公聲迹留契丹，忠義肝膽人所難。',178,'全唐诗/poet.song.84000.json','["嘗聞鄭公聲迹留契丹，忠義肝膽人所難。", "生民莫識兵革面，坐令中國如石磐。", "英靈鍾稟固有異，端拜而議獨膽寒。", "在天景星地朱草，無乃嘉瑞之鬰蟠。", "鄭公遺範後必大，飛木架學罄苑蘭。", "朝廷搜獵不待次，樞柄足辦談笑間。", "幸令天下已妥貼，夢寐聊以寄東山。", "小春桃花破紅萼，和氣簾幕風輕帆。", "降嵩孕昴掩周漢，酒杯瀲灧香初闌。", "復聞五福一日壽，但願膺此比鶴鸞。", "亟隨環召歸禁密，發揮事業安塵寰。"]'),
('7988edaf-88d1-4009-a63a-1ec9ac70c52b','上司空生辰詩','韓駒','宋','宋诗','song-poetry','','[]','君不見玉皇殿上麒麟兒，掣開金鎖馳如飛。',134,'全唐诗/poet.song.84000.json','["君不見玉皇殿上麒麟兒，掣開金鎖馳如飛。", "紫府洞中尋不見，人間輕跳何之奇。", "又不見越王臺上真山島，簇簇靈光如焰火。", "驪龍騰踏上天池，透出月明珠一顆。", "似此嘉祥世希有，今朝放入賢侯手。", "長庚應向夢中來，還信嵩童重臺否。", "欲知仁政多陰騭，瑞氣融融靄春日。", "廣寒宮裏舊靈根，昨夜新枝抽第一。"]'),
('e403d33c-0c00-4ace-a387-c8e8e7cda868','上陳龍圖生辰詩','韓駒','宋','宋诗','song-poetry','','[]','參差鴛瓦對清霜，玉虬薦瑞初騰驤。',191,'全唐诗/poet.song.84000.json','["參差鴛瓦對清霜，玉虬薦瑞初騰驤。", "三山一夜應圖讖，曉來沙磧堪褰裳。", "熒煌戟戶掛弧矢，瑞氣氤氳結霞綺。", "帝令來作金鼎和，趁得寒梅雪香蕊。", "精神照坐神仙，滔滔揮翰傾何源。", "杜詩韓筆繼騷雅，鳳髓鸞膠室世傳。", "皇皇轡駱耀鄉國，春逐霜蹄滿南陌。", "禁城龍閣儼書圖，班近天顔還咫尺。", "泥書細札九天飛，好看錦衣榮袞知。", "亨時得路方平坦，沙堤斝錯黄金羈。", "年年愛日回南陸，慶壽階庭照蘭玉。", "南極仙翁識姓名，星宮曾見刊瓊籙。"]'),
('90390182-1d86-4bf0-8450-60281e19265c','上丘郎中生辰詩','韓駒','宋','宋诗','song-poetry','','[]','瑯玡崒嵂神仙居，雲中縹緲飛雙鳬。',186,'全唐诗/poet.song.84000.json','["瑯玡崒嵂神仙居，雲中縹緲飛雙鳬。", "玉皇步虛求真儒，翱翔萬里朝皇都。", "金門待詔登公車，彤墀耿耿攄良謨。", "寵光已覽升榮途，握蘭華省歲云徂。", "下憐民物來剖符，寬即不猛鞭用蒲。", "薰陶一味清和敷，報政嘗聞帝曰俞。", "要令仁風及海隅，光華玉節徯來蘇。", "黄童白叟爭歡呼，不須輓粟更飛芻。", "已見年豐樂有餘，玉宇風清化日舒。", "寶爐煙裊度垂弧，憑誰爲我倩麻姑，滿泛金波倒玉壺。", "願君不老八千歲，何啻二十四考居中書。"]'),
('f3d92240-2c82-42e5-a7bb-2c96fe02387b','上丘漕使生辰詩','韓駒','宋','宋诗','song-poetry','','[]','金蜀自昔稱遐封，師帥敢是流嘗澤通。',192,'全唐诗/poet.song.84000.json','["金蜀自昔稱遐封，師帥敢是流嘗澤通。", "嚴宸軫慮文軌同，繡榮遣宣仁風。", "思皇儲精動上穹，炎正重開神降嵩。", "天姿有道和氣融，許國純誠嘉且忠。", "暫借經綸粉省中，輶軒一動竦疲癃。", "詔書誕布恩龐洪，窮谷瀕川靡不蒙。", "取予轉輸公帑充，斂匪加民用度豐。", "樂育菁莪泮水宮，青衿咸仰百川東。", "欽哉美意奉淵衷，多取平反囹圄空。", "名利全歸幹制功，良法通商來往憧。", "疊組重龜問望隆，誦有輿人謠有童。", "但聞載途祝我公，遐齡實惠俱無窮。"]'),
('a694e2b5-e592-4037-b724-7e4010a95435','上漕使生辰詩','韓駒','宋','宋诗','song-poetry','','[]','於皇聖運齊中興，地應嶽瀆天垂星。',256,'全唐诗/poet.song.84000.json','["於皇聖運齊中興，地應嶽瀆天垂星。", "儲靈韞異一發越，中和備體生奇英。", "清淮無波萬瀨肅，纖雲四卷澄水玉。", "薰風庭院倏經秋，長庚入夢祥光燭。", "童年氣韻已不羣，四座愕視天麒麟。", "蘭筋勁翮翔萬里，蓬山錦帳皆彌綸。", "五袴興謠謚三郡，筠秦東甌漸澤潤。", "褰幃便使八州清，光華併管三司峻。", "高懷違俗星斗寒，偉度照人雲夢寬。", "刑清財阜治尤最，天語璿題永不刊。", "夜觀三極三台上，玉節光芒邇天杖。", "浮丘自是地行仙，天遣夔龍助君相。", "仲舒簡古帝所思，弱翁治行已深知。", "粉澤典章混文軌，燕許大手非公誰。", "維南不爲承恩祝，直爲蒼現並蒙福。", "致君堯舜億千齡，頌聲徧寫南山竹。"]'),
('39fa53b0-2ebd-456d-b835-0fcbe8f41438','上王太守生辰詩','韓駒','宋','宋诗','song-poetry','','[]','碧落仙家瓊樹枝，傳芳何處慶雲低。',192,'全唐诗/poet.song.84000.json','["碧落仙家瓊樹枝，傳芳何處慶雲低。", "人間鳳曆將移朔，天上瑤光欲轉西。", "丹穴巢空騫瑞翼，渥漥波漲奮霜蹄。", "堂堂風骨端如岳，凜凜神姿秀入奎。", "紫殿文章驚獨步，黄金名字最先題。", "袖將月窟三春桂，踏盡雲頭萬級梯。", "北闕一麾新出守，南州五馬總驕嘶。", "鈴齋玉麈清談笑，晏館金花貼鼓鼙。", "詩焰迸騰昏日月，酒觴沉困吸虹蜺。", "未能度嶺尋真去，直欲枯潭覓劍攜。", "千里暫煩傾皂蓋，九重終看步沙堤。", "吏情何以爲公頌，祇賦嵩高與壽齊。"]'),
('abfe7a2a-654d-4262-a866-aab1e82ec73c','上黄倅生辰詩','韓駒','宋','宋诗','song-poetry','','[]','羣陰剝盡陽方回，石麟應期天上來。',96,'全唐诗/poet.song.84000.json','["羣陰剝盡陽方回，石麟應期天上來。", "盡鍾粹美入骨骨，餘妍散向江頭梅。", "梅花冷艷排風雪，相映姿韻俱瓊瑰。", "會將風味歸鼎鼐，均調正屬經綸才。", "令辰祝頌喧瑤席，共把梅花壽千百。", "願公長與此花枝，歲歲相逢無紀極。"]'),
('bd598588-d9b2-415d-b831-ea690893124e','上傅守生辰詩','韓駒','宋','宋诗','song-poetry','','[]','于公向日多陰德，扶持自是神明力。',384,'全唐诗/poet.song.84000.json','["于公向日多陰德，扶持自是神明力。", "積善袞袞生公侯，神仙中人不易得。", "此夜長天降瑞星，賢佐乘時爲國生。", "秋水爲神玉爲骨，士林皆賀振佳聲。", "申伯默儲嵩岳氣，玉山照人光彩異。", "北斗以南能幾人，風塵外物巖廊器。", "公之才業天下奇，照山生玉水生犀。", "公稟英靈真間出，氣象往往干雲霓。", "謝安肯爲蒼生起，文采風流今尚爾。", "太學名華入紫宸，妙年歷落青雲士。", "麟臺公監舊仙郎，小郡何煩鳳翼張。", "詔書擢守二千石，緹騎千里照路傍。", "朝廷清明天子聖，下車先使奸豪靜。", "玉麟春踏武陽花，年豐千里無夜驚。", "金章紫綬照青春，儉節清明絕世倫。", "鄉閭禮遜已成俗，樽俎談笑多嘉賓。", "歌詠瑯瑯振金石，風生萬里華胥國。", "坐令白日生春輝，長與聖明恢壽域。", "一杯相屬時初冬，正在乾坤和氣中。", "感君生日遙稱壽，百歲須齊衛武公。", "使君高誼驅今古，歲之旱兮待公雨。", "九重明主正思賢，吾君英濟超光武。", "鰲殿沉沉玉鎖關，壽星元在碧霄間。", "黄閣此行膺大任，祇對吟詠祝南山。"]'),
('d6a219b6-5f38-4b2a-8363-2b90600d9e16','上太師公相生辰詩十首  其一','韓駒','宋','宋诗','song-poetry','','[]','地靈人傑產忠良，瑞靄龍蟠虎踞鄉。',64,'全唐诗/poet.song.84000.json','["地靈人傑產忠良，瑞靄龍蟠虎踞鄉。", "天欲中興神降岳，世將嘉靖弼生商。", "和羹早報梅花信，壽酒先飛柏葉觴。", "笑指山南成带礪，龐眉與國等綿長。"]'),
('ecc75e9d-ed84-433c-9f49-06e0ec78ea3f','上太師公相生辰詩十首  其二','韓駒','宋','宋诗','song-poetry','','[]','運鍾百六擾神州，國祚當時劇贅旒。',64,'全唐诗/poet.song.84000.json','["運鍾百六擾神州，國祚當時劇贅旒。", "獨藉奇材支大廈，允資巨力障橫流。", "嘯呼左袒安劉氏，指顧南冠縶楚囚。", "整頓乾坤康濟了，千齡翊宇永同休。"]'),
('70da4afa-f411-4a16-b6cf-f2cc1f1230d6','上太師公相生辰詩十首  其三','韓駒','宋','宋诗','song-poetry','','[]','揚眉吐氣快生風，萬里歸來虎帳中。',64,'全唐诗/poet.song.84000.json','["揚眉吐氣快生風，萬里歸來虎帳中。", "竭節任公營大計，解紛排難激丹衷。", "只憑忠信行蠻貊，遂使聲名等岱崧。", "一德一心天所祐，定知福壽享無窮。"]'),
('3744b519-4cd1-4292-aff3-61286f5b1bf2','上太師公相生辰詩十首  其四','韓駒','宋','宋诗','song-poetry','','[]','交歡鄰國獨推誠，不顧流言斷必行。',64,'全唐诗/poet.song.84000.json','["交歡鄰國獨推誠，不顧流言斷必行。", "直欲生靈躋壽域，聊將干舞解平城。", "坐扶國祚齊箕翼，立挽天河洗甲兵。", "和議一成夷夏福，蒼生擊壤詠昇平。"]'),
('3861cda7-600a-42d1-91dd-8289a4596cf6','上太師公相生辰詩十首  其五','韓駒','宋','宋诗','song-poetry','','[]','談笑能令國勢強，一時忠義凜秋霜。',64,'全唐诗/poet.song.84000.json','["談笑能令國勢強，一時忠義凜秋霜。", "挽回騩馭還長樂，直把鴻勳紀太常。", "問寢東朝宮殿曉，來庭北使塞垣長。", "輔成孝弟光寰宇，竹帛仍傳萬世芳。"]'),
('049cd73c-b794-4bd1-bcc6-97eed2cf2238','上太師公相生辰詩十首  其六','韓駒','宋','宋诗','song-poetry','','[]','跋扈驕矜勢糾紛，兵威不戢定將焚。',64,'全唐诗/poet.song.84000.json','["跋扈驕矜勢糾紛，兵威不戢定將焚。", "權歸宥密消兵釁，力掃欃槍息祲氛。", "鴻劍將軍休畫策，捧觴都護罷論勳。", "四方廊廟無餘事，咸仰伊周輔聖君。"]'),
('32f076d2-80ad-4e0b-9472-4a0d77622d79','上太師公相生辰詩十首  其七','韓駒','宋','宋诗','song-poetry','','[]','偃伯靈臺滌翳昏，太平有象更何言。',64,'全唐诗/poet.song.84000.json','["偃伯靈臺滌翳昏，太平有象更何言。", "百神禋祀承天貺，萬里調元識定尊。", "復見漢儀難並舉，請觀周樂足同論。", "秉鈞當軸誠知體，坐使先生道滿門。"]'),
('a61f557e-9e10-484a-a9a6-b77e1178e159','上太師公相生辰詩十首  其八','韓駒','宋','宋诗','song-poetry','','[]','騎壒蒙蒙一洗空，恢崇儒館闡文風。',64,'全唐诗/poet.song.84000.json','["騎壒蒙蒙一洗空，恢崇儒館闡文風。", "正當世祖投戈際，遠邁元和沸鼎中。", "坐使車書同萬里，行看冠蓋襲諸戎。", "我公勳業追王佐，豈比區區頌泮宮。"]'),
('9b0253a3-9da6-4eb8-9ca8-c2c76e73ea63','上太師公相生辰詩十首  其九','韓駒','宋','宋诗','song-poetry','','[]','勤勞王室見周公，報賜宜膺曲阜封。',64,'全唐诗/poet.song.84000.json','["勤勞王室見周公，報賜宜膺曲阜封。", "兆見維秦符佐命，祥開有魏慶疇庸。", "申加井賦思方洽，倍衍圭腴賞正濃。", "一德君臣千載遇，九州四海仰雲龍。"]'),
('371992e8-fd62-497e-89f6-de904708cf3f','上太師公相生辰詩十首  其一○','韓駒','宋','宋诗','song-poetry','','[]','手扶日月補圜穹，錫第庸旌再造功。',64,'全唐诗/poet.song.84000.json','["手扶日月補圜穹，錫第庸旌再造功。", "樂奏鈞天迎騎擁，詩歌湛露晏堂豐。", "屬車臨幸龍顔喜，拔宅飛升帝眷隆。", "燕雀非惟依託計，華夷億萬賴帡幪。"]'),
('e04763ad-8b97-47e4-b583-154d1a363d86','上太師公相生辰詩','韓駒','宋','宋诗','song-poetry','','[]','鷲嶺云何錫杖飛，漢家社稷要扶持。',64,'全唐诗/poet.song.84000.json','["鷲嶺云何錫杖飛，漢家社稷要扶持。", "袞衣人共尊姬旦，木鐸天將以仲尼。", "億萬生靈俱再造，百年壽考復奚缺。", "欲枯滄海濡秋兔，來寫門生獻壽詩。"]'),
('ad0f3928-687b-4de1-a281-3fe77edc53ac','上蔡太師生辰詩四首  其一','韓駒','宋','宋诗','song-poetry','','[]','五百年來間氣鍾，堂堂皎月衆星中。',64,'全唐诗/poet.song.84000.json','["五百年來間氣鍾，堂堂皎月衆星中。", "鈞陶四海規模大，心膂三朝禮貌隆。", "壽杖特尊黄髪老，袞衣重拜黑頭翁。", "彭聃豈足爲遐算，直與昇平到不窮。"]'),
('9a924088-a5b0-4e96-bf7f-3dc1df8236a2','上蔡太師生辰詩四首  其二','韓駒','宋','宋诗','song-poetry','','[]','燕雀同欣大廈成，公歸何處不歡聲。',64,'全唐诗/poet.song.84000.json','["燕雀同欣大廈成，公歸何處不歡聲。", "全將和氣還羣物，不放纖塵點太清。", "人指靈椿期壽考，天將神鼎待功名。", "誕辰正得三陽節，已與東君助發生。"]'),
('0b2ea303-322e-41fc-a719-a76e66b4796b','上蔡太師生辰詩四首  其三','韓駒','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君王正殿壓金鰲，一品師臣待赭袍。',64,'全唐诗/poet.song.84000.json','["君王正殿壓金鰲，一品師臣待赭袍。", "萬世規模神鼎重，八年勳業泰山高。", "崇寧樞筦聯領翼，大觀蓬山擢鳳毛。", "介壽幾何詞謾費，爲公仙谷問蟠桃。"]'),
('1615a45b-44a5-4bf4-b3a7-4e9ff36bf1d2','上蔡太師生辰詩四首  其四','韓駒','宋','宋诗','song-poetry','','[]','天遣飛仙下九州，儗倫慎勿漢唐求。',64,'全唐诗/poet.song.84000.json','["天遣飛仙下九州，儗倫慎勿漢唐求。", "他年呂望應黄髪，今日周公尚黑頭。", "夾輔元勳歸玉鉉，太平餘事入銀鈎。", "慶河一派莆陽水，長繞壺山滾滾流。"]'),
('2e8ca964-3676-4939-b08b-4b63e5cb9287','去黄州日','韓駒','宋','宋诗','song-poetry','','[]','經營一頃將歸老，眷戀群山爲少留。',32,'全唐诗/poet.song.84000.json','["經營一頃將歸老，眷戀群山爲少留。", "百日使君無足憶，空餘詩句在江城。"]'),
('3e9ebfe1-e4b4-45c1-9079-0e594241b3cf','題李白畫像','韓駒','宋','宋诗','song-poetry','','[]','玉堂學士今劉向，禁直岧嶤九天上。',32,'全唐诗/poet.song.84000.json','["玉堂學士今劉向，禁直岧嶤九天上。", "不須對此融心神，會植青藜夜相訪。"]'),
('93c4dfc0-912d-46d6-a5cd-1e220d812643','壽鄭丞相','韓駒','宋','宋诗','song-poetry','','[]','歲在淵獻牽牛中，月缺其圓夜無風。',194,'全唐诗/poet.song.84000.json','["歲在淵獻牽牛中，月缺其圓夜無風。", "不知魏分此何夕，瑞光千丈如長虹。", "乃是絳闕來榮公，仙宮羽衛紛層空。", "榮公鼎軸三朝老，活國時推第一功。", "已見指揮收北地，曾聞談笑卻西戎。", "震風凌雨士奔走，十年分與爲帡幪。", "陰功隱德乃如此，故應福祿來無窮。", "朝來寶閣動喜氣，黄雲赤霧相溟濛。", "紫衣貴人押君賜，琥珀酒艷琉璃鍾。", "小儒荷恩與稱述，詩自老來殊不工。", "獻公以九皋之仙鶴，祝公以萬仞之喬松。", "願公壽與宋無極，劍履日在明光宮。"]'),
('3ed1ba66-4b00-40b1-b103-e6cc2623b20c','湘山','韓駒','宋','宋诗','song-poetry','','[]','湘南第一境，山水足娛人。',48,'全唐诗/poet.song.84000.json','["湘南第一境，山水足娛人。", "塔占飛來石，僧留過去身。", "雲泉蒼壁曙，竹樹絳園春。", "羨爾安禪客，翛然不受塵。"]'),
('b80a58a1-f94a-42b9-a031-79c3d8a554d5','句  其一','韓駒','宋','宋诗','song-poetry','','[]','窮如老鼠穿牛角，拙似鮎魚上竹竿。',16,'全唐诗/poet.song.84000.json','["窮如老鼠穿牛角，拙似鮎魚上竹竿。"]'),
('84115ece-0d0d-4150-b034-e58f0dcddde2','句  其二','韓駒','宋','宋诗','song-poetry','','[]','車騎擁西疇。',6,'全唐诗/poet.song.84000.json','["車騎擁西疇。"]'),
('cd0cb15f-2f32-4766-9d30-8107eb23a666','句  其三','韓駒','宋','宋诗','song-poetry','','[]','船擁清溪尚一樽。',23,'全唐诗/poet.song.84000.json','["船擁清溪尚一樽。", "以上宋陸游《老學庵筆記》卷九。"]'),
('70f4ccc2-18ea-4f1b-aacd-667ea785700b','句  其四','韓駒','宋','宋诗','song-poetry','','[]','勸我卷風金叵羅。',8,'全唐诗/poet.song.84000.json','["勸我卷風金叵羅。"]'),
('ba5798c4-c494-4ab7-8b6e-493120895a5d','句  其五','韓駒','宋','宋诗','song-poetry','','[]','海棠不入草堂手。',8,'全唐诗/poet.song.84000.json','["海棠不入草堂手。"]'),
('bde8d322-aedd-49f5-970b-a95408740d60','句  其六','韓駒','宋','宋诗','song-poetry','','[]','麥天晨氣潤，況復雨頻頻。',12,'全唐诗/poet.song.84000.json','["麥天晨氣潤，況復雨頻頻。"]'),
('20971b2f-1bb6-4617-bcbb-02c11d0710aa','句  其七','韓駒','宋','宋诗','song-poetry','','[]','冥冥沙水雁初下，獵獵菰蒲秋向深。',16,'全唐诗/poet.song.84000.json','["冥冥沙水雁初下，獵獵菰蒲秋向深。"]'),
('81bd89d5-da7f-449b-833e-6d518edf0db2','句  其八','韓駒','宋','宋诗','song-poetry','','[]','曉猿啼破千巖翠，古木陰成一徑幽。',16,'全唐诗/poet.song.84000.json','["曉猿啼破千巖翠，古木陰成一徑幽。"]'),
('bbdedceb-0cde-4131-b7a8-9045c2df1ec4','句  其九','韓駒','宋','宋诗','song-poetry','','[]','饑腸不貯酒，凍粟自生春。',12,'全唐诗/poet.song.84000.json','["饑腸不貯酒，凍粟自生春。"]'),
('b29877fd-5c34-4cfb-b380-f0e4026a0c3a','句  其一○','韓駒','宋','宋诗','song-poetry','','[]','縣古槐根露，官清馬骨高。',12,'全唐诗/poet.song.84000.json','["縣古槐根露，官清馬骨高。"]'),
('6949824a-9c9c-4057-af1d-28c6f85498fe','句  其一一','韓駒','宋','宋诗','song-poetry','','[]','風流要是賢公子，白晳仍爲美少年。',16,'全唐诗/poet.song.84000.json','["風流要是賢公子，白晳仍爲美少年。"]'),
('d9b8d6e8-c777-4b7c-8ad9-a346bd9830a9','句  其一二','韓駒','宋','宋诗','song-poetry','','[]','止應獨有江山秀，合自都無廊廟心。',16,'全唐诗/poet.song.84000.json','["止應獨有江山秀，合自都無廊廟心。"]'),
('cc5812e3-3260-4657-93d4-23876344bb83','句  其一三','韓駒','宋','宋诗','song-poetry','','[]','樵策初無主，雞豚各認家。',12,'全唐诗/poet.song.84000.json','["樵策初無主，雞豚各認家。"]'),
('1ce8cf6f-454f-4bb1-9977-4ccf1eb911d2','句  其一四','韓駒','宋','宋诗','song-poetry','','[]','雨暗階前路，苔冶林外家。',12,'全唐诗/poet.song.84000.json','["雨暗階前路，苔冶林外家。"]'),
('d35b7bd5-2efa-4911-84ad-d2b8d7b4a80e','句  其一五','韓駒','宋','宋诗','song-poetry','','[]','月中有女曾分種，世上無花敢鬬香。',16,'全唐诗/poet.song.84000.json','["月中有女曾分種，世上無花敢鬬香。"]'),
('8827745d-5e81-4f7f-bf98-d1fa90e56ae7','句  其一六','韓駒','宋','宋诗','song-poetry','','[]','人間八月秋光好，芙蓉溪上春酣酣。',16,'全唐诗/poet.song.84000.json','["人間八月秋光好，芙蓉溪上春酣酣。"]'),
('727c3ff0-a31c-402d-8ba0-b97400346f70','句  其一七','韓駒','宋','宋诗','song-poetry','','[]','宛陵堂下探梅時。',8,'全唐诗/poet.song.84000.json','["宛陵堂下探梅時。"]'),
('0cf2b4f4-c651-49cb-b14e-e6f9b946f7ea','句  其一八','韓駒','宋','宋诗','song-poetry','','[]','冰壺骨相自清臞。',8,'全唐诗/poet.song.84000.json','["冰壺骨相自清臞。"]'),
('67b3b1ce-67b8-481f-a4ad-59bec7ff5fc6','句  其一九','韓駒','宋','宋诗','song-poetry','','[]','嵩岳降真賢。',6,'全唐诗/poet.song.84000.json','["嵩岳降真賢。"]'),
('0b43e173-356f-44c8-8cbf-3bb9df6a3cab','句  其二○','韓駒','宋','宋诗','song-poetry','','[]','洪府西山最景奇。',8,'全唐诗/poet.song.84000.json','["洪府西山最景奇。"]'),
('cb7d48b7-1856-4f59-897a-dd6158ed7e13','句  其二一','韓駒','宋','宋诗','song-poetry','','[]','孤舟晚颺湖光裏，衰草斜陽無恨意。',16,'全唐诗/poet.song.84000.json','["孤舟晚颺湖光裏，衰草斜陽無恨意。"]'),
('421aa599-aa86-4047-8384-ddd735fee82d','句  其二二','韓駒','宋','宋诗','song-poetry','','[]','連山橫截展一臂，爲我障斷西南夷。',16,'全唐诗/poet.song.84000.json','["連山橫截展一臂，爲我障斷西南夷。"]'),
('e216c56b-d043-4360-98be-5303888993ec','哀高永年戰沒','黄友','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','粉身碎骨事無難，祇爲君恩重泰山。',32,'全唐诗/poet.song.84000.json','["粉身碎骨事無難，祇爲君恩重泰山。", "風淡月明都護府，功名千古在人間。"]'),
('2b150809-a65a-48fb-bd92-0d0fd7716b23','詠風','黄友','宋','宋诗','song-poetry','','[]','不假玄冥力，乘空散寂寥。',48,'全唐诗/poet.song.84000.json','["不假玄冥力，乘空散寂寥。", "聲雄秦塞鼓，勢撼浙江潮。", "落日銜山嘴，浮雲亞隴腰。", "鵬程如借便，九萬看扶搖。"]'),
('241ece2f-dada-4781-b1c3-82bbd3f8ab50','句','王履','宋','宋诗','song-poetry','','[]','矯首向天兮天卒無言，忠臣死難兮死亦何愆。',20,'全唐诗/poet.song.84000.json','["矯首向天兮天卒無言，忠臣死難兮死亦何愆。"]'),
('bbe92016-5ef0-4334-bbed-68ef68806803','杜鵑','鄭瑴','宋','宋诗','song-poetry','','[]','杜鵑飛飛無定棲，寄巢生子百鳥依。',32,'全唐诗/poet.song.84000.json','["杜鵑飛飛無定棲，寄巢生子百鳥依。", "園林花老晝夜啼，安得百鳥挾以歸。"]'),
('61fd511f-0692-45c4-a1c6-6c7964b01291','浙源山','權邦彥','宋','宋诗','song-poetry','','[]','一抹冷雲遮嶺半，千章古木滿巖隈。',64,'全唐诗/poet.song.84000.json','["一抹冷雲遮嶺半，千章古木滿巖隈。", "山深林合失昏晝，路轉溪迴迷去來。", "鷹隼翻空何事擊，猿猱緣壁爲誰哀。", "此行步步山寮界，歸雁詩圖相對開。"]'),
('b0bdbec4-96c8-4bf2-b9fc-d4453bdcdc1b','樂平道中','權邦彥','宋','宋诗','song-poetry','','[]','稻米流脂薑紫芽，芋魁肥白蔗糖沙。',64,'全唐诗/poet.song.84000.json','["稻米流脂薑紫芽，芋魁肥白蔗糖沙。", "村村沽酒喚客喫，並舍有溪魚可叉。", "枹鼓不鳴盜賊少，雞豚里舍語聲嘩。", "賽神還了今年願，又整明年龍骨車。"]'),
('3ac462fd-3fad-46ae-8d60-8f97cb418a04','二月九日遊百門泉覽□由殿院有詩刻石因用其韻書之並律詩奉呈  其一','權邦彥','宋','宋诗','song-poetry','','[]','西山□人巧相逼，興欲乘風先兩腋。',240,'全唐诗/poet.song.84000.json','["西山□人巧相逼，興欲乘風先兩腋。", "犯寒策馬古共城，未見春林眩紅碧。", "土膏浮焰遠沄沄，野燒舊痕明皪皪。", "造幽忽覺累物異，心瑩如澄眼如拭。", "山根出泉泉湧竇，泓此一樣玻璃色。", "炯然毛髪立可數，我欲探之還杖植。", "酈元水經陸羽品，甲乙未許來輕敵。", "徑須乘夜□□□，□試飛橈撥雲跡。", "寒垣奔□□長□，□帽多塵更吹炙。", "偶來娛此得閑曠，塵土自無何用滌。", "境清意徹兩相會，坐對行吟一傾臆。", "鷗鷺飛浮亦閑暇，知我忘機羣可人。", "擬將筆力出□□，□□才□費雕刻。", "荒乘野逸不知倦，是樂箇中真自適。", "暮歸穿邑驚市人，應笑新遷二千石。"]'),
('208ae0cf-e5dd-47d8-af25-4dae78122c50','二月九日遊百門泉覽□由殿院有詩刻石因用其韻書之並律詩奉呈  其二','權邦彥','宋','宋诗','song-poetry','','[]','眼看綠凈思悠哉，縐縠圓珠串欲裁。',64,'全唐诗/poet.song.84000.json','["眼看綠凈思悠哉，縐縠圓珠串欲裁。", "舡穩恍如雲外去，鳥飛驚自鑑中來。", "浺瀜陂浸秦山碎，觱沸泉縈濟水回。", "何似此閑弄明月，月中長嘯有高臺。"]'),
('3eec1e71-0275-45ff-a24e-b7ea0311dba3','遊洞庭山','李彌大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','山浮羣玉碧空沉，萬頃光涵幾許深。',64,'全唐诗/poet.song.84000.json','["山浮羣玉碧空沉，萬頃光涵幾許深。", "梵剎樓臺噓海蜃，洞天日月浴丹金。", "秋林結緣留連賞，春塢藏紅次第吟。", "擬泛一舟追范蠡，從來世味不關心。"]'),
('4cabc3ba-0c0d-4e48-8402-27617cac35a4','堯峰院','李彌大','宋','宋诗','song-poetry','','[]','雲峰何岧嶤，去天餘幾丈。',240,'全唐诗/poet.song.84000.json','["雲峰何岧嶤，去天餘幾丈。", "其下蔚華林，幽禪屹相向。", "我游先朝暾，海日射巾杖。", "飛蓋不須持，步步蒼松障。", "山僧知我來，羅立鳬雁行。", "提攜兩行人，爲我談實相。", "一種勿弦琴，三嘆無聲唱。", "開軒面東南，千里入俯仰。", "西登妙高臺，更欲茲曠望。", "土斷澤繞山，煙濤渺雲浪。", "恐是六鰲連，蓬壺墮莽蒼。", "又疑鯨入海，偃脊起青嶂。", "時方老火熾，金石流欲煬。", "須臾變雲雨，爲作雄風壯。", "翻手回涼秋，掀舞千林響。", "誰云免水宮，自是神龍藏。", "三高如可作，吾欲五湖訪。", "洗足巨浸心，振衣孤峰上。", "寄語夸奪流，得飽但相忘。", "長哦可當歌，踏月下空曠。"]'),
('bf6bf24d-ea37-4b36-b50a-6453d5d66cfd','無礙泉','李彌大','宋','宋诗','song-poetry','','[]','甌研水月先春焙，鼎煮雲林無礙泉。',32,'全唐诗/poet.song.84000.json','["甌研水月先春焙，鼎煮雲林無礙泉。", "將謂蘇州能太守，老僧還解覓詩篇。"]'),
('e6a6d455-f3ca-47dc-8619-09a0025a6261','散步山村喜風俗淳樸小詩紀之','李彌大','宋','宋诗','song-poetry','','[]','山居時散步，所接多耕夫。',60,'全唐诗/poet.song.84000.json','["山居時散步，所接多耕夫。", "或揖或不揖，頗忘爾與君。", "陰晴話愁喜，豐約道有無。", "電迅嘆人壽，風波驚世途。", "超然心不累，朝市何有乎。"]'),
('602523a3-4e15-4329-b012-b2b03c7b4594','親舊有問山中事者示之以詩','李彌大','宋','宋诗','song-poetry','','[]','試與問秦漢，人家總不知。',48,'全唐诗/poet.song.84000.json','["試與問秦漢，人家總不知。", "餐霞雲竇冷，臥月石牀欹。", "流水天常洗，桃花春自遲。", "年年深洞裏，閑着一枰棋。"]'),
('13870c06-ad53-40de-9d1b-45dbdec630c9','觀燈','王子獻','宋','宋诗','song-poetry','','[]','春燈絕勝百花芳，元夕紛華盛福唐。',64,'全唐诗/poet.song.84000.json','["春燈絕勝百花芳，元夕紛華盛福唐。", "銀燭燒空排麗景，鼇山聳處觀祥光。", "管絃喧夜千秋歲，羅綺填街百和香。", "欲識神君行樂意，姑循前哲事祈禳。"]'),
('7c74c2a1-0e59-46ad-972f-1c037c082c9a','對菊懷陸子靜','鄭建古','宋','宋诗','song-poetry','','[]','落落薌城二老翁，白鬚遙映菊英中。',64,'全唐诗/poet.song.84000.json','["落落薌城二老翁，白鬚遙映菊英中。", "交成晚節人彌淡，吟到寒花句亦工。", "灌溉已欣分綺色，扶持還藉挹芳叢。", "吾徒素愛凌霜質，相對應知臭味同。"]'),
('6f6023e7-9fe9-4088-8ad7-c164207f2a36','游休休亭','鄭集','宋','宋诗','song-poetry','','[]','世事心知不可爲，拂衣歸此養天機。',32,'全唐诗/poet.song.84000.json','["世事心知不可爲，拂衣歸此養天機。", "先生獨善端無意，肯續春秋辨是非。"]'),
('6e8c7b33-db82-447d-8a07-7b84930b5be2','咏栖雲洞','余光庭','宋','宋诗','song-poetry','','[]','去住無心洞裏雲，雲窩寂寞宿氤氳。',32,'全唐诗/poet.song.84000.json','["去住無心洞裏雲，雲窩寂寞宿氤氳。", "遙知此勝非凡匹，澗水巖花香異聞。"]'),
('f73ce5bc-e595-4d10-80ba-020b5f32af98','句','董剛','宋','宋诗','song-poetry','','[]','郡爲三蜀蔽，地與兩京通。',12,'全唐诗/poet.song.84000.json','["郡爲三蜀蔽，地與兩京通。"]'),
('67369477-a296-4e4e-b61a-ba9364397f1b','題七星巖','宋逑','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三四奇峰傍短亭，一巖春色冠圖經。',64,'全唐诗/poet.song.84000.json','["三四奇峰傍短亭，一巖春色冠圖經。", "四時吞吐西江水，萬古森羅北斗星。", "日月餘輝通□□，□霞微徑上青冥。", "嶺南惟此興王地，好與邦人作畫屏。"]'),
('d975614c-762e-4683-9ab2-c2fec7b6ad18','挽李方叔','郭挺','宋','宋诗','song-poetry','','[]','憔悴詞林失俊英，已應精爽在蓬瀛。',64,'全唐诗/poet.song.84000.json','["憔悴詞林失俊英，已應精爽在蓬瀛。", "楷模昔日依元禮，貧病他年累長卿。", "無復波瀾窺大手，空將日月送虛名。", "當時潁曲爲耕地，祇有風灘晝夜聲。"]'),
('2893ea6d-3f5a-47c9-8ba2-3eec055e9069','挽李方叔','趙善𡨢','宋','宋诗','song-poetry','','[]','藤崖羅邁等蒼龍，踵洞寒噴江海通。',64,'全唐诗/poet.song.84000.json','["藤崖羅邁等蒼龍，踵洞寒噴江海通。", "幾萬重峰團碧色，百千級雪下青空。", "塵埃世界深山北，今古是非流水東。", "筇杖平頭天地闊，醉他白日立清風。"]'),
('0a4fffaf-adef-47d9-8790-5f5c6848d96a','游大滌  其一','趙善䚮','宋','宋诗','song-poetry','','[]','黄簾有影金燈暗，碧殿無人玉磬清。',32,'全唐诗/poet.song.84000.json','["黄簾有影金燈暗，碧殿無人玉磬清。", "我亦三生羽衣客，夢魂久已到瑤京。"]'),
('ffcad803-74a7-4a52-8cbd-26ac8acd89f5','游大滌  其二','趙善䚮','宋','宋诗','song-poetry','','[]','雲葩裛石侵衣潤，嵐翠籠山入眼明。',32,'全唐诗/poet.song.84000.json','["雲葩裛石侵衣潤，嵐翠籠山入眼明。", "何處如今有仙隱，願尋藥圃斸玄英。"]'),
('7d459551-b2a2-4848-9d89-c02d8cdbb39c','題岑公洞','趙善贛','宋','宋诗','song-poetry','','[]','真人邈何之，恍忽不可見。',120,'全唐诗/poet.song.84000.json','["真人邈何之，恍忽不可見。", "洞居獨嵌空，壁留明珠濺。", "藤蘿含冥濛，竹柏鬬葱蒨。", "至幽合人心，遠翠落江面。", "野老乘籃輿，使君肆清燕。", "日影砌下倒，雲容坐間變。", "大木巖欲傾，邃壑路微轉。", "崢嶸施屏風，點綴成彩絢。", "雖云急行樂，勝賞殆亦遍。", "欲歸重盤旋，拂石看古篆。"]'),
('bd7e49e2-90c6-42cd-95a7-73ba6cd3d5ab','京口多景樓','趙善倫','宋','宋诗','song-poetry','','[]','壯觀東南二百州，景於多處更多愁。',64,'全唐诗/poet.song.84000.json','["壯觀東南二百州，景於多處更多愁。", "江流千古英雄淚，山掩諸公富貴羞。", "北府如今唯有酒，中原在望忍登樓。", "西風戰艦今何在，且辦年年使客舟。"]'),
('15b840ef-433b-42bc-8211-dca909d04cc4','題翠蛟亭','趙善革','宋','宋诗','song-poetry','','[]','未到康廬看玉淵，且來大滌掬飛泉。',32,'全唐诗/poet.song.84000.json','["未到康廬看玉淵，且來大滌掬飛泉。", "決流放閘雖人力，濺玉跳珠卻自然。"]'),
('9b759fc6-fdcb-4aee-a7f0-6e1347fe4b4e','大滌洞  其一','趙善革','宋','宋诗','song-poetry','','[]','敲撐振策上嶙峋，亂石逢迎領略頻。',64,'全唐诗/poet.song.84000.json','["敲撐振策上嶙峋，亂石逢迎領略頻。", "風竇靜吟吹地籟，澗泉高瀉曳天紳。", "雲山勝景身無累，觴詠清懷筆有神。", "殘夢驚回三十歲，瑯玕芝草一時新。"]'),
('73481561-424e-4de9-83c5-11e793836e98','大滌洞  其二','趙善革','宋','宋诗','song-poetry','','[]','舊游風物轉頭非，只有青山不改移。',64,'全唐诗/poet.song.84000.json','["舊游風物轉頭非，只有青山不改移。", "深壑貯風馴虎嘯，斷崖飛瀑翠蛟馳。", "郭翁遺迹雲煙鎖，坡老清名草木知。", "笑問聚仙亭上月，風流應不減當時。"]'),
('77b92aac-ca80-4a10-9fca-ba9509712444','大滌洞  其三','趙善革','宋','宋诗','song-poetry','','[]','冠蓋初收見在身，來尋大滌滌塵氛。',64,'全唐诗/poet.song.84000.json','["冠蓋初收見在身，來尋大滌滌塵氛。", "心如霜後凌虛月，迹是風前出岫雲。", "仙姥定能賒甕酒，華堂小憩看爐熏。", "甚思屏置人間事，韜養巖間霧雨文。"]'),
('4be21a2d-a14b-4fb0-9130-8a392fbdbf26','大滌洞  其一','槻伯圜','宋','宋诗','song-poetry','','[]','洞霄問路覓青梯，尚恐巖阿有勒移。',64,'全唐诗/poet.song.84000.json','["洞霄問路覓青梯，尚恐巖阿有勒移。", "暫許尋山留信宿，何由稅駕息驅馳。", "七仙不死今仍在，五洞交扃昔所知。", "信有靈丹藏箬下，刀圭分乞豈無時。"]'),
('809975df-005b-4023-80f9-465ced0decdd','大滌洞  其二','槻伯圜','宋','宋诗','song-poetry','','[]','飛餉江淮脫此身，聊尋九鎖浣兵氛。',64,'全唐诗/poet.song.84000.json','["飛餉江淮脫此身，聊尋九鎖浣兵氛。", "笑呼天柱峰前月，共踏棲真洞裏雲。", "陰谷神泉霜後王，陽坡靈草雨餘薰。", "十年洗髓除凡骨，儻契仙翁邁與文。"]'),
('ee1d7d99-a304-4798-98aa-03085c9db281','大滌洞  其三','槻伯圜','宋','宋诗','song-poetry','','[]','餘杭曉旆籋飛梯，大滌松陰午未移。',64,'全唐诗/poet.song.84000.json','["餘杭曉旆籋飛梯，大滌松陰午未移。", "羣從追隨巾屨集，衆真參會珮環馳。", "白鴉翻舞仙如在，黄鶴迎來聖得知。", "老□□□□□□，□□□□□□□。"]'),
('0ec788ae-ea5c-4c59-93d4-5ba71e93ae74','大滌洞  其四','槻伯圜','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.song.84000.json','["□□□□□□□，□□□□□□□。", "□□□□□□□，捲壑飛泉日夜馳。", "龍蛻洞深神所蟄，鳳鳴巖隱世誰知。", "坡仙一去無消息，相見清游彼一時。"]'),
('eaf62e3d-4ed0-48c2-8fb0-7a625e556535','大滌洞  其五','槻伯圜','宋','宋诗','song-poetry','','[]','快上籃輿曉色分，松風滿袂滌埃氛。',64,'全唐诗/poet.song.84000.json','["快上籃輿曉色分，松風滿袂滌埃氛。", "三竿未放高峰日，一笑先開洞府雲。", "憶昔曾留天帝坐，至今猶带御爐薰。", "莫教俗駕來相尾，只恐詒譏晉郭文。"]'),
('5a46e2a3-e766-453e-a63e-8eea004bc70c','大滌洞  其六','槻伯圜','宋','宋诗','song-poetry','','[]','人間安得倚天梯，欲訪真源志不移。',64,'全唐诗/poet.song.84000.json','["人間安得倚天梯，欲訪真源志不移。", "大滌乃今追勝迹，清都何待更神馳。", "已逃蕭斧杉難老，不逐秦鞭石有知。", "尚覺林泉佳氣王，難忘羽衛幸臨時。"]'),
('1b181947-b370-4bcb-aa4a-dba8a745d83d','大滌洞  其七','槻伯圜','宋','宋诗','song-poetry','','[]','松筠玉美育見長身，瓊館沉沉遠楚氛。',65,'全唐诗/poet.song.84000.json','["松筠玉美育見長身，瓊館沉沉遠楚氛。", "裂石看傾三峽雪，解衣同試一甌雲。", "朮畦曉露初收藥，蘭徑秋風靜吐薰。", "爲拂蒼崖題歲月，重來應復感斯文。"]'),
('2b7e2cf4-7f8e-4482-9d23-8f6e4d80ea54','句  其一','王才元','宋','宋诗','song-poetry','','[]','雪曳山容改。',6,'全唐诗/poet.song.84000.json','["雪曳山容改。"]'),
('c525f0bd-c244-41aa-86b0-5e86d8b2aa50','句  其二','王才元','宋','宋诗','song-poetry','','[]','遠墅炊煙近。',6,'全唐诗/poet.song.84000.json','["遠墅炊煙近。"]'),
('5be1268a-9c84-4cb0-9beb-245f2251b3c6','寄弟子慧山偈','釋道瓊','宋','宋诗','song-poetry','','[]','口觜不中祥老子，愛向叢林鼓是非。',32,'全唐诗/poet.song.84000.json','["口觜不中祥老子，愛向叢林鼓是非。", "分付雪峰山首座，爲吾痛罵莫饒伊。"]'),
('7ac57b13-0e57-43d0-8663-049006bc71f1','頌古二首  其一','釋道瓊','宋','宋诗','song-poetry','','[]','掩耳不及忽雷奔，天低尺五雨傾盆。',32,'全唐诗/poet.song.84000.json','["掩耳不及忽雷奔，天低尺五雨傾盆。", "葉隨流水歸何處，牛带寒鴉過別村。"]'),
('142affa7-29f4-49b2-85d0-f83f3f7ecf3c','頌古二首  其二','釋道瓊','宋','宋诗','song-poetry','','[]','捨筏懷兼濟，逢耕更問津。',24,'全唐诗/poet.song.84000.json','["捨筏懷兼濟，逢耕更問津。", "卻將未歸意，說與欲行人。"]'),
('836f2c0e-fe64-4fa3-96a4-2ead55c0a000','呈芙蓉楷禪師','高世則','宋','宋诗','song-poetry','','[]','懸崖撒手任縱橫，大地虛空自坦平。',32,'全唐诗/poet.song.84000.json','["懸崖撒手任縱橫，大地虛空自坦平。", "照壑輝巖上借月，庵頭別有一簾明。"]'),
('040c29da-a323-4390-8224-92041bc7140c','偈','釋法如','宋','宋诗','song-poetry','','[]','乾坤之內，宇宙之間。',20,'全唐诗/poet.song.84000.json','["乾坤之內，宇宙之間。", "中有一寶，秘在形山。"]'),
('2e8dfd79-cbd8-4340-9e82-4c50e739d899','偈三首  其一','釋介諶','宋','宋诗','song-poetry','','[]','出西天，入東土。',23,'全唐诗/poet.song.84000.json','["出西天，入東土。", "雲從龍，風從虎。", "一任諸方點頭。"]'),
('ed3778c3-3d50-406f-b344-fc46c2a74186','偈三首  其二','釋介諶','宋','宋诗','song-poetry','','[]','文殊智，普賢行，多年曆日。',26,'全唐诗/poet.song.84000.json','["文殊智，普賢行，多年曆日。", "德山棒，臨濟喝，亂世英雄。"]'),
('7bbe5cec-4d8c-460c-be0f-b46bdb6a9aa3','偈三首  其三','釋介諶','宋','宋诗','song-poetry','','[]','我若說有，你爲有礙。',61,'全唐诗/poet.song.84000.json','["我若說有，你爲有礙。", "我若說無，你爲無礙。", "我若橫說，你又跨不過。", "我若竪說，你又跳不出。", "若欲叢林平貼，大家無事，不如推倒育王。"]'),
('770970be-2f44-4dfb-a40e-fe12033359ab','偈二首  其一','釋慧琳','宋','宋诗','song-poetry','','[]','有漏笊漓，無漏木杓。',36,'全唐诗/poet.song.84000.json','["有漏笊漓，無漏木杓。", "庭白牡丹，檻紅芍藥。", "因思九年面壁人，到頭不識這一著。"]'),
('e4c2db5c-9055-445b-9f28-6307dc64ab1a','偈二首  其二','釋慧琳','宋','宋诗','song-poetry','','[]','一即多，多即一，毗盧頂上明如日。',48,'全唐诗/poet.song.84000.json','["一即多，多即一，毗盧頂上明如日。", "也無一，也無多，現成公案沒殽訛。", "拈起舊來氈拍板，明時共唱太平歌。"]'),
('6ba4bb3f-7a58-451c-a023-880d3e9c0cbd','頌古二首  其一','釋慧琳','宋','宋诗','song-poetry','','[]','五鳳樓脫問洛陽，金鞭遙指御街長。',32,'全唐诗/poet.song.84000.json','["五鳳樓脫問洛陽，金鞭遙指御街長。", "春風是處華爭發，游子年年憶故鄉。"]'),
('10c5f4f4-f1a0-4efb-9074-c9bb691c14de','頌古二首  其二','釋慧琳','宋','宋诗','song-poetry','','[]','赤體更無藏隱處，黄龍未語先分付。',32,'全唐诗/poet.song.84000.json','["赤體更無藏隱處，黄龍未語先分付。", "若將見解上門來，他家自有通霄路。"]'),
('91597556-5ed0-4bd6-b5ee-05f1df86ada6','呈泐潭草堂清禪師偈三首  其一','本明道人','宋','宋诗','song-poetry','','[]','不識煩惱是菩提，若隨煩惱是愚癡。',32,'全唐诗/poet.song.84000.json','["不識煩惱是菩提，若隨煩惱是愚癡。", "起滅之時須要會，鷂過新羅人不知。"]'),
('e1482700-3f42-4a85-8513-0a52bbd2f451','呈泐潭草堂清禪師偈三首  其二','本明道人','宋','宋诗','song-poetry','','[]','不識煩惱是菩提，凈華生淤泥。',31,'全唐诗/poet.song.84000.json','["不識煩惱是菩提，凈華生淤泥。", "人來問我若何爲，喫粥喫飯了洗鉢盂。"]'),
('b093ee62-d166-420e-8142-7ed31c6d6226','呈泐潭草堂清禪師偈三首  其三','本明道人','宋','宋诗','song-poetry','','[]','莫管他，莫管他，終日癡憨筭海沙。',32,'全唐诗/poet.song.84000.json','["莫管他，莫管他，終日癡憨筭海沙。", "要識本來真面目，便是祖師一木叉。"]'),
('27d1a33d-6706-4d95-be0e-ce58e70ca4d9','偈','釋圓智','宋','宋诗','song-poetry','','[]','蘆華白，蓼華紅，溪邊脩竹碧煙籠。',44,'全唐诗/poet.song.84000.json','["蘆華白，蓼華紅，溪邊脩竹碧煙籠。", "閑雲抱幽石，玉露滴巖叢。", "昨夜烏龜變作鱉，今朝水牯悟圓通。"]'),
('55502153-5c5b-4cc3-8b4c-a6a0edd49652','偈','釋良範','宋','宋诗','song-poetry','','[]','塵劫已前事，堂堂無背面。',70,'全唐诗/poet.song.84000.json','["塵劫已前事，堂堂無背面。", "動靜莫能該，舒卷快如電。", "莫道凡不知，佛也覷不見。", "決定在何處，合取這兩片。", "薦不薦，更爲諸人通一線。", "天下太平，皇風永扇。"]'),
('ec5d29a5-8815-4409-9551-8f7f80f7b097','竹枝辭','李邦獻','宋','宋诗','song-poetry','','[]','江上漁舟葉葉輕，峽中雲雨晚涼生。',32,'全唐诗/poet.song.84000.json','["江上漁舟葉葉輕，峽中雲雨晚涼生。", "長亭宴罷客歸去，桂樹夕陽啼鳥聲。"]'),
('bc646a8d-95cb-44e1-99af-ea083c92c289','過仙都徐氏山居  其一','李邦獻','宋','宋诗','song-poetry','','[]','道出仙都下，溪深草木閑。',48,'全唐诗/poet.song.84000.json','["道出仙都下，溪深草木閑。", "陰晴老農事，豐稔此心關。", "誰削千尋石，雲藏萬疊山。", "王程元有限，那得更躋攀。"]'),
('132839fc-7f0b-4f97-b69c-65fda61cd200','過仙都徐氏山居  其二','李邦獻','宋','宋诗','song-poetry','','[]','四海無塵戰馬閑，稻梁桑柘綠回環。',32,'全唐诗/poet.song.84000.json','["四海無塵戰馬閑，稻梁桑柘綠回環。", "不知盡是君王力，華屋重重對好山。"]'),
('e60cc744-ea5b-4221-99bc-be5a3a4abc6f','仁壽堂古梅','李邦獻','宋','宋诗','song-poetry','','[]','手種黄梅已着花，此身依舊在天涯。',32,'全唐诗/poet.song.84000.json','["手種黄梅已着花，此身依舊在天涯。", "三年客罷攜家去，贏得東風兩鬢華。"]'),
('593ae05c-9d01-467f-8b2a-60ea410e0b9d','馬王廟','李邦獻','宋','宋诗','song-poetry','','[]','矍鑠茲翁老莫量，據鞍猶得亞燕揚。',64,'全唐诗/poet.song.84000.json','["矍鑠茲翁老莫量，據鞍猶得亞燕揚。", "能將岸幘窺文叔，祇把虛蛙當子陽。", "薏苡滿車翻作禍，馬人上日竟成行。", "三瀧廟食傳千古，回首雲臺草樹荒。"]'),
('9bf728b2-65a1-423c-81dd-567b5cc5478f','寄鶴林辛上人','蘇莊','宋','宋诗','song-poetry','','[]','苦憶長廊清磬音，復懷贊公栴檀林。',64,'全唐诗/poet.song.84000.json','["苦憶長廊清磬音，復懷贊公栴檀林。", "陽坡佳木鳥相喚，澗戶曉行藤竹陰。", "日晴山路筍橛晚，雨足野塘蒲稗深。", "短褐兀然聊戲劇，滄江鷗鷺本無心。"]'),
('8f49c437-7896-4354-87f0-df0710ef65a4','小齋即事二首  其一','劉一止','宋','宋诗','song-poetry','','[]','憐琴爲絃直，愛棋因局方。',48,'全唐诗/poet.song.84000.json','["憐琴爲絃直，愛棋因局方。", "未用較得失，那能記宮商。", "我老世愈疏，一拙萬事妨。", "惟此二物随，不係有興亡。"]'),
('1bd98882-9dd2-4f87-941d-e16d02dce6e4','小齋即事二首  其二','劉一止','宋','宋诗','song-poetry','','[]','旱夏甘雨零，坐見草木長。',48,'全唐诗/poet.song.84000.json','["旱夏甘雨零，坐見草木長。", "天憐官窮隘，乞與風颯爽。", "四簷溜通池，激激聽微響。", "雖非山林間，故作山林想。"]'),
('0c9183d6-7f63-42f3-bac3-6cd124c7563f','道中雜興五首  其一','劉一止','宋','宋诗','song-poetry','','[]','瀕春欲生妍，梅蘂先媚好。',36,'全唐诗/poet.song.84000.json','["瀕春欲生妍，梅蘂先媚好。", "寧辭犯霜雪，漸擬蘇百草。", "耿耿甘獨待，餘恩及枯槁。"]'),
('241e1235-05d0-41db-a508-6ec4601e1466','道中雜興五首  其二','劉一止','宋','宋诗','song-poetry','','[]','姚黄花中君，芍藥乃近侍。',36,'全唐诗/poet.song.84000.json','["姚黄花中君，芍藥乃近侍。", "我嘗品江梅，真是花御史。", "不見雪霜中，炯炯但孤峙。"]'),
('d9beb810-1bbf-48e1-a6bc-dfbf228effdb','道中雜興五首  其三','劉一止','宋','宋诗','song-poetry','','[]','晴風掃頑雲，白日光在地。',36,'全唐诗/poet.song.84000.json','["晴風掃頑雲，白日光在地。", "雲翳無幾何，聚散等懸寄。", "所以寸草心，各各抱根蒂。"]'),
('a02a12b1-204b-4fc3-a251-330abe39216c','道中雜興五首  其四','劉一止','宋','宋诗','song-poetry','','[]','麥頭漸青青，麥田何井井。',36,'全唐诗/poet.song.84000.json','["麥頭漸青青，麥田何井井。", "黄雲被原野，衆草昏未醒。", "方知天壤間，春風有畦畛。"]'),
('96a5f279-370a-4eaf-a32c-8f3741660bea','道中雜興五首  其五','劉一止','宋','宋诗','song-poetry','','[]','長亭連短亭，隻堠復雙堠。',36,'全唐诗/poet.song.84000.json','["長亭連短亭，隻堠復雙堠。", "居然送行客，歷歷記奔走。", "十里同五里，先後無好醜。"]'),
('ba814392-c477-4e4c-be2f-8b893d212928','識舟亭一首','劉一止','宋','宋诗','song-poetry','','[]','渺渺歸帆江北渚，脉脉相望那得語。',64,'全唐诗/poet.song.84000.json','["渺渺歸帆江北渚，脉脉相望那得語。", "舟中賈客嬋娟女，朝樂瀟湘暮荆楚。", "我欲招之問計然，浮名唾去如飄烟。", "買魚沽酒嘯儔侣，槌鼓弄笛凋殘年。"]'),
('b89f977d-70ab-4d91-9add-1dd2e9cf77bc','過新開湖呈無言兄御史','劉一止','宋','宋诗','song-poetry','','[]','整整斜斜村舍居，十十五五沙中鳬。',64,'全唐诗/poet.song.84000.json','["整整斜斜村舍居，十十五五沙中鳬。", "潛魚釣影水深淺，高柳着行烟有無。", "天闊雲低過平楚，已覺淮音近吳語。", "淮南米賤好留儂，正恐不歸心更苦。"]'),
('f6841c0c-ed5e-43a9-8ba0-daade91a9689','腰鎌一首','劉一止','宋','宋诗','song-poetry','','[]','腰鎌行稻區，引挽親刈熟。',192,'全唐诗/poet.song.84000.json','["腰鎌行稻區，引挽親刈熟。", "黄雲卧千頃，彌望極平陸。", "潦水秋未收，褰裳聽滿足。", "爲士復兼農，自身仍當僕。", "書年賀豐稔，天事誠委曲。", "辛苦豈敢辭，幸此卒歲蓄。", "歸來妻孥笑，風日緇面目。", "未覺城市胜，生理係斗斛。", "少年事筆耕，初不辨穜稑。", "讀書舌本燥，得食僅半菽。", "人言清有餘，自哂瘦如竹。", "虚名真畫餅，逸景等轉燭。", "今我更百態，漸已不諱俗。", "杯水重萬言，嚢錢踰滿腹。", "却嗤祖士少，未免懷愧恧。", "客來詎相訪，底用身障簏。"]'),
('cc682202-5b5b-4bc8-86de-32da7df9b13c','無言兄以銀壺作粥糜頗極其妙舟居夜饑頃刻可辦戲作此詩','劉一止','宋','宋诗','song-poetry','','[]','少年愛酒不廢沽，滑稽鴟夷每随車。',208,'全唐诗/poet.song.84000.json','["少年愛酒不廢沽，滑稽鴟夷每随車。", "春禽似是知我意，日日勸我提葫蘆。", "侵尋老境筋力異，宿昔百嗜今一無。", "羈窮未免走四方，是口時賴薄粥餬。", "憐君巧作此瓢壺，善爲口計真不疏。", "上蓋下豐腹胍𦘴，空洞可置升米餘。", "釜湯外沸如隔膜，氣塞不作聲盧胡。", "須臾已復成淖糜，勻滑不減傾醍醐。", "篷窗夜饑急星火，咄嗟而辦功可書。", "山僧歙鉢未足詫，考父古鼎非時須。", "我聞壺中有高隱，日月或類蓬萊居。", "神仙有無事恍惚，山澤形貌常多臞。", "不如一飽睡清熟，個中便是真華胥。"]'),
('a414dcd3-82d6-463b-a3c8-125daa44916f','盧駿元憲使寄示會稽競秀閣識舟亭二詩爲各賦一首  其一','劉一止','宋','宋诗','song-poetry','','[]','葱籠秀擁秦山落，盡日春風吹嶺脚。',64,'全唐诗/poet.song.84000.json','["葱籠秀擁秦山落，盡日春風吹嶺脚。", "朝來領略到窗几，誰遣虚空出阿閣。", "南臺御史去天近，身與孤雲生兩角。", "胸中摸索千丈絃，更恐并吞有衡霍。"]'),
('86b43fa7-4412-4177-a8f9-3ba4f65f25a0','盧駿元憲使寄示會稽競秀閣識舟亭二詩爲各賦一首  其二','劉一止','宋','宋诗','song-poetry','','[]','海門山邊初落潮，西興渡口浪痕高。',64,'全唐诗/poet.song.84000.json','["海門山邊初落潮，西興渡口浪痕高。", "渺渺目亂翻雲濤，心識不語迎歸橈。", "江亭晚日風蕭騷，軋啞鳴櫓相向搖。", "平頭鴈落沙沒腰，舟人底處尋青招。"]'),
('b2303a14-9e2e-43a2-8ba1-6c0be2632b24','天長道中作饑來驅我去二首寄呈劉盧二御史  其一','劉一止','宋','宋诗','song-poetry','','[]','饑來驅我去，去去復何之。',96,'全唐诗/poet.song.84000.json','["饑來驅我去，去去復何之。", "西風迎馬頭，背日霜林披。", "十年京洛塵，衣弊因改爲。", "豈惟衣日化，面目亦已緇。", "功名誤少小，辛苦道老黧。", "追惟中自驚，恍聲失旦鷄。", "安得如虚空，萬境俱一齊。", "我心無去來，我馬随東西。"]'),
('1d7a67d8-c46f-47c9-ba5b-e389595dc0e3','天長道中作饑來驅我去二首寄呈劉盧二御史  其二','劉一止','宋','宋诗','song-poetry','','[]','饑來驅我去，去去復何如。',132,'全唐诗/poet.song.84000.json','["饑來驅我去，去去復何如。", "我饑亦何慚，所歎爲此軀。", "明發着征衫，薄暮投郊墟。", "烟林號怒風，牛背立饑烏。", "境惡夢多悸，愁孤鬰難舒。", "念初別鄉邦，短檝穿菰蘆。", "眼中兩御史，炯炯冰在壺。", "清游失追攀，負此山繞湖。", "我行日已西，回首風牽裾。", "兩公飫文章，筆端吐新腴。", "願言繼殘膏，龜腸正空虛。"]'),
('beed9f3a-0ea9-4e87-b906-c5f442fdcd13','拱州道中二首  其一','劉一止','宋','宋诗','song-poetry','','[]','城樓百尺兀相望，帝作東輔拱神州。',32,'全唐诗/poet.song.84000.json','["城樓百尺兀相望，帝作東輔拱神州。", "當日隋家漕渠柳，至今春在末梢頭。"]'),
('e176eef2-f4b7-439f-9b4f-79fc3ce0a6b1','拱州道中二首  其二','劉一止','宋','宋诗','song-poetry','','[]','柳條明媚欲變色，便想春思浩無涯。',32,'全唐诗/poet.song.84000.json','["柳條明媚欲變色，便想春思浩無涯。", "行人手挽不忍斷，云此生意方萌芽。"]'),
('61e13f6d-25b7-4e9e-9aa1-58fe14220dc8','家姪季高作詩止酒戲賦二首  其一','劉一止','宋','宋诗','song-poetry','','[]','淵明出從任，初亦計林田。',120,'全唐诗/poet.song.84000.json','["淵明出從任，初亦計林田。", "一朝倦束带，唾棄如飄烟。", "無酒每從人，兹事若可憐。", "醉來便逐客，卿去我欲眠。", "了知此賢胸，醒醉皆超然。", "胡爲遽止酒，而作止酒篇。", "此身役萬物，不使一物偏。", "有偏即是累，在性皆非圓。", "我樽可忘酒，我琴故無絃。", "攜琴玩空樽，惟我樂也天。"]'),
('f4535e18-4e0d-45f6-bea6-8193f3214785','家姪季高作詩止酒戲賦二首  其二','劉一止','宋','宋诗','song-poetry','','[]','淵明賦止酒，止酒未嘗止。',156,'全唐诗/poet.song.84000.json','["淵明賦止酒，止酒未嘗止。", "今朝詩固云，從此真止矣。", "我觀他日詩，說酒特未已。", "必飲誠有累，必止亦非理。", "無如作病何，聊用忘憂耳。", "得失定相半，随遇無彼此。", "胡爲我阿咸，深拒堅壁壘。", "子言故多師，烏有與亡是。", "獨此止酒詩，字字如信史。", "恐子昧圓通，未究真正義。", "當觀諸世間，一一等幻戲。", "死生尚云爾，何乃較醒醉。", "操瓢起相從，無爲乏我事。"]'),
('a5c9307e-3bfc-40e7-a503-fc7978aeb201','方時敏寄和詩復用韻報之并簡季高理前止酒之語季高嘗夢蕭相國戒勿飲酒  其一','劉一止','宋','宋诗','song-poetry','','[]','疇昔城南隅，蓮葉秋田田。',120,'全唐诗/poet.song.84000.json','["疇昔城南隅，蓮葉秋田田。", "從公觴玉醪，醉墨看雲烟。", "我乃世背馳，公獨肯顧憐。", "追思十年夢，僅熟一覺眠。", "念當老扁舟，生理師計然。", "不意菰蘆中，復見瓊瑤篇。", "筆力如置陣，彌縫認先偏。", "從容步武間，左右方若圓。", "又如清廟音，三歎聞疏絃。", "安得化爲雲，追逐飛上天。"]'),
('5fecfbbc-c66b-419d-a592-681c824eb406','方時敏寄和詩復用韻報之并簡季高理前止酒之語季高嘗夢蕭相國戒勿飲酒  其二','劉一止','宋','宋诗','song-poetry','','[]','阮籍劉伯倫，嗜酒不知止。',156,'全唐诗/poet.song.84000.json','["阮籍劉伯倫，嗜酒不知止。", "顛狂欲求名，此計真陋矣。", "酒中有何好，正自未能已。", "愁來得暫驅，洞若適妙理。", "我豈沈酣徒，公亦聊爾耳。", "世間等夢間，未悟彼易此。", "阿高志得殊，家學自中壘。", "嗷嗷求獨醒，今昨較非是。", "無心窮酒聖，有意造詩史。", "自言古鄼侯，告戒存密義。", "逡巡若神授，恍惚類兒戲。", "不須更論酒，春夢本如醉。", "我知昴星精，不管太白事。"]'),
('eabd0bbf-8a8a-420a-a68e-62a2a1bd9407','次韻趙端直貽何子楚卜居山間二絕句  其一','劉一止','宋','宋诗','song-poetry','','[]','賀老晚乞一曲湖，絕勝叔平千頭奴。',32,'全唐诗/poet.song.84000.json','["賀老晚乞一曲湖，絕勝叔平千頭奴。", "端直自是功名人，未用早計此索居。"]'),
('d13b3020-ed9a-4047-9215-554700dd3752','次韻趙端直貽何子楚卜居山間二絕句  其二','劉一止','宋','宋诗','song-poetry','','[]','後堂彈絲嬌不止，知有性靈雙婢子。',32,'全唐诗/poet.song.84000.json','["後堂彈絲嬌不止，知有性靈雙婢子。", "歌詞自製清如水，却怪驚塵暗中起。"]'),
('3e8eec13-c267-4c66-b9ad-27583230d2c0','次韻子楚秀才  其一','劉一止','宋','宋诗','song-poetry','','[]','何郎卜築吞江湖，下瞰培塿皆僕奴。',32,'全唐诗/poet.song.84000.json','["何郎卜築吞江湖，下瞰培塿皆僕奴。", "山川勝絕本相假，正復此士堪此居。"]'),
('7c96c68c-69f3-4ecf-a4b5-1d3f6a499e3e','次韻子楚秀才  其二','劉一止','宋','宋诗','song-poetry','','[]','何郎歸歟直止止，所恨扁舟欠西子。',32,'全唐诗/poet.song.84000.json','["何郎歸歟直止止，所恨扁舟欠西子。", "山高日長貪睡美，不有江聲誰喚起。"]'),
('f7f45d96-cb5d-450c-91d4-54b5500328ca','贈道人王生一首','劉一止','宋','宋诗','song-poetry','','[]','夜來清商入梧桐，策策不已鳴霜風。',128,'全唐诗/poet.song.84000.json','["夜來清商入梧桐，策策不已鳴霜風。", "故烟一碧萬烟樹，惨淡已有傷秋容。", "嗟哉造物本何意，安得永賴長養功。", "我獨冷眼閱榮悴，心與日出清霜融。", "子奚不來助我喜，甕頭春風生麴米。", "人間有酒誰不醉，知其天者我與子。", "我身雖無雙羽翰，欲将夢到三神山。", "借爾八尺龍鬚席，蘧然一覺俱飛還。"]'),
('dfb09a77-b392-4c02-9f7b-e7c173a8b49b','家弟元成將參部來取別是夕忽夢與元成跨馬並行隱隱聞車轂聲如在道途覺而作詩并以贈行','劉一止','宋','宋诗','song-poetry','','[]','荒凉半畝居，風烟夜沈沈。',132,'全唐诗/poet.song.84000.json','["荒凉半畝居，風烟夜沈沈。", "安得清夢間，尚有車轂音。", "自我客京華，半世歷嶔嶔。", "日月不相貸，鬢有微霜侵。", "騎馬著青衫，兹事已不任。", "如何棲遲中，心跡猶差参。", "夢境通前生，染習良已深。", "歲月不可磨，愈厲如精金。", "富貴豈足道，大是功名心。", "勉哉子馳驅，壮志方在今。", "力學懶似儂，膏肓恐難鍼。"]'),
('f117a9f3-c082-4f32-83da-347cc1c175b1','次韻寄酬無言兄頒政二章  其一','劉一止','宋','宋诗','song-poetry','','[]','鳳不出丹穴，姬孔歎且思。',168,'全唐诗/poet.song.84000.json','["鳳不出丹穴，姬孔歎且思。", "忽來乃爲時，不計身安危。", "采色炫世眼，鳴聲漏天機。", "高梧寄孤巢，俯仰反自悲。", "矧復鷃雀儔，妒喘如筒吹。", "我知盛名下，憂惙甚井眉。", "寵辱更事耳，何異秦晉饑。", "生身等世間，寧免相貸資。", "公乎豈人謀，天特相兹時。", "奈何不自量，徑欲力撼之。", "如我實助喜，良是昔所期。", "蜀牋冰不如，忽枉灑蘭辭。", "三復重太息，無術可肉飛。", "要看筆如椽，塗改生民詩。"]'),
('d889527c-e5d5-4c21-8e3b-993191ef5336','次韻寄酬無言兄頒政二章  其二','劉一止','宋','宋诗','song-poetry','','[]','自公之出矣，豈不旦夕思。',168,'全唐诗/poet.song.84000.json','["自公之出矣，豈不旦夕思。", "人情劇險艱，太行未足危。", "十年江湖心，鷗鳥識忘機。", "却來鵷鷺行，方寸交喜悲。", "晚被天語溫，習如和風吹。", "凡公宿昔交，誰不勝兩眉。", "如我故陸沈，筆耕遇比饑。", "胸腹抱介介，何以取世資。", "時哉今唐虞，不出斯無時。", "苕之水洋洋，我饑實樂之。", "如何磊落人，頗復誤見期。", "誰能叩人門，受彼在亡辭。", "吸飲風露寒，身輕會孤飛。", "明時自嗟拙，敢賦衡門詩。"]'),
('7d5d4e77-6689-4086-9189-ccc81fab40c7','與家姪季高夜語用毛內相韻','劉一止','宋','宋诗','song-poetry','','[]','儒生習氣非偶然，出入文史東西家。',160,'全唐诗/poet.song.84000.json','["儒生習氣非偶然，出入文史東西家。", "掃除凈盡如宿草，春風一夕已復芽。", "子方妙年有奇氣，我已種種成蒼華。", "文章百巧坐一窮，無地可學東陵瓜。", "擩嚌山色吞湖光，凜凛尚可驅百邪。", "子昔自云有仙骨，夢騎青螭籋飛霞。", "要與李杜高頡頏，下視餘子窘可嗟。", "寒燈夜語耿不寐，似覺冰雪生齒牙。", "頗言室有法喜妻，幸是元無翁可撾。", "何如從吾巢雲巔，共訪葛洪學丹砂。"]'),
('eb856e9d-4acb-4296-bc18-58e40e5d162d','贈別歸安周縣丞二首  其一','劉一止','宋','宋诗','song-poetry','','[]','自我居里間，連墻絕未去。',204,'全唐诗/poet.song.84000.json','["自我居里間，連墻絕未去。", "非我敢杜門，客實莫我顧。", "頽然坐空廬，習懶已成痼。", "惟有一束書，遮眼慰遲暮。", "周郎來何許，文字得我怖。", "淵源笑鯢桓，采色隱豹霧。", "追随古河洲，山色入幽步。", "詩文互徴逐，酒鸞及時具。", "如我衆棄餘，君意獨何慕。", "入蘭不知芳，逐臭無乃誤。", "君亦忘機人，足跡亂鷗鷺。", "堂前種白蓮，心境涵凈土。", "觀空本無說，因物自吐露。", "往來忘時節，相對兩如寓。", "屈指說去官，始憶三年住。", "囅然同一笑，歲月真脫免。", "我不記前三，更問末後句。"]'),
('e84d568c-3e37-41bd-83fb-e26fcfa99535','贈別歸安周縣丞二首  其二','劉一止','宋','宋诗','song-poetry','','[]','庭前百个竹，眼見三隕籜。',132,'全唐诗/poet.song.84000.json','["庭前百个竹，眼見三隕籜。", "不知如許久，已復東行槖。", "君初無住想，脫去亦不惡。", "官身等出家，随牒即行脚。", "笑傲雲烟間，何適非至樂。", "嗟我獨奈何，生理自窘縳。", "四十三年非，醖造此大錯。", "從今便上上，萬事付莫莫。", "張公留衣鉢，綠蓑與青篛。", "會當老扁舟，相與同啐啄。", "更看後五日，放過前一著。"]'),
('11ab4296-473e-4734-81b4-2ceab4aa7598','宿溪口一首','劉一止','宋','宋诗','song-poetry','','[]','溪聲來天邊，風水共豪縱。',48,'全唐诗/poet.song.84000.json','["溪聲來天邊，風水共豪縱。", "夜氣劇奔馬，侵曉不能控。", "書生有清癖，詠雪寧忽凍。", "胡爲枕寒流，故遣不成夢。"]'),
('e4c7dbf4-30ec-4681-9096-190b5f53adeb','賦建安林尚能家追遠堂一首','劉一止','宋','宋诗','song-poetry','','[]','履霜存永慕，風樹寄悲惋。',180,'全唐诗/poet.song.84000.json','["履霜存永慕，風樹寄悲惋。", "古來孝子心，百歲常輾轉。", "雞豚逮親存，適意寧一臠。", "他時轂千乘，泣涕顔有靦。", "生世苟如此，豈得但理遣。", "所以奉嘗事，自竭叵不勉。", "尚能七閩秀，器識頗凝遠。", "求官自束髮，捧檄恨晼晚。", "歸懷追養勤，作堂近山巘。", "欲招九原魂，彷彿此息偃。", "牛羊家自腯，菘韭傍可剪。", "春秋及時祀，情物兩俱腆。", "遂令里間兒，艱詫知禮典。", "孰先如此堂，孰孝如此悃。", "從今大而門，至行神所戩。"]'),
('c642933d-1225-4ca0-964d-c0259056310c','宋景文公之孫景雲得玉龜印有忠孝侯印四字示詩次其韻','劉一止','宋','宋诗','song-poetry','','[]','寶器傳家寧浪出，漢爵通侯二千石。',96,'全唐诗/poet.song.84000.json','["寶器傳家寧浪出，漢爵通侯二千石。", "懸知忠孝萃公門，寸印便應輕尺璧。", "虎頭飛去通神畫，未免誑欺涉嘲罵。", "餘不左顧非偶然，渭水得璜天或者。", "公門次第生輝光，一一詞鋒如劍鋩。", "龜玉正憐俱在手，莫放柙中蒼兕吼。"]'),
('66213795-c1ba-44ee-8355-0b0012ba92b2','舍弟出家作詩貽之','劉一止','宋','宋诗','song-poetry','','[]','在家情已疏，出家終不惡。',108,'全唐诗/poet.song.84000.json','["在家情已疏，出家終不惡。", "不有清凈緣，云何脫徽索。", "我昔志婚宦，謂足世味樂。", "顛倒十年間，如蠺竟自縛。", "業已無奈何，勸汝莫莫莫。", "一漚非全潮，起滅皆妄作。", "當知是身浮，流浪恐非託。", "伎倆百不好，攝念乃初學。", "如病求真醫，安心是良藥。"]'),
('aaab907b-ec38-4e03-abc8-50e7ba8cec44','和巒嶅二子寒食少天色五字  其一','劉一止','宋','宋诗','song-poetry','','[]','霧雨昏不醒，東風曉能酸。',24,'全唐诗/poet.song.84000.json','["霧雨昏不醒，東風曉能酸。", "我食日不足，寧憂三日寒。"]'),
('0c5bd02a-7df5-498d-8a7c-be1bcafbefb0','和巒嶅二子寒食少天色五字  其二','劉一止','宋','宋诗','song-poetry','','[]','去年今日時，桃李半狼藉。',24,'全唐诗/poet.song.84000.json','["去年今日時，桃李半狼藉。", "能随里門兒，買𩛿作寒食。"]'),
('8c277767-e94c-4d76-93d8-62d204ac1baf','和巒嶅二子寒食少天色五字  其三','劉一止','宋','宋诗','song-poetry','','[]','人言二月時，霏雨生樹杪。',24,'全唐诗/poet.song.84000.json','["人言二月時，霏雨生樹杪。", "天色何時光，要向寒食少。"]'),
('40acc8a0-1912-475f-91f9-a1eef6bb7abd','和巒嶅二子寒食少天色五字  其四','劉一止','宋','宋诗','song-poetry','','[]','江南舟軋鴉，江北馬連翩。',24,'全唐诗/poet.song.84000.json','["江南舟軋鴉，江北馬連翩。", "經春不能賞，誰云不關天。"]'),
('9a856def-b7ca-4093-9ab3-ac8abccfcedc','和巒嶅二子寒食少天色五字  其五','劉一止','宋','宋诗','song-poetry','','[]','春風未渠尖，花草有矜色。',24,'全唐诗/poet.song.84000.json','["春風未渠尖，花草有矜色。", "酴醿會傾城，牡丹欲傾國。"]'),
('a2b2f1e7-e689-4aa5-bd2b-2b930b5fe91d','太守生辰四首以受天百祿爲韻  其一','劉一止','宋','宋诗','song-poetry','','[]','漢城欲回春，梅柳詫先受。',48,'全唐诗/poet.song.84000.json','["漢城欲回春，梅柳詫先受。", "江北迎兩轓，江南試春酒。", "得州古云樂，渠閣大如斗。", "要將歲寒姿，一笑閱好醜。"]'),
('21efe9a9-2a09-436a-b2f0-f45906d082dc','太守生辰四首以受天百祿爲韻  其二','劉一止','宋','宋诗','song-poetry','','[]','朱轓世功名，地接韋杜天。',48,'全唐诗/poet.song.84000.json','["朱轓世功名，地接韋杜天。", "勤勞三十載，始着榮途鞭。", "淹速會有時，用舍何其賢。", "或者相棄除，天公賜長年。"]'),
('eb06069c-6690-4976-971e-5487b3a37708','太守生辰四首以受天百祿爲韻  其三','劉一止','宋','宋诗','song-poetry','','[]','杯觴誰聖賢，翰墨自主客。',48,'全唐诗/poet.song.84000.json','["杯觴誰聖賢，翰墨自主客。", "一醉迎春風，麗思發幽賾。", "河東豈無賦，諷一或勸百。", "願公攄梗概，早晚煥簡册。"]'),
('581fbe07-356c-4b33-b9bf-750aca7a2f29','太守生辰四首以受天百祿爲韻  其四','劉一止','宋','宋诗','song-poetry','','[]','龍門映當代，開闔踵前躅。',48,'全唐诗/poet.song.84000.json','["龍門映當代，開闔踵前躅。", "自笑牛馬走，老矣戀寸祿。", "染指睨列鼎，炙手借餘燠。", "但恐飛詔來，沙頭理行軸。"]'),
('7430159b-b923-4092-b63d-66a09eea5ef4','又以永錫難老爲韻  其一','劉一止','宋','宋诗','song-poetry','','[]','相門若崇山，神物職所領。',48,'全唐诗/poet.song.84000.json','["相門若崇山，神物職所領。", "天令佑世德，奕奕發秀穎。", "圖書漫今古，論議餘骨鯁。", "富貴豈足言，功烈相與永。"]'),
('d4e44e2a-bc65-43ff-b90b-5c2f386f3b8f','又以永錫難老爲韻  其二','劉一止','宋','宋诗','song-poetry','','[]','倚公芸香閣，今古壓紬繹。',48,'全唐诗/poet.song.84000.json','["倚公芸香閣，今古壓紬繹。", "付公銅虎符，利疚稔更歷。", "帝曰我此賢，儲作國柱石。", "俾爾壽而富，一一天所錫。"]'),
('c39ba5c7-a96d-4baf-8e9b-bbecccc99eb0','又以永錫難老爲韻  其三','劉一止','宋','宋诗','song-poetry','','[]','采采黄菊英，秀色真可餐。',48,'全唐诗/poet.song.84000.json','["采采黄菊英，秀色真可餐。", "泛之清霞觴，薦以白玉盤。", "我欲持壽公，助發凌風翰。", "天地炯在眼，一舉非公難。"]'),
('1b25be60-ae57-4d3e-89b2-bc3253674733','又以永錫難老爲韻  其四','劉一止','宋','宋诗','song-poetry','','[]','長松倚青壁，千歲身不老。',48,'全唐诗/poet.song.84000.json','["長松倚青壁，千歲身不老。", "下顧蓬艾姿，生意何草草。", "願言雨露甘，餘潤及枯槁。", "耿耿心自憐，得蔭苦不早。"]'),
('d7b63fe4-c39d-4476-b844-d59896554c16','夜起觀雪一首','劉一止','宋','宋诗','song-poetry','','[]','寒空夜作山林聲，打窗窸窣饑鼠行。',128,'全唐诗/poet.song.84000.json','["寒空夜作山林聲，打窗窸窣饑鼠行。", "褰帷忽怪窗淡白，開門雪飛縱復横。", "天上瑞花開又落，庭下疏梅初破萼。", "忍寒耐苦發孤妍，似與老人甘落莫。", "遙憐國難何時清，嗣皇求衣天未明。", "長蛇封豕欲薦食，執筆固陋慚書生。", "皇天悔禍今可卜，乞與江湖比歲熟。", "莫言此雪不樂饑，便是天公真雨粟。"]'),
('124ae455-4030-4717-a978-8f503d8d5c3b','待潮浙江口寄左與言大夫葉元亮學士兼簡吳似之大著','劉一止','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今日江頭雪欲作，濤怒風豪兩噴薄。',192,'全唐诗/poet.song.84000.json','["今日江頭雪欲作，濤怒風豪兩噴薄。", "青鞋黄帽湖海人，獨立沙邊如病鶴。", "閑身不待君賜與，擬占風烟佳處着。", "如何寸祿晚見招，踉蹡欲前還欲却。", "翩翩西湖兩公子，胸次崢嶸飽邱壑。", "糟床夜注喜相報，自發清吟侑觴酌。", "我來一笑豈易得，十載湖山負佳約。", "間關百態成底事，毛髪星星已非昨。", "人間俯仰變今古，總似潮生與潮落。", "會須乞取此身健，在眼好山俱着脚。", "頗聞神方能却老，肯輔衰殘殊不惡。", "因聲更約吳太史，石鼎他年煮仙藥。"]'),
('64d6d670-4af5-441e-b013-d42be7c1e5f9','送樓伴張吏部還朝一首','劉一止','宋','宋诗','song-poetry','','[]','中臺縹緲神仙居，退朝往往聯飇輿。',368,'全唐诗/poet.song.84000.json','["中臺縹緲神仙居，退朝往往聯飇輿。", "追随五城十二樓，鞭鸞笞鳳相嬉娱。", "一一氣貌清而腴，下哂山澤皆臞儒。", "虚堂夜直冷不寐，博極天上人間書。", "去取小雅大雅詩，賡續二典竄禹謨。", "塵凡豈得追步趨，夢境欲到猶趦趄。", "望郎何事飛軺車，東浮江淮絕句吳。", "天令賤子得所圖，邂逅實始迎郊墟。", "公不鄙我置坐隅，假以色笑安且舒。", "乃知仙風自恢廓，不邀我敬憐其愚。", "從容自喜吐傑句，屏息側聽仍嗟吁。", "朱絃疏越清廟奏，一唱三歎音有餘。", "何劉沈謝氣力短，郊島輩行不足奴。", "惟公妙年擅場屋，一日聲價騰八區。", "諸公貴人交薦達，帝以見晚驚嚴徐。", "要津已復更步武，簪筆會直承明廬。", "頗聞細書問良苦，便覺風信催旋艫。", "公歸儻辨報明主，物色士類供時須。", "班公騶僕我不如，山林鐘鼎端異途。", "何王之門曳長裾，半生鼓瑟從吹竽。", "逝将爭席朋樵漁，正恐不免饑見驅。", "間關老矣尚耿耿，所覬肝膽從公輸。", "他時門下有此客，中夜彈劍非無魚。"]'),
('916b7798-5934-4d31-82bf-4d3f0871615c','雪夜一首呈傅舍人','劉一止','宋','宋诗','song-poetry','','[]','朔風無端卷入幕，短檠滉漾吹花落。',64,'全唐诗/poet.song.84000.json','["朔風無端卷入幕，短檠滉漾吹花落。", "怪來覓句如斲冰，門外雪花如舞鶴。", "老妻自起傾殘樽，麒麟活火紅燉燉。", "憑君爲喚詩腸溫，他日有酒不足論。"]'),
('959b1404-6a7d-4203-918b-e0978a19d348','憶山中一首示巒嶅二子用前韻','劉一止','宋','宋诗','song-poetry','','[]','世路欹危如燕幕，未厭山中昔牢落。',64,'全唐诗/poet.song.84000.json','["世路欹危如燕幕，未厭山中昔牢落。", "春前擷韭秋擷菘，有客有客鷴與鶴。", "瓦甌鐵杓文石樽，枯樵發火勢易燉。", "得酒徑就山僧溫，聽風聽雨取次論。"]'),
('0d24222c-dba8-49fb-9f69-8f9a6eb15c88','次韻方允迪袐監九日登高一首','劉一止','宋','宋诗','song-poetry','','[]','九日意蕭條，病卧如漳濱。',168,'全唐诗/poet.song.84000.json','["九日意蕭條，病卧如漳濱。", "紅萸起自插，黄菊兹及辰。", "身落芹藻間，心與鴻鴈親。", "想見龍山遊，嘲謔落帽人。", "眷焉瀛洲客，共此溪港鄰。", "白髪俱許長，清愁浩無垠。", "四年京華別，前事寧忍詢。", "國恥久未雪，憤切此逐臣。", "革路何時還，今誰叫穹旻。", "駕言寫心憂，一涴衣上塵。", "扁舟羡鴟夷，舉酒憶季真。", "目極樵徑風，便擬從採薪。", "但恐嵌巖中，不著功名身。", "報國君尚強，我拙甘長貧。"]'),
('159e5d61-4907-4f76-a62c-9df66de5b0b2','水車一首','劉一止','宋','宋诗','song-poetry','','[]','村田高仰對低窊，咫尺溪流有等差。',128,'全唐诗/poet.song.84000.json','["村田高仰對低窊，咫尺溪流有等差。", "我欲浸灌均田涯，天公不遣雷鞭車。", "老龍下飲骨節瘦，引水上泥聲呷呀。", "初疑蹙踏動地軸，風輪共轉相鈎加。", "嗟我婦子脚不停，日走百里不離家。", "綠芒刺水秧初芽，雪浪翻壠何時花。", "農家作勞無別想，兩耳未厭長嘔啞。", "殘年我亦冀一飽，謂此鼓吹勝聞蛙。"]'),
('78f13031-9cbb-4e9b-b642-f2fb1914c479','和雲門行持長老十二辰歌呈同遊二三士','劉一止','宋','宋诗','song-poetry','','[]','虚堂怖鬼鼠窸窣，牀上門牛由蟻窟。',96,'全唐诗/poet.song.84000.json','["虚堂怖鬼鼠窸窣，牀上門牛由蟻窟。", "将軍見虎箭羽沒，兔起鶻落不待咄。", "初心學道如龍頭，習疑玩久蛇尾收。", "雲門倒跨一木馬，追風相羊踏九州。", "諸賢巧思生棘猴，碧雞談辨不肯休。", "煩師放出紫湖狗，騎猪南穿聲喧啾。"]'),
('7fc43eba-f44d-4317-b92d-91f391248517','從謝仲謙乞猫一首','劉一止','宋','宋诗','song-poetry','','[]','昔人蟻動疑鬭牛，我家奔鼠如馬羣。',128,'全唐诗/poet.song.84000.json','["昔人蟻動疑鬭牛，我家奔鼠如馬羣。", "穿牀撼席不得寐，囓噬編簡連帨帉。", "主人瓶粟常掛壁，每飯不肉如廣文。", "誰令作意肆奸孽，似怨釜鬵無餘葷。", "君家得猫自拯溺，恩育幾歲忘其勤。", "屋頭但怪鼠跡絕，不知下有飛将軍。", "他時生囝願聘取，青海龍種豈足云。", "歸來堂上看俘馘，買魚貫柳酬策勛。"]'),
('27f34cd0-c367-4bf9-995c-b7ec510da157','次韻曾宏父見貽一首','劉一止','宋','宋诗','song-poetry','','[]','東巡屬車何大勤，鐵馬風趨過吳下。',96,'全唐诗/poet.song.84000.json','["東巡屬車何大勤，鐵馬風趨過吳下。", "周宣自有中興日，天厭氈庭尚須暇。", "所興吳越天有年，汙邪委地連山前。", "與君步屧探禹穴，感時興物俱惘然。", "一官寓食家傳久，暮景差池亦何有。", "遮藏要見太平時，狐死何曾忘丘首。"]'),
('26a2ce67-ce79-4f11-8677-56c32856e7c3','二禽言  其一','劉一止','宋','宋诗','song-poetry','','[]','婆餅焦，游子饑。',32,'全唐诗/poet.song.84000.json','["婆餅焦，游子饑。", "游子饑，泣路岐。", "耕牛殺盡飽狂虜，桑下老農心更苦。"]'),
('50d7e833-19ab-44b3-825d-f26aa9689449','二禽言  其二','劉一止','宋','宋诗','song-poetry','','[]','泥滑滑，風蕭蕭。',40,'全唐诗/poet.song.84000.json','["泥滑滑，風蕭蕭。", "烟雨昏，獨木橋。", "軋鴉鳴櫓逆風搖，行子終歲事遠徭，使我心悸不得邀。"]'),
('ebca2092-65cc-46e7-b661-70ba84bbb5ec','和胡浚明村中好客稀五字併作一首','劉一止','宋','宋诗','song-poetry','','[]','青山爲郭雲當門，疏烟細雨梅花村。',160,'全唐诗/poet.song.84000.json','["青山爲郭雲當門，疏烟細雨梅花村。", "門前落澗瀉寒溜，袞袞似是通河源。", "隱居二士清而通，談道不愧将無同。", "何人載酒問奇字，糟床夜注時一中。", "天驥權奇嗟欲老，家有龍駒頭尺好。", "孫郎並舍真可人，散亂書籤共探討。", "只今干戈迷所適，我亦間關暫投跡。", "君家鳥雀不驚人，應怪蒼黄如此客。", "謀身已拙知遁肥，邂逅得此良亦稀。", "化雲所願四方逐，念絕側翅随人飛。"]'),
('e738dd89-42d2-4fe6-9806-f6cd80cab500','送吳興太守盧給事赴兵部侍郎召四首以邦家之光爲韻  其一','劉一止','宋','宋诗','song-poetry','','[]','東風催行艫，旍旗轉修扛。',108,'全唐诗/poet.song.84000.json','["東風催行艫，旍旗轉修扛。", "千騎如登仙，我心豈得降。", "嗣學初元年，德意孚萬邦。", "不戰屈醜虜，威聲疾奔瀧。", "眷言帷幄舊，分符隔濤江。", "尚書古司戎，名實尚誰雙。", "折衝要從容，談笑空酒缸。", "帝曰汝遄歸，謀國資敦龐。", "無庸斗大州，洪鐘受微撞。"]'),
('fdb76942-2b91-498d-85d9-2b5bb446d70c','送吳興太守盧給事赴兵部侍郎召四首以邦家之光爲韻  其二','劉一止','宋','宋诗','song-poetry','','[]','汀洲初檝迎，紅紫爛朝霞。',72,'全唐诗/poet.song.84000.json','["汀洲初檝迎，紅紫爛朝霞。", "及兹理旋艫，綠陰已籠沙。", "使君如東君，來去不戀家。", "獨持五色筆，摛辭燦芳華。", "明年鳳凰池，春風浩無涯。", "須公賦丹青，去路不可遮。"]'),
('806ef924-25df-497c-9396-846a9f0b585d','送吳興太守盧給事赴兵部侍郎召四首以邦家之光爲韻  其三','劉一止','宋','宋诗','song-poetry','','[]','公來臨我邦，天意若見私。',96,'全唐诗/poet.song.84000.json','["公來臨我邦，天意若見私。", "從容坐席間，風化已四馳。", "民曰吾二天，士曰得我師。", "庶幾少淹留，子弟公教之。", "如何如不顧，公豈要我思。", "不見溪上山，旦暮發妍姿。", "及兹有行色，風日含悽悲。", "公亦何負渠，欠渠百篇詩。"]'),
('46ab72cc-2f37-45ef-967d-c93dbd3844d6','送吳興太守盧給事赴兵部侍郎召四首以邦家之光爲韻  其四','劉一止','宋','宋诗','song-poetry','','[]','西雍拜顔色，振鷺俱分行。',156,'全唐诗/poet.song.84000.json','["西雍拜顔色，振鷺俱分行。", "繡衣浙江濱，再上君子堂。", "首尾二十載，持槖侍明光。", "厭看南朝山，易綰吳興章。", "煌煌朱兩轓，照我梓與桑。", "怪我衫始青，憐我鬢已蒼。", "頗復見勞苦，感慨激中腸。", "向來官如泥，葡萄換西凉。", "剪翎但鳴悲，坐閱百鳥翔。", "公爲世良師，醫國有禁方。", "頗聞藥籠中，臭味久已嘗。", "小草存遠志，未用出聲妨。", "採掇公弗疑，結根稔風霜。"]'),
('556aad76-0013-4488-94f8-da44b794eb9f','張倅生辰作質龜相鶴二詩爲壽  其一','劉一止','宋','宋诗','song-poetry','','[]','神龜異生稟，懷抱星與月。',96,'全唐诗/poet.song.84000.json','["神龜異生稟，懷抱星與月。", "蹣跚守叢著，遊戲引蓮葉。", "青雲覆其上，文字書左脇。", "千年愈堅瘦，腹背類璆鐵。", "有如盛德士，秉志厲霜雪。", "不求赫赫名，羞作翕翕熱。", "行藏關理亂，閱世自明哲。", "時哉此唐虞，負圖追往諜。"]'),
('4058abc3-e3d6-4c11-9c05-4bd3c4db2a38','張倅生辰作質龜相鶴二詩爲壽  其二','劉一止','宋','宋诗','song-poetry','','[]','黄鶴初出胎，骨格已驚衆。',96,'全唐诗/poet.song.84000.json','["黄鶴初出胎，骨格已驚衆。", "翩翩謝囂塵，颯爽自神縱。", "朝飛出芝田，夕飲下雲夢。", "寧知風露質，乃系世輕重。", "有如賢達人，胸腹抱空洞。", "觀時自隱顯，豈待吹嘘送。", "會看九臯鳴，一一律呂中。", "閱歲千六百，羣飛接鸞鳳。"]'),
('f856fb21-d13c-4406-acb0-4da071beb14c','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其一','劉一止','宋','宋诗','song-poetry','','[]','蘋洲景物最惱客，無賴山色只供愁。',32,'全唐诗/poet.song.84000.json','["蘋洲景物最惱客，無賴山色只供愁。", "短棹從渠系烟雨，春容併在水南頭。"]'),
('82a2f46b-f9cb-4bde-8bc0-19ac0484d433','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其二','劉一止','宋','宋诗','song-poetry','','[]','並山微徑自曲折，野人種花無數蹊。',32,'全唐诗/poet.song.84000.json','["並山微徑自曲折，野人種花無數蹊。", "太傅風流猶可想，樓船皓齒合招攜。"]'),
('4f5d1a6b-d77b-4756-832d-52db356cde8d','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其三','劉一止','宋','宋诗','song-poetry','','[]','謝家溪亭花鎖碎，尚憶故歲春未闌。',32,'全唐诗/poet.song.84000.json','["謝家溪亭花鎖碎，尚憶故歲春未闌。", "覓得小航衝雨去，濕紅飛處忍朝寒。"]'),
('4e4f5dc9-9c39-4dd8-a5bf-c93b55e0a9b8','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其四','劉一止','宋','宋诗','song-poetry','','[]','使君覓句自超絕，江邊烏桕能絕人。',32,'全唐诗/poet.song.84000.json','["使君覓句自超絕，江邊烏桕能絕人。", "我疑秘思有天巧，滉漾胸中百頃春。"]'),
('77eda13b-37bb-4dd9-ad0d-20b83102c828','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其五','劉一止','宋','宋诗','song-poetry','','[]','官閑亦復一笑適，理檝及此春日晴。',32,'全唐诗/poet.song.84000.json','["官閑亦復一笑適，理檝及此春日晴。", "追吟乃得伯宏父，便覺侯喜無詩聲。"]'),
('cc156a6c-82c5-4bf3-b8a1-e36868c574e4','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其六','劉一止','宋','宋诗','song-poetry','','[]','老來文字讀不入，抽思軋軋如涸泉。',32,'全唐诗/poet.song.84000.json','["老來文字讀不入，抽思軋軋如涸泉。", "從君敢作入社客，正恐釜豆相泣煎。"]'),
('2baca3e2-3c99-4075-8567-f4c519427c94','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其七','劉一止','宋','宋诗','song-poetry','','[]','有懷玉堂前學士，典冊汗漫真全潮。',32,'全唐诗/poet.song.84000.json','["有懷玉堂前學士，典冊汗漫真全潮。", "子向白雲深處覓，面山溪館带長橋。"]'),
('99c16b51-f43f-4f20-8d86-555203e00663','曾宏父将游吳興示所和葉內相八首次其韻太守亦和故并及之  其八','劉一止','宋','宋诗','song-poetry','','[]','翰林久袖經綸手，筆力游戲吞山川。',32,'全唐诗/poet.song.84000.json','["翰林久袖經綸手，筆力游戲吞山川。", "要試臯夔致君術，不應牢落著幽禪。"]'),
('730ecde3-3ab0-41b7-b1e0-e400ffc88474','南山有蹲鴟一首示里中諸豪','劉一止','宋','宋诗','song-poetry','','[]','南山有蹲鴟，春田多鳬茈。',108,'全唐诗/poet.song.84000.json','["南山有蹲鴟，春田多鳬茈。", "何必泌之水，可以樂我饑。", "六師擁行在，閭巷屯虎貔。", "民食尚可紓，軍食星火移。", "努力輸縣官，無乏轅門炊。", "所願將與士，感此艱食時。", "忠義發飫腹，向敵爭先之。", "驅逐狐鼠羣，宇縣還清夷。", "我輩死即休，粒米不敢私。"]'),
('1d99d7ef-845a-47e1-b2c4-727b78f0c1ac','聞杭州亂二首  其一','劉一止','宋','宋诗','song-poetry','','[]','饑來命餉寒索衣，官家養兵如養兒。',80,'全唐诗/poet.song.84000.json','["饑來命餉寒索衣，官家養兵如養兒。", "時平軍律久玩弛，轅門笑歌驕莫随。", "往時金陵囚刺史，今者杭州漕臣死。", "稽天烈焰窮朝昏，千丈紅霞炫江水。", "鄰州之兵如此兵，嗚呼此難何時平。"]'),
('8bcfa92b-9df5-4cba-ab17-f155d54d9e1e','聞杭州亂二首  其二','劉一止','宋','宋诗','song-poetry','','[]','緩城将母走者誰，吾宗貴人丞相兒。',84,'全唐诗/poet.song.84000.json','["緩城将母走者誰，吾宗貴人丞相兒。", "高門潭潭深如海，一朝赤脚踏路岐。", "吁嗟身世本何有，金帛滿家那得守。", "衣冠自古皆賊仇，玉石俱焚無好醜。", "嗚呼安得貧富受用勢略齊，無庸懸絕産禍機。"]'),
('2b37e17f-f755-41e2-a850-3d7738358c07','傅子駿右司見和雪句且有兩宮北狩之感復用韻二首  其一','劉一止','宋','宋诗','song-poetry','','[]','萬里胡沙驚毳幕，北望旄頭天際落。',64,'全唐诗/poet.song.84000.json','["萬里胡沙驚毳幕，北望旄頭天際落。", "向來官軍如路人，受甲逡巡惟指鶴。", "寧知竟屈鑾輅尊，問天火令何當燉。", "落雪如絮不我溫，九關夢想血面論。"]'),
('3bc1a23d-ef73-4639-806d-b67caba8fe03','傅子駿右司見和雪句且有兩宮北狩之感復用韻二首  其二','劉一止','宋','宋诗','song-poetry','','[]','先生著書風撼幕，詩成弄筆雲烟落。',64,'全唐诗/poet.song.84000.json','["先生著書風撼幕，詩成弄筆雲烟落。", "舍傍種竹欲招鳳，郭內有田纔給鶴。", "眼看雪片黏空尊，寒齋芋火猶能燉。", "怪我官冷何時溫，我亦聊爾公弗論。"]'),
('c4ff0a58-7908-483a-917a-ff804e5327dd','次韻方允迪秘監步月感懷一首','劉一止','宋','宋诗','song-poetry','','[]','伊昔苕水濱，詩酒相逆送。',156,'全唐诗/poet.song.84000.json','["伊昔苕水濱，詩酒相逆送。", "紅蕖三百頃，天遣作妙供。", "於今幾何時，喜懼不同夢。", "驚心風月夕，怨笛有殘弄。", "所嗟老侵尋，不愧官冗從。", "當時季孟間，衆識長雛鳳。", "寧知天一角，復此樽酒共。", "文章自千古，習氣無乃重。", "詩如朝陽鳴，一一律呂中。", "從遊二三駿，蹀躞不受鞚。", "阿威有家學，落筆競豪縱。", "傷時復懷舊，一笑得再慟。", "公等俱勉旃，如我堪底用。"]'),
('f03d71f5-5592-4bad-8186-8d8d6e01a3d8','允迪以羊膏瀹茗飲呂景實景實有詩歎賞僕意未然輙次原韻','劉一止','宋','宋诗','song-poetry','','[]','精金不受釧釵辱，瑞草何曾取膏腹。',147,'全唐诗/poet.song.84000.json','["精金不受釧釵辱，瑞草何曾取膏腹。", "乳花粥西名已非，薦以羊肪何太俗。", "山林鐘鼎異天性，難遣華腴偶窮獨。", "森森正味苦且嚴，玉質無瑕誰敢戮。", "君家饌林多錯本，讀罷流涎誑枯吻。", "故令茗盌變腥膻，遠想黄封雪花醖。", "呼酪爲奴逢彼怒，自惜爭雄巧相污。", "我寧不飲信我說，獨喜君詩有神助。", "君不見穆家兄弟故可人，概以骨鯁恐異趣。"]'),
('6f3d1a1d-0bc2-4d0f-85af-cc95692a9af0','將如京師和方時敏機宜十二辰歌一首','劉一止','宋','宋诗','song-poetry','','[]','羣兒鼠竊均有遇，老矣自知牛後誤。',96,'全唐诗/poet.song.84000.json','["羣兒鼠竊均有遇，老矣自知牛後誤。", "成功未解鬬兩虎，援翰徒勞秃千免。", "佩書丱首何龍鍾，靈蛇光怪蟠心胸。", "馬頭三千悲遠道，羊角萬里無高風。", "秦歌嗚嗚楚猴舞，一笑何如共雞黍。", "謀身狗苟君勿嗤，聊戲墨猪書韻語。"]'),
('e1161c6c-104a-4903-b9e3-c8b055b0e8bc','五十少公卿贈何子楚居士','劉一止','宋','宋诗','song-poetry','','[]','五十少公卿，三十老舉子。',252,'全唐诗/poet.song.84000.json','["五十少公卿，三十老舉子。", "世間老與少，不必較年齒。", "我觀宦達人，顔色自豐美。", "癯者忽易腴，變化一日耳。", "人言老再少，信是有此理。", "我爲老諸生，流落逾二紀。", "四十又過四，淟涊百僚底。", "說老已十年，何况真老矣。", "壮氣推幽憂，髮白面目緇。", "寧有再少時，一衰乃如此。", "何郎窮過我，齒髮亦相似。", "閑居傲軒裳，臞腹滿經史。", "時時吐光焰，麗句落窗几。", "誰家肯終惠，試此足千里。", "空令坐窮獨，閣戶今掃軌。", "宦達世共慕，閑曠我所喜。", "丈夫生世間，要自發奇偉。", "富貴何足云，功名半張紙。", "古來傲世士，良是窮乃止。", "未有如子年，忼慨隱廛市。", "我不愧公卿，愧此少居士。"]'),
('2c04c930-28a9-4448-a98e-3b5f12b81c35','水村二首示友人  其一','劉一止','宋','宋诗','song-poetry','','[]','浮花蕩漾青蘋小，綠柄欹垂剪刀草。',64,'全唐诗/poet.song.84000.json','["浮花蕩漾青蘋小，綠柄欹垂剪刀草。", "朝從港東暮港西，採花擷草無盡期。", "秋光有盡意無盡，萬馬奔騰山作陣。", "眼中未飽公莫回，饑腸作惡如鳴雷。"]'),
('6f47f0da-9a16-428c-9203-941ecc660014','水村二首示友人  其二','劉一止','宋','宋诗','song-poetry','','[]','張公一生雲水客，往歲孤蹤寄苕霅。',64,'全唐诗/poet.song.84000.json','["張公一生雲水客，往歲孤蹤寄苕霅。", "故人刺史眼爲青，願爲泛宅浮清泠。", "當時鷗鳥難問跡，尚有水村名泊宅。", "碧蓑青笠寧在無，公今仙去當傳余。"]'),
('b0f10ab4-d488-4458-bb9c-b747a8ac3392','借居鸕鷀山中一首呈方允迪道蹤昆仲','劉一止','宋','宋诗','song-poetry','','[]','長松舞高寒，落澗瀉清泚。',144,'全唐诗/poet.song.84000.json','["長松舞高寒，落澗瀉清泚。", "笙簧響天上，金石鳴地底。", "雲容何潤澤，下有隱君子。", "樂此山水音，清若變流徴。", "怪我從何來，塵土兩目眯。", "寇戎在江滸，薦食心未已。", "赤嚢走邊報，朝暮異憂喜。", "安知隱人樂，勝絕有如此。", "古來成敗事，不入山中耳。", "願言晚相收，置我巖壑裏。", "酌泉得醒心，茹朮可不死。", "况有載酒人，半道同栗里。"]'),
('0703a5ca-f774-42e2-b177-ca17742cf962','山居作拆字詩一首寄江子我郎中比嘗以拆字語爲戲然未有以爲詩者請自今始','劉一止','宋','宋诗','song-poetry','','[]','日月明朝昏，山風嵐自起。',48,'全唐诗/poet.song.84000.json','["日月明朝昏，山風嵐自起。", "石皮破仍堅，古木枯不死。", "可人何當來，意若重千里。", "永言詠黄鵠，志士心未已。"]'),
('bb2b3e8c-9982-49bb-8d2e-a9a868f21158','次韻鄭維心貽盧叔才一首','劉一止','宋','宋诗','song-poetry','','[]','朝行轉木末，暮返循水涯。',147,'全唐诗/poet.song.84000.json','["朝行轉木末，暮返循水涯。", "生長山水間，途窮自知歸。", "萬緒更擾擾，衆目何睽睽。", "有若脫{革卮}牛，邂逅得此時。", "坐念盧夫子，與世真背馳。", "讀書如董生，三載圃不窺。", "清詩見真情，觀者豈得疵。", "春風入閭巷，爛熳百草菲。", "摩腹忽起行，菜茹傷蕨薇。", "平生經綸學，無術取世資。", "貧交可相覓，叩門兩無疑。", "富貴不汝求，吾至君勿揮。"]'),
('bc3c26e9-ca0a-4be8-9ba8-3ac300d1be45','次韻維心謝沈尚書惠筆一首','劉一止','宋','宋诗','song-poetry','','[]','書生磨吻鉛刀銛，君家手筆不退尖。',208,'全唐诗/poet.song.84000.json','["書生磨吻鉛刀銛，君家手筆不退尖。", "琢成秀句奪天巧，平揖鮑謝奴高錢。", "郊寒島瘦復可哂，漢風楚國真能兼。", "胸中疾邪茹不吐，但覺忿氣生虬髯。", "叵堪陳壽書漢實，毫端有口可得箝。", "尚書昔侍金華講，論議凛凛秋霜嚴。", "曾将一字竊魯史，未用三語求阮瞻。", "分君賜筆助清峭，雕犀鏤象光出奩。", "如吾樸遫豈足數，半世翰墨徒心潛。", "老去文章讀不入，編帙散亂如投籤。", "因君窮討默自愧，僻魯成痼何時砭。", "須要盡見君家書，槁死不歎周南淹。", "更從湘東覓金管，賞激忠孝祛奸憸。"]'),
('6d02aa12-7211-4afa-9d11-e862cf1c12ad','謝吳興守李端明致酒一首時寓德清','劉一止','宋','宋诗','song-poetry','','[]','孔愉廟邊溪水長，石壁巖下飛泉香。',144,'全唐诗/poet.song.84000.json','["孔愉廟邊溪水長，石壁巖下飛泉香。", "居士住此幾寒暑，只見四山青又黄。", "今年春雨摧麥芒，六月稻穗乾欲僵。", "煩公焦勞坐黄堂，何不趣公歸贊襄。", "爲時開閣陰與陽，不令此憂遺君王。", "我君有如坐甑內，口顧怫鬰不得驤。", "公欲令我蘇肺腸，白衣致酒甚沛滂。", "瓶粟未空陶氏倉，得酒且到王生鄉。", "更招山前老漫郎，渠家曲柄荷可觴。"]'),
('22e6e27d-4009-46f5-a82c-370be8d2d85f','月出一首','劉一止','宋','宋诗','song-poetry','','[]','東峰高如屏，月出久未知。',96,'全唐诗/poet.song.84000.json','["東峰高如屏，月出久未知。", "竹影忽上窗，淡臺時參差。", "幽人坐數息，瞑久息愈遲。", "舉目月在窗，便覺心境移。", "平生浪紛擾，自省黠半癡。", "歲晚得此身，終焉以爲期。", "山中有寒暄，我不記四時。", "樂此見有初，非關未忘詩。"]'),
('9f941b6d-fc57-4160-a937-6436c5781857','剡溪道上一首','劉一止','宋','宋诗','song-poetry','','[]','一水縈不斷，千巖翠相扶。',96,'全唐诗/poet.song.84000.json','["一水縈不斷，千巖翠相扶。", "孤篷載雪歸，我昔見畫圖。", "今年兩經行，明晦自惨舒。", "旱夏山若焦，秋至潦溢途。", "是中無故人，王事當馳驅。", "景物寄心賞，随遇便有餘。", "不覺老季真，乞歸尚狂疏。", "官家賜閑身，用底一曲湖。"]'),
('1b3c4a50-ee09-419a-81cb-00bf59a8be01','觀大龍湫一首','劉一止','宋','宋诗','song-poetry','','[]','峰頭鴈何在，井底龍不出。',96,'全唐诗/poet.song.84000.json','["峰頭鴈何在，井底龍不出。", "吐作玉虹流，倒挂二千尺。", "落澗勢初緩，漸聽轉山急。", "噀面飛雨過，著衣晨霧濕。", "造物等幻戲，此地真絕特。", "勿言王事勞，遇勝得小立。", "慚愧大尊者，幾載面青壁。", "山高不礙見，泉聲不妨寂。"]'),
('7506e3a4-433f-49ce-86f2-6186009efe3a','次韻建安劉彦冲學士寄茶一首','劉一止','宋','宋诗','song-poetry','','[]','寒溪日潄枯腸潔，自志窮愁漸陋劣。',72,'全唐诗/poet.song.84000.json','["寒溪日潄枯腸潔，自志窮愁漸陋劣。", "故人不愛北苑春，更遣清甘嚅吻頰。", "只今相望如參商，武夷孤絕雲蒼茫。", "底事坐閱百鳥翔，要借玉川風兩腋，高飛令我墜君傍。"]'),
('b9ddb1c6-e3ec-4b9f-910d-172518c4e8ff','賦程伯禹給事漫吾亭一首','劉一止','宋','宋诗','song-poetry','','[]','道州固傷時，晚歲吾山溪。',144,'全唐诗/poet.song.84000.json','["道州固傷時，晚歲吾山溪。", "彼物何曾爭，我自分兩畦。", "宣州絕代賢，雅志蘇羣黎。", "胸次包峥嶸，不肯去角圭。", "何從得漫名，正恐亦偶題。", "渺觀身世空，萬境俱一齊。", "浪云出處殊，不悟東自西。", "向來功名轍，復入山水蹊。", "公今持左符，早晚朝金閨。", "生賢出世間，渠能絕攀躋。", "要須了此心，泛應忘高低。", "昔我蓋已漫，今我亦非迷。"]'),
('57db2bdb-87b8-4ac2-a6aa-59bfacb68d42','獨居會稽官舍送僧遊龜溪因記寄聲弊廬','劉一止','宋','宋诗','song-poetry','','[]','老人年六十，生理常刺促。',96,'全唐诗/poet.song.84000.json','["老人年六十，生理常刺促。", "歸無一稜田，此事亂心曲。", "妻孥渺相望，幼稚炯在目。", "師今遇龜溪，山水無盡綠。", "石壁嚴寶坊，泉甘宜杞菊。", "但恐齋廚空，眼飽不救腹。", "並山行徑微，草露濕人足。", "師訪老人家，門前有修竹。"]'),
('6a691679-5333-4039-bd41-bb1def4d1365','酬王元渤舍人方智善學士求余作墨竹一首','劉一止','宋','宋诗','song-poetry','','[]','堂名似賢人似竹，瘦節孤高照崕谷。',160,'全唐诗/poet.song.84000.json','["堂名似賢人似竹，瘦節孤高照崕谷。", "百年人與竹俱化，尚有諸孫來借宿。", "家風愛竹餘底事，至今十飯九不肉。", "惟應說食誑枯腸，更寫寒梢媚幽獨。", "王郎散带談清虚，爲竹造門顔不忸。", "方英炯炯貌臞甚，門倚江干千个綠。", "兩家人物摠風流，石壁山前烟雨秋。", "豈惟千首輕萬戶，胸中世襲瀟灑侯。", "我乃癡絕非畫絕，憐此霜根貫金鐵。", "短綃淡墨持似公，更聽哦詩聲激烈。"]'),
('9e27ae90-20bf-43a5-a8e7-ec31bbb66e0a','題等侯軒一首','劉一止','宋','宋诗','song-poetry','','[]','蒼官與青士，昔封瀟灑侯。',96,'全唐诗/poet.song.84000.json','["蒼官與青士，昔封瀟灑侯。", "萬个儼相持，更比千戶優。", "道人心安樂，可念過不留。", "延我聽風窗，凄清韻天球。", "傍瞻卧麟冡，卿雲覆杯丘。", "前峰鬰岧嶤，落澗緣道周。", "居然氣象異，况乃世德修。", "他日名可占，子孫荷靈休。"]'),
('f74c2c8e-5272-4982-b58e-5013d0dd559b','訪石林葉少藴觀文二首  其一','劉一止','宋','宋诗','song-poetry','','[]','卿雲覆其上，草木爭鮮新。',144,'全唐诗/poet.song.84000.json','["卿雲覆其上，草木爭鮮新。", "竹露先參差，晴曦破蕭晨。", "萬石紛拱揖，静默自主賓。", "似中有老仙，雲霞煥精神。", "朝暮林壑間，搜抉出怪珍。", "風欹青篛笠，雨墊烏角巾。", "山靈指相謂，箇是夔龍身。", "如何輕世累，蕭散意許真。", "了知袞衣貴，未若巖石親。", "功名乃棄餘，道德受咨詢。", "我來追步趨，且復結勝因。", "劇談到羲軒，愧此真天人。"]'),
('5df9df16-d8b3-4a1f-8dfb-e7a600670d41','訪石林葉少藴觀文二首  其二','劉一止','宋','宋诗','song-poetry','','[]','夔龍在丘壑，神物發幽秘。',144,'全唐诗/poet.song.84000.json','["夔龍在丘壑，神物發幽秘。", "森然萬瓊瑰，參錯分位置。", "踞地猛獸伏，拏空孤鳥厲。", "先後相長雄，突怒疑攫噬。", "各以奇自列，寧謂我獨嗜。", "羊酪非不珍，蒓羮有至味。", "鄭公信骨鯁，我但見嫵媚。", "種竹被崕巒，惡木不得地。", "荃蘭偏九畹，薉草惨無類。", "造化初何心，被物自殊志。", "那知此巖傍，閱世等如寄。", "願言賦丹青，遠近同一視。"]'),
('254eec3d-4073-403d-a6ee-f52a79b04f9c','次韻倪文舉芮國器扁舟見過溪上之作','劉一止','宋','宋诗','song-poetry','','[]','頓有兩玉人，風流晉宋間。',84,'全唐诗/poet.song.84000.json','["頓有兩玉人，風流晉宋間。", "况復子倪子，妙思輕小山。", "訪我相後先，知我倦飛還。", "僮僕怪主人，羈縶如在閑。", "何曾得此客，能使意緒寛。", "從今望仙舟，我門肯常關。", "春風孔郎溪，松下荆可班。"]'),
('2c672378-c12b-45b0-b6bb-c968a6efa3ba','幾上人名所乘舟曰釣月庵求詩爲賦二首  其一','劉一止','宋','宋诗','song-poetry','','[]','古德杖頭挑，今師竿下取。',24,'全唐诗/poet.song.84000.json','["古德杖頭挑，今師竿下取。", "月滿體自如，清光無處所。"]'),
('bed2181d-809c-4608-8299-6fe4b7ae403c','幾上人名所乘舟曰釣月庵求詩爲賦二首  其二','劉一止','宋','宋诗','song-poetry','','[]','昔人釣忘餌，今師亦忘鈎。',24,'全唐诗/poet.song.84000.json','["昔人釣忘餌，今師亦忘鈎。", "静夜江不湍，孤光送歸舟。"]'),
('47b7c054-c7e4-4a26-b216-50cc2a73b168','雙頭黄芍藥二首  其一','劉一止','宋','宋诗','song-poetry','','[]','漢宮時世妝，承恩嬌姊妹。',24,'全唐诗/poet.song.84000.json','["漢宮時世妝，承恩嬌姊妹。", "解道根蒂同，如何兩心背。"]'),
('9cc3b48c-a9ba-413c-9ccf-669636f615b2','雙頭黄芍藥二首  其二','劉一止','宋','宋诗','song-poetry','','[]','映立自亭亭，吸飲風露饒。',24,'全唐诗/poet.song.84000.json','["映立自亭亭，吸飲風露饒。", "不作恩與怨，世間兒女妖。"]');
